INSERT INTO public.photos VALUES (24183, 'Tâ”œâ•‘neles sobre el Huerva 1963', 'El soterramiento de las vâ”œÂ¡as del ferrocarril desde la estaciâ”œâ”‚n Campo Sepulcro, hasta el paseo de Mola, supuso la construcciâ”œâ”‚n de un nuevo puente sobre el râ”œÂ¡o Huerva. En la imagen, obras de construcciâ”œâ”‚n del nuevo puente, con vista de los nuevos tâ”œâ•‘neles para el ferrocarril, en lo que aâ”œâ–’os despuâ”œÂ®s serâ”œÃ­ denominado como "Avenida de Goya". A la izquierda, visual de la calle Zumalacâ”œÃ­rregui (antigua avenida Central), cuya pasarela peatonal sobre el râ”œÂ¡o serâ”œÃ­ desmantelada cuando esta obra de soterramiento estâ”œÂ® terminada. A la derecha, al fondo, sobresale parcialmente la torre de la Parroquia de N.â”¬Â¬ S.â”¬Â¬ del Perpetuo Socorro. Tras las obras, la zona serâ”œÃ­ muy transformada. Fuente visual: Fundaciâ”œâ”‚n de los Ferrocarriles Espaâ”œâ–’oles.', 1963, 1963, 1963, 'Anos 60', 'UNIVERSIDAD', 41.64347700, -0.89031100, '0101000020E61000001B9C887E6D7DECBF355D4F745DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16804788840.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16804788840.webp', 'https://www.flickr.com/photos/zaragozaantigua/16804788840/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24184, 'Estaciâ”œâ”‚n Zaragoza-Goya 2011', 'Obras de construcciâ”œâ”‚n de la estaciâ”œâ”‚n ferroviaria de cercanâ”œÂ¡as Zaragoza-Goya en 2011. Serâ”œÃ­ inaugurada el 3 de abril de 2012. Detrâ”œÃ­s, manzana de viviendas esquina Fâ”œÂ®lix Latassa con avenida Goya. Fuente: zaragozacool.wordpress.com/2011/10/08/estacion-de-goya-ob...', 2011, 2011, 2011, 'Siglo XXI', 'UNIVERSIDAD', 41.64390100, -0.89126900, '0101000020E61000003509DE904685ECBF4C6E14596BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19503258889.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19503258889.webp', 'https://www.flickr.com/photos/zaragozaantigua/19503258889/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24194, 'Râ”œÂ¡o Huerva 1936', 'Imagen de la altura que llevaba el pico de la riada de febrero de 1936, donde el metâ”œÃ­lico puente daba paso al ferrocarril de la compaâ”œâ–’â”œÂ¡a MZA (Madrid-Zaragoza-Alicante) y le daba continuidad desde Campo Sepulcro (a la izquierda), y la estaciâ”œâ”‚n de Miraflores (hacia la derecha). A la izquierda, la metâ”œÃ­lica pasarela peatonal, mâ”œÃ­s elevada, que conectaba la Avenida Central con la Gran Vâ”œÂ¡a. Fuente visual: Archivo Pâ”œâ•‘blico Municipal.', 1936, 1936, 1936, 'Anos 30', 'UNIVERSIDAD', 41.64347700, -0.89031100, '0101000020E61000001B9C887E6D7DECBF355D4F745DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22834803969.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22834803969.webp', 'https://www.flickr.com/photos/zaragozaantigua/22834803969/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24207, 'Fernando el Catâ”œâ”‚lico 1950', 'Aâ”œÂ®rea visual del despejado entorno del paseo de Fernando el Catâ”œâ”‚lico, desde su arranque en la zanja del ferrocarril a Barcelona, que proviene desde el fondo, la estaciâ”œâ”‚n de Zaragoza-Campo Sepulcro. Desde esta altura son perfectamente visibles los pasos que salvaban la zanja, y la delimitaciâ”œâ”‚n de solares en los que, en poco tiempo, serâ”œÂ¡an construidos modernos bloques que flanquearâ”œÃ­n el paseo. Fuente visual: "Zaragoza 1908-2008. Arquitectura y Urbanismo".', 1950, 1950, 1950, 'Anos 50', 'UNIVERSIDAD', 41.64426000, -0.89189000, '0101000020E61000005F24B4E55C8AECBF7C0F971C77D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33648251942.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33648251942.webp', 'https://www.flickr.com/photos/zaragozaantigua/33648251942/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24208, 'Avenida Goya 2011', 'Foto: Pablo Lâ”œâ”‚pez Learte. Infrecuente vista subterrâ”œÃ­nea de la avenida de Francisco de Goya, en el punto donde â”œÂ®sta pasa cubriendo el râ”œÂ¡o Huerva desde 1966. En el centro de la imagen, puente ferroviario renovado en 1959. Fuente: Heraldo de Aragâ”œâ”‚n.', 2011, 2011, 2011, 'Siglo XXI', 'UNIVERSIDAD', 41.64353800, -0.89031100, '0101000020E61000001B9C887E6D7DECBFDBDD03745FD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36630416175.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36630416175.webp', 'https://www.flickr.com/photos/zaragozaantigua/36630416175/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24211, 'Av. de Goya 2011', 'Foto: Josâ”œÂ® Miguel Marco. Obras de demoliciâ”œâ”‚n de la antigua trinchera del ferrocarril entre Madrid y Barcelona, con vista a los edificios de la avenida de Goya, entre los nâ”œâ•‘meros 67 y 75, desde la iglesia del Corazâ”œâ”‚n de Marâ”œÂ¡a hasta la calle de San Antonio Marâ”œÂ¡a Claret, en mayo de 2011. Serâ”œÃ­ sustituida por un nuevo tâ”œâ•‘nel, cuya armadura para sostener la losa que lo cubrirâ”œÃ­ estâ”œÃ­ siendo colocada. Esta obra se realizâ”œâ”‚ como acompaâ”œâ–’amiento de la estaciâ”œâ”‚n de cercanâ”œÂ¡as Zaragoza-Goya, siendo demolidos 310 metros de trinchera entre el râ”œÂ¡o Huerva y la iglesia citada. El anterior cubrimiento de esta infraestructura se llevâ”œâ”‚ a cabo entre 1959 y 1962. En 2012 se inaugurarâ”œÂ¡a el edificio de la terminal. Fuente: Heraldo de Aragâ”œâ”‚n.', 2011, 2011, 2011, 'Siglo XXI', 'UNIVERSIDAD', 41.64551900, -0.89331500, '0101000020E6100000F5D6C0560996ECBF2BF9D85DA0D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37050990264.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37050990264.webp', 'https://www.flickr.com/photos/zaragozaantigua/37050990264/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24213, '&quot;Av. de Goya&quot; 1963', 'Imagen capturada durante las obras de duplicaciâ”œâ”‚n y soterramiento de la vâ”œÂ¡a del ferrocarril de Madrid a Barcelona en el punto donde se salvaba el desnivel de diez metros por donde fluâ”œÂ¡a entre acusada pendiente el râ”œÂ¡o Huerva. Por el tramo aâ”œâ•‘n al aire entre los nuevos tâ”œâ•‘neles del ferrocarril, correspondiente al puente sobre el Huerva, circula un convoy en direcciâ”œâ”‚n a la estaciâ”œâ”‚n de Miraflores. A la izquierda, traseras del antiguo nâ”¬â•‘ 45 de la la calle Zumalacâ”œÃ­rregui (que antes fuera avenida Central). A la derecha, traseras y lateral del antiguo nâ”¬â•‘ 18 de la calle de Benavente. Tras las obras, la reurbanizaciâ”œâ”‚n de la zona serâ”œÃ­ muy intensa, y el nuevo vial resultante sobre las vâ”œÂ¡as soterradas serâ”œÃ­ denominado aâ”œâ–’os despuâ”œÂ®s como avenida de Goya. De resultas de ello, la antigua calle de Goya habrâ”œÂ¡a de ser redenominada como de Jusepe Martâ”œÂ¡nez. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1963, 1963, 1963, 'Anos 60', 'UNIVERSIDAD', 41.64353800, -0.89031100, '0101000020E61000001B9C887E6D7DECBFDBDD03745FD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40418089085.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40418089085.webp', 'https://www.flickr.com/photos/zaragozaantigua/40418089085/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24256, 'Cubrimiento Huerva 1925', 'Obras de cubrimiento del râ”œÂ¡o Huerva en la Gran Vâ”œÂ¡a, entre la calle Goya y la plaza Paraâ”œÂ¡so. 1925. Obras de rectificaciâ”œâ”‚n del cauce en la curva de "La Veneciana", demoliendo los antiguos muros para construir los nuevos. Fuente: AHPZ-Archivo Coyne, (SF), Estudio Coyne.', 1925, 1925, 1925, 'Anos 20', 'UNIVERSIDAD', 41.64528900, -0.88988100, '0101000020E6100000E99D0AB8E779ECBFF9BB77D498D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14884268331.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14884268331.webp', 'https://www.flickr.com/photos/zaragozaantigua/14884268331/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24260, 'Gran Vâ”œÂ¡a 1925', 'Imagen de las obras de cubrimiento del râ”œÂ¡o Huerva en su tramo urbano, en la denominada "Primera zona", desde la "curva de la Veneciana", escenario de la captura fotogrâ”œÃ­fica (esa fâ”œÃ­brica quedaba a la derecha), hasta el puente de Santa Engracia. Al fondo, parcial vista de la fâ”œÃ­brica de sombreros que en 1931 sufrirâ”œÂ¡a un fatal incendio. Fuente visual: Carlos Blâ”œÃ­zquez, en "El Huerva, un râ”œÂ¡o con mucha historia".', 1925, 1925, 1925, 'Anos 20', 'UNIVERSIDAD', 41.64528300, -0.89024500, '0101000020E61000003EAE0D15E37CECBF17D522A298D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22076281825.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22076281825.webp', 'https://www.flickr.com/photos/zaragozaantigua/22076281825/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24262, 'Calle de Dato 1930', 'Penosa imagen, por su calidad fotogrâ”œÃ­fica, del antiguo principio de la calle de Eduardo Dato, con el camino de los Cubos y el brazal bajo de la acequia de la Romareda pasando justo delante. El muro del fondo delimitaba las antiguas instalaciones de la fâ”œÃ­brica de espejos de La Veneciana, detrâ”œÃ­s de las cuales estaba la flamante nueva Gran Vâ”œÂ¡a. A la izquierda, el edificio de dos alturas del antiguo nâ”¬â•‘ 2 de la calle de Dato. A la derecha no aparece ninguna seâ”œâ–’al edilicia, porque habâ”œÂ¡a un solar, en terrenos que fueran de la torre de Bernardo Fita. Fuente visual: Miguel Marâ”œÂ¡n Chivite, en el periâ”œâ”‚dico "Heraldo de Aragâ”œâ”‚n".', 1930, 1930, 1930, 'Anos 30', 'UNIVERSIDAD', 41.64597000, -0.89020400, '0101000020E61000009A9658198D7CECBF3B191C25AFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31695140424.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31695140424.webp', 'https://www.flickr.com/photos/zaragozaantigua/31695140424/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24267, 'Ferial 1931', 'Imagen del Ferial de las fiestas mayores de octubre, capturada en el amplio recinto del final de la Gran Vâ”œÂ¡a, delimitado por el brazal alto de la acequia de la Romareda, la lâ”œÂ¡nea de ferrocarril de Zaragoza a Barcelona, el brazal bajo de la acequia de la Romareda, y un vial en proceso de urbanizaciâ”œâ”‚n que luego serâ”œÃ­ denominado de Ricla (los inmuebles del fondo). Aquâ”œÂ¡ se ofrecâ”œÂ¡an al pâ”œâ•‘blico las tradicionales barracas fiesteras con atracciones de caballitos, toboganes, tiros al blanco, tâ”œâ”‚mbolas, churrerâ”œÂ¡as, y circos. Fuente visual: www.mecd.gob.es/.', 1931, 1931, 1931, 'Anos 30', 'UNIVERSIDAD', 41.64522700, -0.89151100, '0101000020E6100000B5C6A0134287ECBF83BF5FCC96D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36213333820.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36213333820.webp', 'https://www.flickr.com/photos/zaragozaantigua/36213333820/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24449, 'Avenida de Goya 1963', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. 09/06/1963. "Inauguraciâ”œâ”‚n de la fâ”œÃ­brica de Galletas Cuâ”œÂ®tara." El empresario "galletero" Juan Gâ”œâ”‚mez Cuâ”œÂ®tara, mediante el "Plan Cuâ”œÂ®tara", se lanzâ”œâ”‚ a principios de los aâ”œâ–’os 60 a una importante expansiâ”œâ”‚n industrial en forma de media docena de nuevas pequeâ”œâ–’as fâ”œÃ­bricas en distintos puntos del paâ”œÂ¡s, al objeto de conseguir una buena cuota del mercado. Zaragoza fue una de las localidades elegidas. En la imagen, una caravana de transportes de la empresa aparcadas a la altura de la ubicaciâ”œâ”‚n de la fâ”œÃ­brica en la avenida de Goya, a la izquierda de la imagen. El cubrimiento de las vâ”œÂ¡as del tren era tan reciente, que aâ”œâ•‘n no habâ”œÂ¡a aceras, ni viales asfaltados. Coches aparcados, sâ”œÂ¡. A la derecha, el enorme arco de entrada a la Parroquia del Corazâ”œâ”‚n de Marâ”œÂ¡a. Al fondo, Fernando el Catâ”œâ”‚lico.', 1963, 1963, 1963, 'Anos 60', 'UNIVERSIDAD', 41.64596300, -0.89342200, '0101000020E610000077DCF0BBE996ECBF89B663EAAED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15218423765.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15218423765.webp', 'https://www.flickr.com/photos/zaragozaantigua/15218423765/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25010, 'Paseo de Ruiseâ”œâ–’ores 1922', 'Imagen capturada en el arbolado paseo de Ruiseâ”œâ–’ores, poco antes del despartidero donde comienza el camino antiguo de Cuarte, a espaldas del fotâ”œâ”‚grafo, junto al cerramiento de la casa de Juliâ”œÃ­n Escudero y el colegio Pompiliano de las Reverendas Madres Escolapias en construcciâ”œâ”‚n. A la derecha, interesante vista parcial del hotelito de Sebastiâ”œÃ­n Rodrâ”œÂ¡guez, que inicia la singular e irrepetible galerâ”œÂ¡a de viviendas unifamiliares construidas a principios de siglo en esta exclusiva zona residencial de la ciudad. Le siguen el de Raimundo Balet; el de â”œÃ¼ngel Anâ”œâ”‚s; la Villa Alta de Emilio Ostalâ”œÂ®; y el de la viuda de Collado.', 1922, 1922, 1922, 'Anos 20', 'UNIVERSIDAD', 41.63589200, -0.88975300, '0101000020E61000008A929048DB78ECBFDEE4B7E864D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48463896822.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48463896822.webp', 'https://www.flickr.com/photos/zaragozaantigua/48463896822/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24492, 'Antigua plaza de Espaâ”œâ–’a 1940', 'Las Fiestas de Primavera del aâ”œâ–’o 1940 fueron muy animadas, con rica variedad de desfiles de danzantes tâ”œÂ¡picos y festivales folclâ”œâ”‚ricos, bajo el velo protector oficial del diecinueve centenario de la fantâ”œÃ­stica llegada de la Virgen del Pilar en carne mortal a Zaragoza. En esta primaveral programaciâ”œâ”‚n se incluyâ”œâ”‚ la colocaciâ”œâ”‚n de la primera piedra de la nueva Casa Sindical de Aragâ”œâ”‚n en la avenida de Marina Moreno, y para darle respaldo visual, delante de ella desfilâ”œâ”‚, el 26 de mayo, una lucida cabalgata compuesta por las nueve Carrozas de la Producciâ”œâ”‚n Aragonesa, organizada por la Junta del Centenario (mariano), y la Central Nacional Sindicalista, cada una correspondiente con un gremio productivo. Entre ellas estaba la que ilumina esta imagen, la del Calzado, obra del reputado artista local Torres, que reproduce dos figuras de los cuentos tradicionales relacionadas con el sector del calzado: el Gato con Botas, y el zapato perdido de la princesa Cenicienta. En la imagen, la carroza referida, durante los preparativos de la cabalgata, en el entorno de la plaza que se iba a denominar de Espaâ”œâ–’a, pero que tras el golpe del 18-19 de julio de 1936 se tuvo que buscar otro nombre: San Francisco. Al fondo, el nuevo convento de los Carmelitas, que durante la guerra fue usado como cuartel de Comunicaciones, y que ahora estaba a punto de pasar a manos de los Hermanos de las Escuelas Cristianas. Fuente visual: Miguel Marâ”œÂ¡n Chivite, AMZ.', 1940, 1940, 1940, 'Anos 40', 'UNIVERSIDAD', 41.64073700, -0.89366700, '0101000020E61000003A765089EB98ECBF282B86AB03D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25328914079.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25328914079.webp', 'https://www.flickr.com/photos/zaragozaantigua/25328914079/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24930, 'Monumento a Bolâ”œÂ¡var 1970', 'Octubrina y soleada imagen capturada durante la inauguraciâ”œâ”‚n oficial del Monumento a Simâ”œâ”‚n Bolâ”œÂ¡var sito en el parque de Primo de Rivera, en su ubicaciâ”œâ”‚n entre la avenida de los Bearneses y el paseo de Mariano Renovales. Se trataba de una desafortunada râ”œÂ®plica en bronce del original busto de Bolâ”œÂ¡var, obra del escultor Pietro Tenerani (1836) instalado en el caraqueâ”œâ–’o Ministerio de Relaciones Exteriores. Entre la notable presencia de autoridades militares, religiosas y civiles destaca el alcalde Mariano Horno Liria, una amplia delegaciâ”œâ”‚n del râ”œÂ®gimen venezolano encabezada por el embajador Carlos Capriles y la câ”œâ”‚nsul general Josefina Achâ”œÂ®, y monseâ”œâ–’or Sâ”œÃ­nchez Espejo que bendijo la imagen. Como no podâ”œÂ¡a ser de otra forma, los discursos vincularon de forma altamente imaginativa la Zaragoza de la Virgen del Pilar y de los Sitios con el Libertador y con la lucha contra el materialismo y el comunismo. Cuando al Libertador se le saca de esos estrechos y carpetovetâ”œâ”‚nicos corsâ”œÂ®s, los problemas maduran.', 1970, 1970, 1970, 'Anos 70', 'UNIVERSIDAD', 41.63464100, -0.89330400, '0101000020E6100000FB592C45F295ECBFB2D991EA3BD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15042212469.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15042212469.webp', 'https://www.flickr.com/photos/zaragozaantigua/15042212469/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24931, 'Calle Luis Vives 1974', 'Desde la altura de la torre de la Editorial Luis Vives, interesante imagen del panorama en el entorno del paso del Huerva por la zona. En primerâ”œÂ¡simo plano, el "quesito" de la referida editorial, con sus talleres aâ”œâ•‘n en funcionamiento. A la izquierda, la calle Luis Vives, precisamente. A su izquierda, entre la calle Andrâ”œÂ®s Piquer y Santa Teresa de Jesâ”œâ•‘s, el Grupo de Viviendas "Francisco Caballero", y una joya visual: asoman las Casas Baratas del Ensanche de 1934, â”œÂ®stas con su imagen de casita totalmente fuera de contexto. La lâ”œâ”‚gica sistâ”œÂ®mica se impuso poco despuâ”œÂ®s: fueron piqueteadas para mayor aprovechamiento vertical. Poco despuâ”œÂ®s, el puente sobre el Huerva, el Paseo de Mariano Renovales, las moles de los bloques "Marvel", la clâ”œÂ¡nica Quirâ”œâ”‚n, y el Parque Primo de Rivera.', 1974, 1974, 1974, 'Anos 70', 'UNIVERSIDAD', 41.63812900, -0.89580400, '0101000020E6100000100874266DAAECBF89D00836AED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15042594298.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15042594298.webp', 'https://www.flickr.com/photos/zaragozaantigua/15042594298/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24936, 'Paseo de San Sebastiâ”œÃ­n 1976', 'Vista del paseo de San Sebastiâ”œÃ­n en el parque de Primo de Rivera, desde la altura de los antiguos accesos escalonados al Cabezo de Buenavista, donde se sitâ”œâ•‘a el monumento a Alfonso I el Batallador. En primer tâ”œÂ®rmino, la fuente trasladada desde la plaza de Basilio Paraâ”œÂ¡so en enero de 1974, y a la izquierda, el nuevo Jardâ”œÂ¡n Botâ”œÃ­nico. Al fondo la torre de la Feria Nacional de Muestras, destacando entre los edificios de La Romareda y el paseo de Fernando el Catâ”œâ”‚lico. El bulevar y resto de viales de este pulmâ”œâ”‚n verde se nos muestra apoderado por los vehâ”œÂ¡culos a motor de forma absoluta, una situaciâ”œâ”‚n que se mantuvo sin cambios hasta que en los primeros aâ”œâ–’os 80 un grupo de ciudadanos concienciados comenzaron a realizar semanalmente unas llamadas bicifestaciones, que con el lema Coches no, bicis sâ”œÂ¡ reivindicaban el desalojo de esos intrusos motorizados.', 1976, 1976, 1976, 'Anos 70', 'UNIVERSIDAD', 41.63452900, -0.89435400, '0101000020E6100000417FA1478C9EECBF8AAE0B3F38D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15513073492.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15513073492.webp', 'https://www.flickr.com/photos/zaragozaantigua/15513073492/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24940, 'Batallador 1925', '"Zaragoza. Monumento a Alfonso I. Autor: Josâ”œÂ® Bueno." Monumento impulsado por la Junta promotora del centenario 8 de la conquista cristiana de la ciudad, para ser colocado en el Cabezo del parque de Buenavista, fue tallado en mâ”œÃ­rmol de carrara por Josâ”œÂ® Bueno, con un potente pedestal en forma de torreâ”œâ”‚n neomedieval diseâ”œâ–’ado por Miguel â”œÃ¼ngel Navarro. Aunque el aniversario fue en 1918, el batallador estuvo emplazado en su sitio en 1923, en el modo y manera que la imagen ilustra. En 1927 se le colocarâ”œÃ­, sobre los cuatro sillares salientes del frontal, la figura de un leâ”œâ”‚n en bronce, obra del comandante de Infanterâ”œÂ¡a Virgilio Garrâ”œÃ­n, fundida en los talleres Averly. Insâ”œâ”‚litamente, 92 aâ”œâ–’os despuâ”œÂ®s sigue sin haber sido inaugurado por la oficialidad institucional municipal. Fuente visual: Archivo Juan Mora Insa, AHPZ.', 1925, 1925, 1925, 'Anos 20', 'UNIVERSIDAD', 41.63359100, -0.89335200, '0101000020E61000003F1EFAEE5696ECBF1D05888219D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22409809132.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22409809132.webp', 'https://www.flickr.com/photos/zaragozaantigua/22409809132/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24941, 'Cabezo de Buenavista Ca.1920', 'Imagen parcial del Cabezo de Buenavista con detalle de uno de los tres primitivos conjuntos de dobles escaleras y jardines diseâ”œâ–’ados en una zona de acusados desniveles que, mâ”œÃ­s adelante, recibirâ”œÂ¡a el nombre de "Jardâ”œÂ¡n de Invierno", inmediato al Canal Imperial, como destacado elemento del nuevo Parque Buenavista. El Cabezo queda a la izquierda de la imagen, tras un fuerte ascenso. Fuente visual: Archivo fotogrâ”œÃ­fico histâ”œâ”‚rico del SIPA (DARA-AHPZ).', 1920, 1920, 1920, 'Anos 20', 'UNIVERSIDAD', 41.63180200, -0.89279000, '0101000020E610000052448655BC91ECBF11C64FE3DED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23397720424.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23397720424.webp', 'https://www.flickr.com/photos/zaragozaantigua/23397720424/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24942, 'Cabezo de Buenavista 1921', 'Imagen del Cabezo de Buenavista centrada en la zona de acusados desniveles que mâ”œÃ­s adelante recibirâ”œÂ¡a el nombre de "Jardâ”œÂ¡n de Invierno". Sus alabeadas escaleras y bancos de madera, los ornamentos vegetales, y â”œÃ­rboles de repoblaciâ”œâ”‚n, configuraban un singular, recogido y reconocido espacio dentro del nuevo Parque de Buenavista. Fuente visual: Foto F. Lâ”œâ”‚pez Blecua (Archivo A.C. "Paso a Nivel"), en www.rafaelcastillejo.com/', 1921, 1921, 1921, 'Anos 20', 'UNIVERSIDAD', 41.63180200, -0.89279000, '0101000020E610000052448655BC91ECBF11C64FE3DED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23735584070.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23735584070.webp', 'https://www.flickr.com/photos/zaragozaantigua/23735584070/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24948, 'Cabezo de Buenavista 1969', 'Imagen de Miguel Labordeta Subâ”œÂ¡as en el mirador del Cabezo de Buenavista, poco antes de su repentina muerte, tal vez (poema "La voz del poeta") velando largamente en duelo, oyendo en los silencios el ritmo pavoroso de los tiempos, acariciando la marea de las edades inmensas, rompiâ”œÂ®ndose en quejidos y maravillosas melodâ”œÂ¡as contra el humilde corazâ”œâ”‚n infortunado. Fuente visual: "Andalâ”œÃ­n, periâ”œâ”‚dico quincenal aragonâ”œÂ®s".', 1969, 1969, 1969, 'Anos 60', 'UNIVERSIDAD', 41.63227000, -0.89408600, '0101000020E610000073F7393E5A9CECBFF71E2E39EED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32610085656.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32610085656.webp', 'https://www.flickr.com/photos/zaragozaantigua/32610085656/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24990, 'Cabezo de Buenavista 1933', 'Imagen capturada en la muy ocasional pista de esquâ”œÂ¡ del Cabezo de Buenavista, que en el fresco enero de ese aâ”œâ–’o ofreciâ”œâ”‚ un marco incomparable e improvisado para la amateur prâ”œÃ­ctica de deporte blanco, sin que para ello fueran precisas inversiones pâ”œâ•‘blicas, ni privados patronazgos. El restaurant Las Palmeras, cerrado por fuera de temporada, no pudo beneficiarse del excepcional turisteo. Fuente visual: www.mecd.gob.es/.', 1933, 1933, 1933, 'Anos 30', 'UNIVERSIDAD', 41.63402400, -0.89312700, '0101000020E6100000429605137F94ECBF8670CCB227D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35624069571.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35624069571.webp', 'https://www.flickr.com/photos/zaragozaantigua/35624069571/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24991, 'Campeonatos Espaâ”œâ–’a Velocidad 1950', 'Cartel de la III fase de los Campeonatos Espaâ”œâ–’a Velocidad de motociclismo, celebrada en el parque Primo de Rivera el 4 de junio de 1950. El Moto Club Aragâ”œâ”‚n organizâ”œâ”‚ posteriormente en esa misma ubicaciâ”œâ”‚n el Gran Premio Internacional Nuestra Seâ”œâ–’ora del Pilar, entre 1952 y 1974. Fuente: charlescamberoque.unblog.fr/2016/03/06/les-grands-prix-de...', 1950, 1950, 1950, 'Anos 50', 'UNIVERSIDAD', 41.63263400, -0.89561100, '0101000020E6100000EB025E66D8A8ECBF392BA226FAD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36416954642.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36416954642.webp', 'https://www.flickr.com/photos/zaragozaantigua/36416954642/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24995, 'Parque de Buenavista 1933', 'Imagen capturada en el parque de Buenavista y centrada en el evento "carrera de triciclos y automâ”œâ”‚viles infantiles" programado dentro de las Fiestas de Primavera que tuvo lugar el 23 de mayo de 1933, a las cinco de la tarde. La prueba discurriâ”œâ”‚ sobre una distancia de cien metros y todos los participantes fueron obsequiados con una caja de caramelos. En la categorâ”œÂ¡a de "automâ”œâ”‚viles de propulsiâ”œâ”‚n a pedal" resultâ”œâ”‚ ganador el niâ”œâ–’o Jesâ”œâ•‘s Cervello, y en la de "triciclos" el niâ”œâ–’o Josâ”œÂ® Marâ”œÂ¡a Cervello. Al fondo de la escena, el Cabezo de Buenavista con un aspecto parcial de las rampas que mediante escaleras le daban acceso desde la parte baja del parque donde se desarrollaba la carrera.', 1933, 1933, 1933, 'Anos 30', 'UNIVERSIDAD', 41.63486400, -0.89440000, '0101000020E6100000575BB1BFEC9EECBF31B43A3943D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52707152858.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52707152858.webp', 'https://www.flickr.com/photos/zaragozaantigua/52707152858/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24997, 'P.â”¬â•‘ de los Ruiseâ”œâ–’ores 1931', 'Inâ”œÂ®dita imagen capturada en el frondoso andador central del Jardâ”œÂ¡n Botâ”œÃ­nico que formaba parte de la Residencia de Estudiantes o Colegio Mayor de Cerbuna de la Universidad de Zaragoza. Al fondo, puerta de acceso abierta en el nâ”œâ•‘mero 23 del paseo de los Ruiseâ”œâ–’ores. El nuevo instituto MIguel Servet femenino proyectado en 1960 por el arquitecto Regino Borobio Ojeda respetâ”œâ”‚ parte de los jardines que formaban parte de este Jardâ”œÂ¡n Botâ”œÃ­nico, de forma que unas diez especies vegetales de las allâ”œÂ¡ plantadas han llegado hasta nuestros dâ”œÂ¡as.', 1931, 1931, 1931, 'Anos 30', 'UNIVERSIDAD', 41.63570000, -0.88967800, '0101000020E6100000E00F3FFF3D78ECBF9A081B9E5ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53178606148.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53178606148.webp', 'https://www.flickr.com/photos/zaragozaantigua/53178606148/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25003, 'P.â”¬â•‘ de Ruiseâ”œâ–’ores 1922', 'El efecto dominâ”œâ”‚ de la instalaciâ”œâ”‚n de los Depâ”œâ”‚sitos de Agua en la parte alta del Paseo de Cuâ”œÂ®llar, con la reparcelaciâ”œâ”‚n de la zona, permitiâ”œâ”‚ la creaciâ”œâ”‚n, en 1903, del proyecto de "barrio de Ruiseâ”œâ–’ores", junto al paseo de ese nombre, en una zona deshabitada de humanos. La nueva planta, planificada sobre terrenos como los de la antigua Torre de Marraco, estaba pensada como una extensiâ”œâ”‚n del cercano Paseo de Sagasta, con viviendas unifamiliares y estilosas para la alta burguesâ”œÂ¡a local, en una zona donde (tras eliminar una lecherâ”œÂ¡a y grandes establos) el aire era mâ”œÃ­s puro que abajo, en la lejana ciudad. Seis construcciones-piloto (Lucas Abâ”œâ”‚s, Viuda de Collado, Emilio Ostalâ”œÂ®, â”œÃ¼ngel Abâ”œâ”‚s, Raimundo Balet, y Sebastiâ”œÃ­n Rodrâ”œÂ¡guez), inauguraron esta exclusiva zona en 1905, y seâ”œâ–’alaron un camino pronto seguido por notable y selecta parroquia. En la imagen, el paseo de Ruiseâ”œâ–’ores. A la derecha, aspecto de los originales primeros "hotelitos" de la zona, localizados junto a la parte oeste de los Depâ”œâ”‚sitos, con visual insâ”œâ”‚lita del de Sebastiâ”œÃ­n Rodrâ”œÂ¡guez, y su llamativa torrecilla apuntada. A la izquierda, andamios de construcciâ”œâ”‚n del Colegio Pompiliano de las Escolapias, reciâ”œÂ®n llegadas al barrio. Como en la mayor parte de las construcciones de la zona, lo que hoy hay, poco mâ”œÃ­s de nueve dâ”œÂ®cadas despuâ”œÂ®s, poco ha de ver con lo que hubiera, o hubiese. Fuente visual: AHPZ, Archivo Gabriel Faci.', 1922, 1922, 1922, 'Anos 20', 'UNIVERSIDAD', 41.63598100, -0.88971000, '0101000020E6100000B8921D1B8178ECBF4EF04DD367D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21434044649.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21434044649.webp', 'https://www.flickr.com/photos/zaragozaantigua/21434044649/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25012, 'P.â”¬â•‘ de los Ruiseâ”œâ–’ores 1931', 'Inâ”œÂ®dita imagen capturada a la altura del nâ”œâ•‘mero 23 del paseo de los Ruiseâ”œâ–’ores, por donde a la izquierda se accedâ”œÂ¡a al Colegio Mayor de Cerbuna de la Universidad de Zaragoza, cuyo edificio se deja ver en el centro de la escena entre los monumentales acacias del paseo. La inmediata verja perimetral se abre mediante una puerta que permitâ”œÂ¡a el ingreso al Jardâ”œÂ¡n Botâ”œÃ­nico de la ciudad. Por el paseo desciende un autobâ”œâ•‘s de la lâ”œÂ¡nea que conectaba la plaza del Pilar con el Cabezo de Buenavista, de donde proviene. A la derecha, muros de los jardines de la antigua finca de Josâ”œÂ® Herrero, y justo en primer tâ”œÂ®rmino, punto en el que paseo de los Ruiseâ”œâ–’ores da principio al camino viejo de Cuarte, actual calle de Julio Cejador Frauca.', 1931, 1931, 1931, 'Anos 30', 'UNIVERSIDAD', 41.63589200, -0.88975300, '0101000020E61000008A929048DB78ECBFDEE4B7E864D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53166004310.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53166004310.webp', 'https://www.flickr.com/photos/zaragozaantigua/53166004310/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23636, 'Academia General Militar 1937', 'Prisioneros procedentes de Santa Quiteria (Tardienta) que fueron obligados a llevar esa pancarta a su llegada a Zaragoza. La Academia tenâ”œÂ¡a capacidad para albergar 2.000 presos y actuaba como centro de identificaciâ”œâ”‚n y clasificaciâ”œâ”‚n. En enero de 1938 se trasladâ”œâ”‚ el control al nuevo campo de concentraciâ”œâ”‚n de San Juan de Mozarrifar. Fuente visual: Delegaciâ”œâ”‚n de Prensa y Propaganda 5â”¬â•‘ Cuerpo de Ejâ”œÂ®rcito - Zaragoza.', 1937, 1937, 1937, 'Anos 30', NULL, 41.69927200, -0.87141700, '0101000020E6100000B7B585E7A5E2EBBF1781B1BE81D94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14938719875.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14938719875.webp', 'https://www.flickr.com/photos/zaragozaantigua/14938719875/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25077, 'Pardo Sastrâ”œâ”‚n 1930', 'Imagen del original monumento erigido en el parque de Buenavista al botâ”œÃ­nico Josâ”œÂ® Pardo Sastrâ”œâ”‚n (1822-1909). El busto, en mâ”œÃ­rmol, fue tallado por Pedro Sâ”œÃ­nchez Fustero sobre un pedestal en el que se puso la leyenda "Zaragoza al sabio botâ”œÃ­nico Pardo Sastrâ”œâ”‚n". A finales de 1929 fue emplazado muy cerca del "Chalet Buenavista" y el paseo del Canal, a la izquierda de la imagen. El paso del tiempo le hizo mala mella, e incluso mengua de algunos pedazos. En 1971, Francisco Rallo recibiâ”œâ”‚ el municipal encargo de restaurarlo, primero, y de modelar luego una reproducciâ”œâ”‚n en bronce, sobre nuevo pedestal en el que se puede leer la â”œÂ®tica inscripciâ”œâ”‚n "Pardo Sastrâ”œâ”‚n". Vandalizado periâ”œâ”‚dicamente por acâ”œÂ®falos sujetos, robado, devuelto, restaurado, pintarrajeado, limpiado, ensuciado, vuelto a limpiar... Su actual ubicaciâ”œâ”‚n es tambiâ”œÂ®n distinta: junto al antiguo paseo de los Plâ”œÃ­tanos del parque, ahora denominado de Manuel Azaâ”œâ–’a, casi en su confluencia con el paseo de los Bearneses. Fuente visual: Foto Martâ”œÂ¡nez ("Mundo Grâ”œÃ­fico", Madrid).', 1930, 1930, 1930, 'Anos 30', 'UNIVERSIDAD', 41.63350500, -0.89244400, '0101000020E6100000965D30B8E68EECBF1E6D1CB116D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22430934971.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22430934971.webp', 'https://www.flickr.com/photos/zaragozaantigua/22430934971/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25426, 'Paso MZA sobre el Huerva 1911', 'Imagen de la trinchera del ferrocarril de la compaâ”œâ–’â”œÂ¡a MZA (Madrid-Zaragoza-Alicante) a su paso sobre el râ”œÂ¡o Huerva mediante un puente metâ”œÃ­lico (en primer plano) entre la Huerta de Marraco (al fondo) y la Torre de Palomar (margen derecha del râ”œÂ¡o). El puente sobre las vâ”œÂ¡as daba continuidad al camino paralelo al râ”œÂ¡o Huerva, que conducâ”œÂ¡a al camino de los Cubos. (www.flickr.com/photos/zaragozaantigua/16804788840). Fuente visual: hemerotecadigital.bne.es/', 1911, 1911, 1911, 'Anos 10', 'UNIVERSIDAD', 41.64347700, -0.89031100, '0101000020E61000001B9C887E6D7DECBF355D4F745DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20511700974.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20511700974.webp', 'https://www.flickr.com/photos/zaragozaantigua/20511700974/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25487, 'Calle del Carmen 1957', 'Imagen centrada en la fachada del moderno grupo de viviendas de renta limitada proyectado por el arquitecto Josâ”œÂ® de Yarza Garcâ”œÂ¡a en el solar del nâ”¬â•‘ 18-20 de la calle del Carmen. A la izquierda, el bloque del nâ”¬â•‘ 24. A la derecha, vista parcial del edificio correspondiente al nâ”¬â•‘ 16 de la antigua avenida del Carmen. Fuente visual: arch. J. de Yarza', 1957, 1957, 1957, 'Anos 50', 'UNIVERSIDAD', 41.64699100, -0.89241200, '0101000020E6100000BEDA519CA38EECBF36E7E099D0D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37302488134.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37302488134.webp', 'https://www.flickr.com/photos/zaragozaantigua/37302488134/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25581, 'Pre-Avenida de Goya 1965', 'La calle de los ferrocarriles directos, o del ferrocarril de Madrid a Barcelona, o de Zaragoza a Barcelona, era el tramo mâ”œÃ­s o menos urbano que desde la estaciâ”œâ”‚n de Campo Sepulcro llegaba hasta el camino del Puente del Virrey. Cuando la ciudad engullâ”œâ”‚ los terrenos alrededor de la zanja ferroviaria, se planteâ”œâ”‚ soterrarla, cosa que puso muy contentos a los propietarios de los terrenos, que vieron abrâ”œÂ¡rseles los cielos del Dorado con el proceso de urbanizaciâ”œâ”‚n. En la imagen, aspecto de la trinchera del ferrocarril ya soterrado en lo que hoy es la Avenida de Goya, mâ”œÃ­s o menos a la altura de los nâ”œâ•‘meros 23 (izquierda) y 26 (derecha). La parte izquierda era mayormente antiguos talleres, la "Gran Fâ”œÃ­brica Mecâ”œÃ­nica de Calzado" de Josâ”œÂ® Sorrosal, y los huertos traseros de las fincas de la calle Benavente. Destaca la alta y aâ”œâ•‘n solitaria nueva construcciâ”œâ”‚n del nâ”¬â•‘ 37-43, que chaflanea con el Huerva. Al otro lado del râ”œÂ¡o, aspecto parcial del reciente Instituto Goya, y de los bloques a ambos lados del paseo Fernando el Catâ”œâ”‚lico. La parte derecha de la "calle" era un espacio hasta ese momento apenas las traseras de las construcciones de la calle Zumalacâ”œÃ­rregui (antigua avenida Central), con alguna precaria parcela y un par de pequeâ”œâ–’os bloques, hasta llegar al camino del Sâ”œÃ­bado. Poco a poco, esto se fue urbanizando y motorizando, y en 1969 esto serâ”œÃ­ denominado "Avenida Goya", desde el paseo del General Mola, hasta la Estaciâ”œâ”‚n Campo Sepulcro. Pero antes era asâ”œÂ¡. Hace apenas medio siglo. Fuente visual: Archivo Municipal Zaragoza. Gerardo Sancho Ramo. Noviembre 1965.', 1965, 1965, 1965, 'Anos 60', 'UNIVERSIDAD', 41.64333300, -0.88952700, '0101000020E61000007616BD530177ECBF02B859BC58D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16336682234.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16336682234.webp', 'https://www.flickr.com/photos/zaragozaantigua/16336682234/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25582, 'Pre-Avenida de Goya 1965', 'Otra imagen de la soterrada trinchera del ferrocarril en lo que hoy es la Avenida de Goya, mâ”œÃ­s o menos a la altura del nâ”œâ•‘mero 26. Todas esas pequeâ”œâ–’as parcelas de la izquierda daban a la calle Zumalacâ”œÃ­rregui (antigua avenida Central), y llegaban hasta el antiguo Camino del Sâ”œÃ­bado y la calle Alar del Rey (antigua calle de la Cadena). En unos pocos aâ”œâ–’os toda esta zona quedarâ”œÃ­ irreconocible, restando sâ”œâ”‚lo en pie algunos bloques del fondo de la imagen, que hoy quedan como restos arqueolâ”œâ”‚gicos, fâ”œÃ­cilmente distinguibles por unas formas y alturas bien divergentes de las del actual entorno. Fuente visual: Archivo Municipal Zaragoza. Gerardo Sancho Ramo. 1965.', 1965, 1965, 1965, 'Anos 60', 'UNIVERSIDAD', 41.64333300, -0.88952700, '0101000020E61000007616BD530177ECBF02B859BC58D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16372856114.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16372856114.webp', 'https://www.flickr.com/photos/zaragozaantigua/16372856114/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25591, 'Pasarela Huerva 1965', 'Imagen de la antigua pasarela sobre el râ”œÂ¡o Huerva que desde 1936 conectaba la calle de Zumalacâ”œÃ­rregui (al fondo) con la margen izquierda del râ”œÂ¡o (desde donde se ha capturado la imagen), y daba acceso al paseo de Fernando el Catâ”œâ”‚lico. El obraje que aparece alrededor estâ”œÃ­ relacionado con las obras de cubrimiento de las vâ”œÂ¡as del ferrocarril a Barcelona (a la derecha, fuera de plano), sobre la novâ”œÂ¡sima avenida de Goya, que conllevarâ”œÃ­n la desapariciâ”œâ”‚n de este paso peatonal. En el cartelâ”œâ”‚n que pende en primer tâ”œÂ®rmino puede leerse "Terminantemente prohibido estacionarse en la pasarela"', 1965, 1965, 1965, 'Anos 60', 'UNIVERSIDAD', 41.64372800, -0.89024500, '0101000020E61000003EAE0D15E37CECBF7FC2D9AD65D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33357677960.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33357677960.webp', 'https://www.flickr.com/photos/zaragozaantigua/33357677960/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23637, 'Josâ”œÂ® Millâ”œÃ­n-Astray 1930', 'Foto: Miguel Marâ”œÂ¡n Chivite. Academia General Militar de Zaragoza, 6 de junio de 1930. El coronel Josâ”œÂ® Millâ”œÃ­n-Astray (centro) conversa amigablemente con el rey Alfonso XIII. Este personaje se hizo câ”œÂ®lebre posteriormente por sus increpaciones fascistas y necrâ”œâ”‚filas, como "â”¬Ã­Viva la muerte!", lema apâ”œâ”‚crifo de la Legiâ”œâ”‚n Espaâ”œâ–’ola, fuerza militar creada por â”œÂ®l en 1920. Fuente: Archivo Heraldo de Aragâ”œâ”‚n.', 1930, 1930, 1930, 'Anos 30', NULL, 41.69952500, -0.87188200, '0101000020E610000006137F1475E6EBBF01DE02098AD94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14970758952.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14970758952.webp', 'https://www.flickr.com/photos/zaragozaantigua/14970758952/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25603, 'Claretianos en el tejado 1955', 'Tras mâ”œÃ­s de un aâ”œâ–’o de obras, el nuevo Templo de los Claretianos, va cobrando forma (diseâ”œâ–’o de Eduardo Lagunilla de Plandolit). Su fachada, orientada hacia el noreste, daba a la calle San Antonio Mâ”¬Â¬ Claret, luego Avenida de Goya, tras el cubrimiento de la trinchera del ferrocarril. En la imagen, un par de claretianos (distinguibles por sus hâ”œÃ­bitos oscuros, sus gafas, y su quietud) se han subido al tejado a ver câ”œâ”‚mo avanzan las cosas, mientras los obreros trabajan en el cerramiento de la câ”œâ•‘pula sobre el altar mayor. Al fondo, una buena panorâ”œÃ­mica del suroeste de la ciudad. A la derecha, visual de los edificios del entorno de la Avenida Valencia, Corona de Aragâ”œâ”‚n, y la actual Tomâ”œÃ­s Bretâ”œâ”‚n. Mucho mâ”œÃ­s al fondo, las estribaciones del Sistema Ibâ”œÂ®rico se recortan sobre el horizonte. Fuente visual: www.cormariazaragoza.es/?BODAS-DE-ORO-DE-LA-PARROQUIA', 1955, 1955, 1955, 'Anos 50', 'UNIVERSIDAD', 41.64522700, -0.89376300, '0101000020E6100000C1FEEBDCB499ECBF83BF5FCC96D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15612772816.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15612772816.webp', 'https://www.flickr.com/photos/zaragozaantigua/15612772816/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25610, 'Ensanche de Miralbueno 1932', 'Vista aâ”œÂ®rea de la zona denominada Ensanche de Miralbueno. La lâ”œÂ¡nea blanca que atraviesa la imagen es el trazado de las nuevas avenidas de Reina Victoria, y de Alfonso XIII. La plaza del centro es la de Espaâ”œâ–’a. En la esquina superior izquierda, la entrada al parque de Buenavista. Arriba, en el centro, el cuartel de Palafox. A la izquierda brilla el râ”œÂ¡o Huerva, y a la derecha se ve la zona de "casas baratas". En el â”œÃ­ngulo inferior derecho, la vâ”œÂ¡a del ferrocarril Madrid-Zaragoza. Fuente: Plan general de ensanche de Zaragoza, 1934.', 1932, 1932, 1932, 'Anos 30', 'UNIVERSIDAD', 41.64237900, -0.89372200, '0101000020E61000001DE736E15E99ECBF8F519E7939D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19132531409.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19132531409.webp', 'https://www.flickr.com/photos/zaragozaantigua/19132531409/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25611, 'Trinchera del tren 1934', '"Paso superior de la Gran Vâ”œÂ¡a sobre el ferrocarril de M.Z.A. Destrucciâ”œâ”‚n del viejo y construcciâ”œâ”‚n del nuevo". Obras de acondicionamiento de las infraestructuras necesarias para la prolongaciâ”œâ”‚n de la Gran Vâ”œÂ¡a hasta la Romareda. Cruce de las actuales Gran Vâ”œÂ¡a y Fernando el Catâ”œâ”‚lico con avenida de Goya. Fuente: Plan general de ensanche de Zaragoza, 1934.', 1934, 1934, 1934, 'Anos 30', 'UNIVERSIDAD', 41.64411200, -0.89184400, '0101000020E61000004948A46DFC89ECBF077B134372D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19138758758.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19138758758.webp', 'https://www.flickr.com/photos/zaragozaantigua/19138758758/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25612, 'Casas Baratas 1932', 'Conjunto de edificaciones acogidas a los beneficios de la legislaciâ”œâ”‚n de Casas Baratas y Econâ”œâ”‚micas del Ministerio de Trabajo, segâ”œâ•‘n proyecto de Miguel â”œÃ¼ngel Navarro y Secundino de Zuazo en 1928, para la Sociedad Zaragozana de Urbanizaciâ”œâ”‚n y Costrucciâ”œâ”‚n, constituida por los felices propietarios de los solares. Se hallan en la margen izquierda del râ”œÂ¡o Huerva (abajo), a la altura de la actual calle de Mariano Supervâ”œÂ¡a, donde subsiste una manzana y algunos fragmentos. Fuente: Plan general de ensanche de Zaragoza, 1934.', 1932, 1932, 1932, 'Anos 30', 'UNIVERSIDAD', 41.63903400, -0.89343400, '0101000020E6100000874D64E60297ECBF1B84B9DDCBD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19314390592.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19314390592.webp', 'https://www.flickr.com/photos/zaragozaantigua/19314390592/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25616, 'Calle Bretâ”œâ”‚n 1933', 'Imagen de la calle Tomâ”œÃ­s Bretâ”œâ”‚n donde comenzaba, a la izquierda, la calle de la Virtud. Se trata de uno de los escenarios conflictuales de la "Jornada Revolucionaria" de Zaragoza en diciembre de 1933, lo que explica la presencia de la tropa de Guardia de Seguridad y Asalto, y la publicaciâ”œâ”‚n de la imagen en prensa de alcance estatal. Al fondo, y tras la calle Concepciâ”œâ”‚n Arenal, la calle Lorente, que entonces cerraba Bretâ”œâ”‚n. En 1967, la calle de la Virtud fue redenominada "Pilar Lorengar", en tiempos en que el cambio de nombre de viales no provocaba mucho debate. Fuente Visual: "Mundo Grâ”œÃ­fico" (Madrid).', 1933, 1933, 1933, 'Anos 30', 'UNIVERSIDAD', 41.64446600, -0.89593100, '0101000020E6100000581F0F7D77ABECBF25B1A4DC7DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21988763079.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21988763079.webp', 'https://www.flickr.com/photos/zaragozaantigua/21988763079/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25622, 'C.â”¬â•‘ de los Cubos 1902', 'Dibujo publicitario con una singular y humeante vista de la "fâ”œÃ­brica de lonas para alpargatas y otros tejidos varios" de Castillo y Aznar domiciliada en el sinuoso camino de los Cubos nâ”¬â•‘ 280, en un despejado entorno junto al cauce del râ”œÂ¡o Huerva confrontando con la calle de la Luz, desde donde se habrâ”œÂ¡an tomado los esbozos para esta representaciâ”œâ”‚n. Aâ”œâ–’os despuâ”œÂ®s la fâ”œÃ­brica era ya solo de Câ”œÃ­ndido Castillo, especializada en gâ”œÂ®neros de punto, y finalmente de Hijos de Câ”œÃ­ndido Castillo, hasta la reurbanizaciâ”œâ”‚n de esta zona del antiguo ensanche de Miralbueno, cuando la fâ”œÃ­brica fue derribada y susutituida por modernos bloques de viviendas. Fuente visual: Oficina Espaâ”œâ–’ola de Patentes y Marcas.', 1902, 1902, 1902, 'Anos 1900', 'UNIVERSIDAD', 41.63992000, -0.89147900, '0101000020E6100000DD43C2F7FE86ECBF350708E6E8D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25602635347.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25602635347.webp', 'https://www.flickr.com/photos/zaragozaantigua/25602635347/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25637, 'Calle de Cosme Blasco c.1973', 'Imagen capturada en altura desde el inmueble del nâ”¬â•‘ 9-11 de la calle de Ram de Viu y centrada en el lateral norteâ”œâ–’o del colegio de La Salle Gran Vâ”œÂ¡a lindero con la calle de Cosme Blasco, donde destaca la singular torre, que sobresale por encima de la gran nave de la iglesia, y de las dependencias de residencia y formaciâ”œâ”‚n de los Hermanos de las Escuelas Cristianas, establecidos en 1943 en lo que originalmente fue el nuevo Convento e Iglesia de los Carmelitas Descalzos. El aspecto que luce en la imagen era el resultado de unas recientes e importantes modificaciones y aâ”œâ–’adidos a la estructura original, que llevaron a ser reinaugurado unos pocos aâ”œâ–’os antes (1969). Al fondo, inmuebles de los nâ”œâ•‘meros 4 y 2 de la calle de La Salle. En primer tâ”œÂ®rmino, amplia zona verde integrante del gran complejo de la moderna parroquia del Carmen y San Josâ”œÂ® de los Carmelitas Descalzos, donde poco despuâ”œÂ®s y en una parte serâ”œÂ¡an construidos los modernos bloques de los nâ”œâ•‘meros 19 y 21 de la calle de Santa Teresa de Jesâ”œâ•‘s. A la derecha, casual vista de la esquina en ladrillo, recayente a esa calle, del referido complejo del Carmen y San Josâ”œÂ®, o parroquia de San Juan de la Cruz.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.64032600, -0.89282100, '0101000020E610000013D38558FD91ECBFA663CE33F6D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48389574527.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48389574527.webp', 'https://www.flickr.com/photos/zaragozaantigua/48389574527/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25641, 'P.â”¬â•‘ de Fernando el Catâ”œâ”‚lico 1958', 'Imagen tomada en el bulevar del paseo de Fernando el Catâ”œâ”‚lico con el objetivo centrado en el tramo de los nâ”œâ•‘meros impares entre las calles de San Juan de la Cruz y de Mariano Barbasâ”œÃ­n. Destaca el solar donde poco despuâ”œÂ®s se construirâ”œÂ¡a el bloque del nâ”œâ•‘mero 27 del paseo. La continuidad peatonal del bulevar requerâ”œÂ¡a una especial atenciâ”œâ”‚n para evitar no interrumpir el trâ”œÃ­fico rodado.', 1958, 1958, 1958, 'Anos 50', 'UNIVERSIDAD', 41.64226700, -0.89363600, '0101000020E610000079E75086AA98ECBF672618CE35D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53538453036.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53538453036.webp', 'https://www.flickr.com/photos/zaragozaantigua/53538453036/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26015, 'Vista aâ”œÂ®rea Corona de Aragâ”œâ”‚n 1991', 'Foto: Archivo Taumar (Irene Taulâ”œÂ®s y Rafael Margalâ”œÂ®). Vista aâ”œÂ®rea parcial del distrito Universidad, con la calle Corona de Aragâ”œâ”‚n en el centro, de izquierda a derecha. Abajo a la izquierda, acceso principal de la Ciudad Universitaria. Abajo a la derecha, paseo de Fernando el Catâ”œâ”‚lico. Fuente: www.facebook.com/photo.php?fbid=1687671024789930&set=...', 1991, 1991, 1991, 'Anos 90', 'UNIVERSIDAD', 41.64262500, -0.89519400, '0101000020E6100000E06932E36DA5ECBFC74B378941D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22418696871.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22418696871.webp', 'https://www.flickr.com/photos/zaragozaantigua/22418696871/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26022, 'Cabezo de Buena Vista c.1962', 'Vista del parque Primo de Rivera desde el Cabezo de Buena Vista. Fuente: Foto para postal de Comercial Josan. Cesiâ”œâ”‚n de la familia de Josâ”œÂ® Marâ”œÂ¡a Sanz Gonzâ”œÃ­lez a Rafael Castillejo. Dataciâ”œâ”‚n y procesado:', 1962, 1962, 1962, 'Anos 60', 'UNIVERSIDAD', 41.63366800, -0.89333800, '0101000020E610000000C5C8923996ECBFC84274081CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27321614842.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27321614842.webp', 'https://www.flickr.com/photos/zaragozaantigua/27321614842/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21926, 'Editorial Luis Vives 1946', 'Desde la prismâ”œÃ­tica torre de ladrillo caravista de la novâ”œÂ¡sima Feria de Muestras, un vistazo hacia el "quesito" formado por Fernando el Catâ”œâ”‚lico (arbolado, tranquilâ”œÂ¡simo, rueda un tranvâ”œÂ¡a serie 90 con remolque de la lâ”œÂ¡nea 11 "Parque"), el râ”œÂ¡o Huerva a la derecha (la calle Manuel Lasala no existe aâ”œâ•‘n), y la calle Luis Vives (reciâ”œÂ®n abierta, sin el puente del mismo nombre que conectarâ”œÃ­ luego con el Paseo Mariano Renovales). Una parte de este quesito, propiedad municipal y denominado "Campo de la Victoria", fue ofrecido en subasta a la nueva y marista Editorial Luis Vives en 1940, "cocinâ”œÃ­ndola" lo suficiente para que nadie mâ”œÃ­s se presentara. Y la ganaron. La gran nave de 75x25 m. que allâ”œÂ¡ se levantâ”œâ”‚ fue obra de Regino y Josâ”œÂ® Borobio, y ya en 1941 la Editorial estaba tirando tinta. Las instalaciones crecieron luego hasta por tres en tamaâ”œâ–’o, incluyendo una torre de 45 m. de altura, que aparece en algunas imâ”œÃ­genes de los aâ”œâ–’os 60. En 1975 la Editorial se trasladâ”œâ”‚ a la Carretera de Madrid, donde hoy sigue. Todo el quesito fue vendido a un precio interesante, y fue urbanizado en la forma de los tremendos bloques de viviendas que ahora existen. Justo detrâ”œÃ­s de la Editorial, blanquea el importante Grupo de Viviendas "Francisco Caballero", de Allâ”œÃ­negui y Yarza (1941). Junto a ellas, casas y palacetes unifamiliares que caracterizaban el entorno de la actual calle Ram de Viu. De todos ellos sâ”œâ”‚lo perdura uno, la "Casa Familiar tipo 1", obra de Miguel â”œÃ¼ngel Navarro (1929). Un poco mâ”œÃ­s al fondo, las caracterâ”œÂ¡sticas, por modestas, viviendas obreras del industrial Camino del Sâ”œÃ­bado. Es visible la chimenea de una fâ”œÃ­brica de curtidos, orilla al Huerva, en Juan Pablo Bonet. Al fondo del todo, a la derecha, la masa oscura del Parque Pignatelli, desde donde, en descenso, empezaban a levantarse los grandes bloques que caracterizan al actual Paseo Sagasta. Son visibles los remates de los que se levantan en el cruce de Camino de las Torres con Sagasta. Es visible tambiâ”œÂ®n el enorme depâ”œâ”‚sito de', 1946, 1946, 1946, 'Anos 40', 'UNIVERSIDAD', 41.63748000, -0.89855000, '0101000020E6100000FE43FAEDEBC0ECBF52EDD3F198D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14852586062.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14852586062.webp', 'https://www.flickr.com/photos/zaragozaantigua/14852586062/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21939, 'Feria de Muestras 1941', 'En 1934 tuvo lugar la Iâ”¬Â¬ Feria de Muestras Aragonesa, en la Lonja. Al aâ”œâ–’o siguiente, la IIâ”¬Â¬. En 1936, la guerra motivada por el fracaso del Golpe militar, paralizâ”œâ”‚ tambiâ”œÂ®n esta feria. Desde 1939, el nuevo Râ”œÂ®gimen fascista ganador de la guerra quiso recuperarla, pero dâ”œÃ­ndole un carâ”œÃ­cter "nacionalista". Asâ”œÂ¡, en 1941 tuvo lugar la Iâ”¬Â¬ Feria Nacional de Muestras, del 15 al 31 de mayo, en un recinto con pretensiones de permanencia, el denominado "Palacio de la Producciâ”œâ”‚n Aragonesa", junto al parque al que volvieron a denominar de Primo de Rivera (durante la Repâ”œâ•‘blica fue "Parque de Buena Vista"). En la imagen, dibujo del nuevo recinto ferial, proyectado por Regino y Josâ”œÂ® Borobio Ojeda y Josâ”œÂ® Beltrâ”œÃ­n, que quedarâ”œÃ­ terminado en 1958. Fuente visual: "Aragâ”œâ”‚n: revista grâ”œÃ­fica de cultura aragonesa" (Aâ”œâ–’o XVII, Nâ”¬â•‘ 171, junio-julio 1941).', 1941, 1941, 1941, 'Anos 40', 'UNIVERSIDAD', 41.63742200, -0.89889500, '0101000020E6100000A4367172BFC3ECBF1EE0490B97D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15501207198.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15501207198.webp', 'https://www.flickr.com/photos/zaragozaantigua/15501207198/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21946, 'Fuente de la Princesa 1946', 'Tras su periplo por la ciudad, la Fuente de la Princesa o de Neptuno reposa hoy en el parque Grande. Lo hace desde 1946. Fuente: tausiet.blogspot.com.es/2016/01/la-historia-errante-de-ne...', 1946, 1946, 1946, 'Anos 40', 'UNIVERSIDAD', 41.63533700, -0.89719600, '0101000020E6100000B743C362D4B5ECBF29780AB952D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15883391825.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15883391825.webp', 'https://www.flickr.com/photos/zaragozaantigua/15883391825/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21978, 'Feria de Muestras 1941', 'Del 15 al 31 de mayo de 1941 tuvo lugar la Iâ”¬Â¬ Feria Nacional de Muestras, en un nuevo recinto con pretensiones de permanencia, denominado "Palacio de la Producciâ”œâ”‚n Aragonesa", junto al parque redenominado de Primo de Rivera (antes "de Buena Vista"). La imagen, muy daâ”œâ–’ada, representa el cartel oficial de esta muestra, cuyo diseâ”œâ–’o fue obra de Manuel Bayo Marâ”œÂ¡n ("Bayo"). De la reproducciâ”œâ”‚n y tirada se encargâ”œâ”‚ "Industrias del Cartonaje C.A. Zaragoza". Vertebra la composiciâ”œâ”‚n una estilizada representaciâ”œâ”‚n de la esquinera fachada del nuevo recinto ferial, proyectado por Regino y Josâ”œÂ® Borobio Ojeda, y Josâ”œÂ® Beltrâ”œÃ­n, con la significativa torre aâ”œâ•‘n sin el acristalado remate, y los porches de acceso. Flanquean la torre (que, ademâ”œÃ­s, representa el "I" de la Iâ”¬Â¬ ediciâ”œâ”‚n ferial), los sâ”œÂ¡mbolos propiciatorios de la prosperidad (Atenea), el comercio (Vara de Hermes), la agricultura (una espiga dorada por el sol), y la industria (mecâ”œÃ­nica rueda dentada). A ambos lados, las banderas del râ”œÂ®gimen franquista: la nacional, la de FET-JONS, y la del Requetâ”œÂ®. Por encima, las oscuras alas de una feroz â”œÃ­guila imperial, en actitud sobreprotectora, poco amable, nazi. Fuente visual: www.todocoleccion.net/', 1941, 1941, 1941, 'Anos 40', 'UNIVERSIDAD', 41.63732000, -0.89852900, '0101000020E6100000213EB0E3BFC0ECBF1A8BA6B393D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25168769745.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25168769745.webp', 'https://www.flickr.com/photos/zaragozaantigua/25168769745/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22000, 'Paseo Fernando el Catâ”œâ”‚lico 1949', 'Vista desde la torre de la Feria de Muestras, con el arbolado paseo de Fernando el Catâ”œâ”‚lico que se extiende desde la plaza del Emperador Carlos V, en primer tâ”œÂ®rmino, hasta el fondo de la de San Francisco. En el centro, el pionero bloque de los nâ”œâ•‘meros 31-39 de la calle del Arzobispo Apaolaza en un entorno rururbano todavâ”œÂ¡a marcado por la acequia de la Romareda aâ”œâ•‘n al aire. A la izquierda, el despejado campus de la Universidad. A la derecha, la manzana de la editorial Luis Vives y el Grupo de Viviendas Francisco Caballero detrâ”œÃ­s. Sobre el firme, tendido tranviario de la lâ”œÂ¡nea 11 "Parque", en el acceso al bucle de la terminal sita en la plaza del Emperador Carlos.', 1949, 1949, 1949, 'Anos 40', 'UNIVERSIDAD', 41.63851100, -0.89803700, '0101000020E61000006C223317B8BCECBF71917BBABAD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33647517682.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33647517682.webp', 'https://www.flickr.com/photos/zaragozaantigua/33647517682/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22025, 'Feria de Muestras c.1946', 'Imagen de la Feria Nacional de Muestras capturada desde el puente del 13 de Septiembre durante la celebraciâ”œâ”‚n de la ediciâ”œâ”‚n de ese aâ”œâ–’o, con notable concentraciâ”œâ”‚n de automâ”œâ”‚viles aparcados en la prolongaciâ”œâ”‚n del paseo de Fernando el Catâ”œâ”‚lico y numeroso pâ”œâ•‘blico en torno a la terminal de la tranviaria lâ”œÂ¡nea 11. Parque, donde una composiciâ”œâ”‚n se apresta a recoger su contingente para retornarlo a la ciudad. El recinto ferial se encuentra prâ”œÃ­cticamente finalizado desde que se iniciaran sus obras en 1941. Destacan los pâ”œâ”‚rticos de la entrada, el pabellâ”œâ”‚n de oficinas, de gran vestâ”œÂ¡bulo y la referencial torre-linterna inaugurada en 1944.', 1946, 1946, 1946, 'Anos 40', 'UNIVERSIDAD', 41.63761600, -0.89847500, '0101000020E610000055C1A8A44EC0ECBF03B4AD669DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50155751681.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50155751681.webp', 'https://www.flickr.com/photos/zaragozaantigua/50155751681/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22054, 'Parque Primo de Rivera aâ”œâ–’os 50', 'Paseo de San Sebastiâ”œÃ­n; Parque Grande. .', 1950, 1950, 1959, 'Anos 50', 'UNIVERSIDAD', 41.63585700, -0.89607100, '0101000020E6100000C79BFC169DACECBF62F71DC363D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14911691472.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14911691472.webp', 'https://www.flickr.com/photos/zaragozaantigua/14911691472/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22057, 'La Casa Grande 1955', 'En 1955 fue inaugurada la Residencia Sanitaria Josâ”œÂ® Antonio, "la Casa Grande", en el arbolado y despejado paseo de Isabel la Catâ”œâ”‚lica cerca del Colegio-Residencia de Nuestra Seâ”œâ–’ora del Pilar para Huâ”œÂ®rfanos e Hijos del Magisterio, cuyo edificio figura al fondo a la derecha. Fuente visual: www.bancodeimagenesmedicina.com', 1955, 1955, 1955, 'Anos 50', 'UNIVERSIDAD', 41.63537800, -0.90032100, '0101000020E610000051DD5CFC6DCFECBF884CF91054D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14919054055.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14919054055.webp', 'https://www.flickr.com/photos/zaragozaantigua/14919054055/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22101, 'Prolongaciâ”œâ”‚n Fernando el Catâ”œâ”‚lico 1955', 'Vista del entorno de la Feria de Muestras, la "Residencia Sanitaria Josâ”œÂ® Antonio", y la entrada al Parque Primo de Rivera por el Puente del Trece de Septiembre. La imagen (utilizada para Postal de la Editorial Sicilia) ha sido capturada desde la torre de la Editorial Luis Vives. Un tranvâ”œÂ¡a de la Lâ”œÂ¡nea 11 "Parque" esta dando la vuelta en la plaza Emperador Carlos para tomar rumbo a Plaza de Espaâ”œâ–’a. A la derecha, tras la Feria, estâ”œÃ­n comenzando las obras para la construcciâ”œâ”‚n de un nuevo estadio de fâ”œâ•‘tbol. Tras los campos de herbâ”œÃ­ceas, el nuevo Convento de Jerusalâ”œÂ®n. Al fondo, detrâ”œÃ­s de la Carretera de los Enlaces, pabellones del antiguo Cuartel de Casablanca. Fuente visual: en www.delcampe.net/', 1955, 1955, 1955, 'Anos 50', 'UNIVERSIDAD', 41.63756000, -0.89812100, '0101000020E6100000E2395B4068BDECBF6F9EEA909BD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20472937299.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20472937299.webp', 'https://www.flickr.com/photos/zaragozaantigua/20472937299/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22113, 'La &quot;Casa Grande&quot; c.1950', 'Imagen de la Residencia Sanitaria "Josâ”œÂ® Antonio" en pleno proceso de construcciâ”œâ”‚n. Diseâ”œâ–’ada por Fernando Garcâ”œÂ¡a Mercadal, las obras comenzaron en 1948, siendo terminadas en 1952. La inauguraciâ”œâ”‚n oficial fue en 1955. La imagen ha sido capturada desde las traseras del enorme edificio, junto a la calle Gonzalo Calamita, con el râ”œÂ¡o Huerva a la derecha. Fuente visual: www.cehopu.cedex.es/', 1950, 1950, 1950, 'Anos 50', 'UNIVERSIDAD', 41.63494800, -0.90007300, '0101000020E6100000496760E465CDECBF8F54DFF945D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22288467369.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22288467369.webp', 'https://www.flickr.com/photos/zaragozaantigua/22288467369/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22154, 'Editorial Luis Vives 1958', 'Imagen publicitaria de la Editorial Luis Vives, comercializadora de los libros Edelvives. La empresa se ubicâ”œâ”‚ entre 1941 y 1975 en el paseo de Fernando el Catâ”œâ”‚lico 63. A la izquierda, la calle de Luis Vives. Fuente visual: www.flickr.com/photos/114031783@N02/', 1958, 1958, 1958, 'Anos 50', 'UNIVERSIDAD', 41.63830700, -0.89691300, '0101000020E6100000936E4BE482B3ECBF68E7340BB4D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29368652992.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29368652992.webp', 'https://www.flickr.com/photos/zaragozaantigua/29368652992/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22161, 'Feria de Muestras 1958', 'En 1958, Zaragoza soportâ”œâ”‚ un amplio despliegue conmemorativo de los sitios que habâ”œÂ¡an tenido lugar 150 aâ”œâ–’os antes. Se trasladâ”œâ”‚ el cadâ”œÃ­ver de Palafox desde Madrid a la cripta del Pilar. La Instituciâ”œâ”‚n Fernando el Catâ”œâ”‚lico celebrâ”œâ”‚ un congreso de historia en el que la tâ”œâ”‚nica general fue comparar la Guerra Civil con la de la Independencia, atribuyendo a ambas el carâ”œÃ­cter de cruzada catâ”œâ”‚lica. Hubo dos exposiciones, en la Aljaferâ”œÂ¡a sobre los Sitios y en el Museo Etnolâ”œâ”‚gico del parque Primo de Rivera sobre etnografâ”œÂ¡a aragonesa y del sur de Francia. Y en el recinto de la Feria de Muestras, se celebrâ”œâ”‚ una Exposiciâ”œâ”‚n Hispano Francesa, conmemorativa de la celebrada en 1908, inaugurâ”œÃ­ndose el Pabellâ”œâ”‚n Francâ”œÂ®s y dando por concluida la construcciâ”œâ”‚n del recinto. La medalla conmemorativa de este â”œâ•‘ltimo evento reproduce las instalaciones de la Feria de Muestras en el paseo de Isabel la Catâ”œâ”‚lica, asâ”œÂ¡ como los sâ”œÂ¡mbolos vigentes de los dos paâ”œÂ¡ses, y el nuevo pabellâ”œâ”‚n al fondo a la derecha. Fuente visual: www.ebay.es', 1958, 1958, 1958, 'Anos 50', 'UNIVERSIDAD', 41.63746900, -0.89934600, '0101000020E6100000B43A394371C7ECBF5F9B8D9598D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30608389495.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30608389495.webp', 'https://www.flickr.com/photos/zaragozaantigua/30608389495/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22183, 'Cuartel Palafox 1959', 'Imagen capturada como souvenir en el patio de armas del cuartel de Palafox, sede del Regimiento de Montaâ”œâ–’a nâ”¬â•‘ 20. Al fondo, la puerta principal de ingreso, recayente a la calle Domingo Miral. Fuente visual: www.flickr.com/photos/ejercitodetierra/12831102125/in/alb...', 1959, 1959, 1959, 'Anos 50', 'UNIVERSIDAD', 41.63974300, -0.90029700, '0101000020E61000002FFB75A73BCFECBF276C3F19E3D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31952620822.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31952620822.webp', 'https://www.flickr.com/photos/zaragozaantigua/31952620822/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22211, 'RS Josâ”œÂ® Antonio 1955', 'Imagen capturada en la amplia zona a la izquierda de la prolongaciâ”œâ”‚n de la Gran Vâ”œÂ¡a, junto al cauce del râ”œÂ¡o Huerva, donde habâ”œÂ¡a sido construida la gran residencia del Instituto Nacional de Previsiâ”œâ”‚n, que con proyecto de Fernando Garcâ”œÂ¡a Mercadal fue inaugurada oficialmente como Residencia Sanitaria Josâ”œÂ® Antonio. En sus 16 plantas de altura albergaba capacidad para un mâ”œÃ­ximo de 596 camas, e incluâ”œÂ¡a ambulatorio, quirâ”œâ”‚fanos, maternidad, solarium, sala de conferencias y capilla. La fotografâ”œÂ¡a se centra en el original ingreso principal a la residencia, con rampas laterales para vehâ”œÂ¡culos y escaleras centrales para peatones, ascendentes desde el nivel de la calle entre jardines y â”œÃ­rboles. Una ampliaciâ”œâ”‚n acometida a principios de los aâ”œâ–’os setenta, que elevâ”œâ”‚ la capacidad de la residencia hasta las 1400 camas, transformâ”œâ”‚ completamente este ingreso. Fuente visual: bancodeimagenesmedicina.com', 1955, 1955, 1955, 'Anos 50', 'UNIVERSIDAD', 41.63541400, -0.90057700, '0101000020E61000000EF450DB86D1ECBFD4B5F63E55D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/44635378341.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/44635378341.webp', 'https://www.flickr.com/photos/zaragozaantigua/44635378341/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22234, 'La Romareda 1958', 'Vista aâ”œÂ®rea centrada en la Residencia Sanitaria Josâ”œÂ® Antonio, la prolongaciâ”œâ”‚n de la avenida de Fernando el Catâ”œâ”‚lico y el novâ”œÂ¡simo estadio municipal de La Romareda, flanqueado a la izquierda por el nuevo convento de Jerusalâ”œÂ®n, y a la derecha por el ampliado recinto de la Feria Nacional de Muestras. Tras la carretera de Valencia, tradicional entorno agrâ”œÂ¡cola con campos de cultivo surtidos de torres y regados por la acequia de La Romareda. A la derecha, el cuartel de Palafox.', 1958, 1958, 1958, 'Anos 50', 'UNIVERSIDAD', 41.63558800, -0.90064200, '0101000020E6100000D5EDEC2B0FD2ECBF72DD94F25AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50226827921.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50226827921.webp', 'https://www.flickr.com/photos/zaragozaantigua/50226827921/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22237, 'La Residencia Sanitaria 1955', 'Imagen de la reciâ”œÂ®n terminada Residencia Sanitaria Josâ”œÂ® Antonio, cuyas obras comenzaron en 1947 en la prolongaciâ”œâ”‚n de Fernando el Catâ”œâ”‚lico, principio del actual de Isabel la Catâ”œâ”‚lica. Se muestra en todo su luminoso volumen el escalonado diseâ”œâ–’o que desde los pâ”œâ”‚rticos de acceso va ascendiendo en altura hasta las plantas superiores del hospital, desde donde las vistas de la ciudad son espectaculares. En primer tâ”œÂ®rmino, campos de herbâ”œÃ­ceas donde un par de aâ”œâ–’os despuâ”œÂ®s se inaugurarâ”œÂ¡a el estadio municipal de La Romareda.', 1955, 1955, 1955, 'Anos 50', 'UNIVERSIDAD', 41.63546700, -0.90052400, '0101000020E6100000596B28B517D1ECBFF7578FFB56D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50855883151.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50855883151.webp', 'https://www.flickr.com/photos/zaragozaantigua/50855883151/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22302, 'Antonio Machâ”œÂ¡n 1965', 'Firma de autâ”œâ”‚grafos a enfermeras de la Residencia Sanitaria Josâ”œÂ® Antonio (Casa Grande), por parte de Antonio Machâ”œÂ¡n (1903-1977), câ”œÂ®lebre cantante cubano afincado en Espaâ”œâ–’a, que en la â”œÂ®poca de la visita concertada al hospital zaragozano pasaba por una racha de declive de popularidad. Fuente: www.facebook.com/photo.php?fbid=642369309205738&set=p...', 1965, 1965, 1965, 'Anos 60', 'UNIVERSIDAD', 41.63537800, -0.90032100, '0101000020E610000051DD5CFC6DCFECBF884CF91054D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15598106018.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15598106018.webp', 'https://www.flickr.com/photos/zaragozaantigua/15598106018/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22448, 'Vista Parque Primo de Rivera 1960', 'Vista aâ”œÂ®rea sobre el parque Primo de Rivera. Destacan las torres de la Feria de Muestras y de la Editorial Luis Vives. Fuente: TAF Helicâ”œâ–“pters. Arxiu Nacional de Catalunya.', 1960, 1960, 1960, 'Anos 60', 'UNIVERSIDAD', 41.63552000, -0.89725400, '0101000020E6100000DE9046054EB6ECBF1AFA27B858D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31208759382.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31208759382.webp', 'https://www.flickr.com/photos/zaragozaantigua/31208759382/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22449, 'Vista &quot;Casa Grande&quot; 1960', 'Vista aâ”œÂ®rea centrada en la Residencia Sanitaria Josâ”œÂ® Antonio o "Casa Grande", con el estadio de fâ”œâ•‘tbol de la Romareda a la izquierda, junto a la Feria de Muestras. Fuente: TAF Helicâ”œâ–“pters. Arxiu Nacional de Catalunya.', 1960, 1960, 1960, 'Anos 60', 'UNIVERSIDAD', 41.63521200, -0.89996000, '0101000020E61000003FA9F6E978CCECBF6D0377A04ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31208862682.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31208862682.webp', 'https://www.flickr.com/photos/zaragozaantigua/31208862682/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25598, 'A la Romareda 1973', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. 01/10/1973. Un lunes de fâ”œâ•‘tbol era cosa extraordinaria, fuera de lo normal, si es que ese adjetivo encaja en el universo balompâ”œÂ®dico. Y bien calentito estaba todavâ”œÂ¡a el 4 a 0 endosado por el Madrâ”œÂ¡, un par de dâ”œÂ¡as antes, en la quinta jornada de Liga. Ademâ”œÃ­s, este era un partido amistoso (homenaje a Garcâ”œÂ¡a Carnicer), y el natural competitivo decae, por mucho que el "rival" fuera la "Selecciâ”œâ”‚n Aragonesa", si bien la pugna Zaragoza-Aragâ”œâ”‚n es hecho bien trascendente en esta ciudad, quasiantropolâ”œâ”‚gico, que supera la mera autofagia. Por aquellos aâ”œâ–’os se hablaba mucho de eso, incluso desde un punto de vista extradeportivo. La imagen captura el estado de los accesos al recinto de la Romareda desde Isabel la Catâ”œâ”‚lica, que mâ”œÃ­s que accesos, asemejan traviesa gymkana, cuando no demencial "pista americana". El concepto "barrera arquitectâ”œâ”‚nica", o "accesibilidad", eran aâ”œâ•‘n meros delirios foranos. Pero nada parecâ”œÂ¡a importar para ver al equipo del momento, jugara contra quien jugara, lo que se jugara, y aunque hubiera que sortear montaâ”œâ–’as de grava y conglomerados: Nieves, Violeta, Garcâ”œÂ¡a Castany, Planas, Ocampos, Diarte... y con Arrâ”œâ•‘a a punto de llegar, lo merecâ”œÂ¡an. Vale. Al fondo, a la izquierda, la mole de los bloques denominados "Marvel", entre Fray Luis Amigo y Alfonso X el Sabio. Debajo, la esquina neomudâ”œÂ®jar de Luis Bermejo cuando toda esa manzana, junto con la Câ”œÃ­mara de Comercio, conformaba el Recinto Ferial. La masa vegetal es el Parque Grande; por abajo fluye el Huerva. A la derecha, arranque del nuevo edificio del Centro Materno-Infantil de la Casa Grande, lugar aâ”œâ•‘n muy frecuentado en aquellos aâ”œâ–’os.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.63671000, -0.90009500, '0101000020E61000003D61890794CDECBFA18499B67FD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14873091373.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14873091373.webp', 'https://www.flickr.com/photos/zaragozaantigua/14873091373/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25609, 'Romareda 1957', 'Vista aâ”œÂ®rea de las construcciones que poco a poco iban jalonando el nuevo paseo de Isabel la Catâ”œâ”‚lica: el cuartel de Palafox, el recinto de la feria de Muestras, la "Residencia Sanitaria Jose Antonio", el estadio municipal de "La Romareda", el Monasterio de Santa Marâ”œÂ¡a de Jerusalâ”œÂ®n de las HH. Clarisas, y el Colegio-residencia Nâ”¬Â¬. Sâ”¬Â¬. del Pilar para Huerfanos e Hijos del Magisterio. Junto a la "Casa Grande", el râ”œÂ¡o Huerva y el Parque Primo de Rivera. Son tambiâ”œÂ®n visibles los productivos campos de cultivo de esta zona de la lejana periferia zaragozana. Fuente visual: Servicio Aragonâ”œÂ®s de Salud (Pâ”œâ•‘blica) sectorzaragozados.salud.aragon.es/', 1957, 1957, 1957, 'Anos 50', 'UNIVERSIDAD', 41.63614900, -0.90093200, '0101000020E6100000976F7D586FD4ECBF0A3197546DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18996959306.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18996959306.webp', 'https://www.flickr.com/photos/zaragozaantigua/18996959306/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25620, 'Don Cicuta 1973', 'Nacido en el arranque del siglo XX (1901), Valentâ”œÂ¡n Tornos Lâ”œâ”‚pez fue un veterano actor teatral, cinematogrâ”œÃ­fico y televisivo de discreta notoriedad popular, pues los suyos eran esos papeles secundarios siempre fuera del foco mediâ”œÃ­tico, a desmano de lo protagâ”œâ”‚nico. Asâ”œÂ¡ fue hasta que aceptâ”œâ”‚ encarnar a un carpetovetâ”œâ”‚nico personaje, de nombre "Don Cicuta", en un concurso televisivo que tenâ”œÂ¡a una calabaza como referencia, y que comenzâ”œâ”‚ a ser emitido en 1972. Su sentida interpretaciâ”œâ”‚n de los eternos valores patrios, en unos pocos programas se tradujo en uno de esos contundentes, râ”œÃ­pidos y populares "fenâ”œâ”‚menos sociolâ”œâ”‚gicos" carentes de lâ”œâ”‚gica y explicaciâ”œâ”‚n racional alguna. Valentâ”œÂ¡n, caracterizado como el personaje televisivo Don Cicuta, fue convertido en un objeto icâ”œâ”‚nico de consumo masivo (juguetes de todo tipo, cromos, hasta un vinilo), y de merecido reconocimiento profesional ("TP" de Oro de 1972 al "Personaje mâ”œÃ­s Popular"). En este estado de las cosas, fue invitado a la Feria Internacional de Maquinaria Agrâ”œÂ¡cola (FIMA) de 1973, como popularâ”œÂ¡simo personaje que era, para hacer publicidad de Motor Ibâ”œÂ®rica S.A. En la imagen, azafatas de la empresa y pâ”œâ•‘blico de la Feria en general, rodean a Valentâ”œÂ¡n Tornos/Don Cicuta en proceso de firmar un autâ”œâ”‚grafo. Fuente visual: Gerardo Sancho Ramo, en AMZ.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.63759000, -0.89959300, '0101000020E6100000A5BC564277C9ECBFDA20938C9CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23891803424.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23891803424.webp', 'https://www.flickr.com/photos/zaragozaantigua/23891803424/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25630, 'P.â”¬â•‘ de Isabel la Catâ”œâ”‚lica 1955', 'Vista del entorno de la Feria de Muestras, la reciente Residencia Sanitaria Josâ”œÂ® Antonio, y la entrada al Parque Primo de Rivera por el Puente del Trece de Septiembre. La imagen ha sido capturada desde la torre de la Editorial Luis Vives. Un tranvâ”œÂ¡a de la lâ”œÂ¡nea 11 "Parque" permanece en la terminal de la plaza Emperador Carlos V, antes de tomar rumbo a la plaza de Espaâ”œâ–’a, y una unidad de la lâ”œÂ¡nea 15 "Casablanca" se aproxima por Isabel la Catâ”œâ”‚lica, encaminada hacia esa misma direcciâ”œâ”‚n. Esta imagen tiene mucho en comâ”œâ•‘n con otra similar comercializada por ediciones SICILIA (tambiâ”œÂ®n incluida en este Gran Archivo Zaragoza Antigua), tal vez tomadas ambas por la misma persona. Fuente visual: postal de Ediciones DARVI, en www.abebooks.com', 1955, 1955, 1955, 'Anos 50', 'UNIVERSIDAD', 41.63751000, -0.89841300, '0101000020E6100000D3A3A99ECCBFECBFBD6F7CED99D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34043226291.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34043226291.webp', 'https://www.flickr.com/photos/zaragozaantigua/34043226291/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25640, 'Vista c.1956', 'Imagen capturada desde la notable altura de la terraza mâ”œÃ­s norteâ”œâ–’a de la moderna "Residencia Sanitaria Josâ”œÂ® Antonio del Seguro Obligatorio de Enfermedad" y orientada en la direcciâ”œâ”‚n del paseo de Fernando el Catâ”œâ”‚lico, que hacia el fondo muestra el fondo de las antiguas torres y câ”œâ•‘pulas del centro de la ciudad. A la izquierda, la torre-mirador de la Feria de Muestras.', 1956, 1956, 1956, 'Anos 50', 'UNIVERSIDAD', 41.63539500, -0.89954800, '0101000020E6100000A6D425E318C9ECBF5E85949F54D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51676817060.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51676817060.webp', 'https://www.flickr.com/photos/zaragozaantigua/51676817060/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22654, 'Ciudad Universitaria 1976', 'Postal. Aspecto de la Ciudad Universitaria o Campus San Francisco de Zaragoza, en 1976. En primer plano, estanque desaparecido. Tras la Facultad de Ciencias (1950), el Hospital Clâ”œÂ¡nico Universitario (1974). Fuente: www.facebook.com/photo.php?fbid=513848895438611&set=g...', 1976, 1976, 1976, 'Anos 70', 'UNIVERSIDAD', 41.64172000, -0.89829400, '0101000020E6100000412D060FD3BEECBF359886E123D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21397902242.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21397902242.webp', 'https://www.flickr.com/photos/zaragozaantigua/21397902242/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25642, 'Cines Renoir 2012', 'Los multicines Renoir de Zaragoza estaban en el centro comercial Los Porches del Audiorama, con entrada por la calle de Luis Bermejo 4. Se inauguraron con un pase de la pelâ”œÂ¡cula "Niâ”œâ–’o nadie", de Josâ”œÂ® Luis Borau, el 22 de enero de 1997 y abrieron sus puertas a todo el pâ”œâ•‘blico una semana despuâ”œÂ®s. Fueron cerrados el 10 de mayo de 2012, y un tiempo despuâ”œÂ®s sustituidos por un gimnasio.', 2012, 2012, 2012, 'Siglo XXI', 'UNIVERSIDAD', 41.63691200, -0.89964800, '0101000020E6100000882D3D9AEAC9ECBF0937195586D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54391001010.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54391001010.webp', 'https://www.flickr.com/photos/zaragozaantigua/54391001010/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22636, 'La Milagrosa 1970', 'En el aâ”œâ–’o de 1907 la Duquesa de Villahermosa creâ”œâ”‚ una fundaciâ”œâ”‚n para niâ”œâ–’os/as (menores de 14 aâ”œâ–’os) pobres de Zaragoza, a cuyo cargo estarâ”œÂ¡an las Hijas de La Caridad de San Vicente de Paâ”œâ•‘l. El 12 de febrero de 1916, en la finca del solar Maestro Estremiana 3-5, se realizan obras de acomodaciâ”œâ”‚n para impartir allâ”œÂ¡ educaciâ”œâ”‚n, pero el edificio se remodela con vigas de madera verde, lo cual traerâ”œÃ­ luego serias consecuencias. El 2 de octubre de 1921 Sor Concepciâ”œâ”‚n Marâ”œÂ¡n Segura recibe en herencia la casa de verano de sus padres, situada en el "barrio de Torrero" (el chaflâ”œÃ­n del paseo Cuellar nâ”¬â•‘ 57 con la Vâ”œÂ¡a de San Fernando nâ”¬â•‘ 1), con la finalidad de dar enseâ”œâ–’anza gratuita a las niâ”œâ–’as del barrio. En etapas sucesivas se van adquiriendo nuevos terrenos en los que se crearâ”œÃ­n "Las Escuelas de La Milagrosa". Con el tiempo, estas "Escuelas de La Milagrosa" llegaron a tener un nâ”œâ•‘mero de alumnas muy elevado, lo que hizo imposible continuar en esa ubicaciâ”œâ”‚n. Justo en ese momento, la Fundaciâ”œâ”‚n Duquesa Villahermosa no podâ”œÂ¡a continuar su labor educativa en la casa de Maestro Estremiana, ya que se encontraba muy deteriorada: las vigas de madera verde, antes citadas, cedieron al secarse y la termita causâ”œâ”‚ graves destrozos en la estructura de la casa. A estos hechos se uniâ”œâ”‚ un incendio en los desvanes que obligâ”œâ”‚ a desalojar definitivamente el edificio. Tras la venta del edificio de Cuâ”œÂ®llar de "Las Escuelas de La Milagrosa", se comienza la construcciâ”œâ”‚n de un nuevo colegio en el solar de la calle del Maestro Estremiana 3 y 5 (anterior Fundaciâ”œâ”‚n Duquesa Villahermosa), con el nombre de "Colegio La Milagrosa", inaugurado el 19 de marzo de 1978. En la imagen, captura del chaflâ”œÃ­n de "Las Escuelas de La Milagrosa", entre el paseo de Cuâ”œÂ®llar 57 (con vehâ”œÂ¡culos aparcados en la acera), y la Vâ”œÂ¡a de San Fernando 1 (hacia la derecha, donde seâ”œâ–’ala el cartel a "Alcaâ”œâ–’iz"). En la actualidad todo esto forma parte del gran bloque de viviendas del 55-57 del paseo de Cuâ”œÂ®llar.', 1970, 1970, 1970, 'Anos 70', 'UNIVERSIDAD', 41.63543500, -0.88449500, '0101000020E610000076374F75C84DECBFECDD1FEF55D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20246682241.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20246682241.webp', 'https://www.flickr.com/photos/zaragozaantigua/20246682241/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22679, '&quot;Bosque de la Amistad&quot; 1970', 'El Bosque de la Amistad estaba a los pies del Cabezo de Buenavista, en el parque de Primo de Rivera, y se utilizaba como escenario del concurso de belleza Maja Internacional organizado por la Asociaciâ”œâ”‚n Goya Internacional que se celebraba, como era tradicional desde 1966, en el Palacio de la Lonja, dentro de las Fiestas de Primavera. En la imagen, las candidatas a la quinta ediciâ”œâ”‚n de este certamen posan vestidas con atavâ”œÂ¡os tradicionales.', 1970, 1970, 1970, 'Anos 70', 'UNIVERSIDAD', 41.63464100, -0.89330400, '0101000020E6100000FB592C45F295ECBFB2D991EA3BD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26304711951.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26304711951.webp', 'https://www.flickr.com/photos/zaragozaantigua/26304711951/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22703, 'P.â”¬â•‘ de Ruiseâ”œâ–’ores 1971', 'Imagen capturada en el paseo de Ruiseâ”œâ–’ores y centrada en el murete que delimitaba el acceso al antiguo Colegio Pompiliano en el nâ”¬â•‘ 26, antaâ”œâ–’o seâ”œâ–’alada por su notable altura que destacaba en las fotografâ”œÂ¡as de la zona, ya derribado y en trâ”œÃ­nsito de conversiâ”œâ”‚n en una parcela con varios modernos y selectos inmuebles. A su izquierda, el moderno colegio Pompiliano. Al fondo, bloques del Grupo Salduba todavâ”œÂ¡a recayentes al cauce al aire de la acequia de las Adulas, o de San Josâ”œÂ®. A la izquierda, fuera de plano, perduraban las antiguas viviendas unifamiliares de los nâ”œâ•‘meros 24 y 22 (esta ya esquinera con la calle de Fernando de Antequera), si bien tiempo despuâ”œÂ®s tambiâ”œÂ®n fueron sustituidas por modernas construcciones residenciales de alta categorâ”œÂ¡a. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1971, 1971, 1971, 'Anos 70', 'UNIVERSIDAD', 41.63627900, -0.88923600, '0101000020E61000009DA04D0E9F74ECBFD8101C9771D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27546737448.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27546737448.webp', 'https://www.flickr.com/photos/zaragozaantigua/27546737448/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22823, 'Parque de Primo de Rivera 1970', 'Simpâ”œÃ­tica imagen capturada durante la ceremonia de plantaciâ”œâ”‚n de arbustos en el "Bosque de la Amistad" (final del paseo de San Sebastiâ”œÃ­n en el parque de Primo de Rivera) inserta en el programa de actividades de la elecciâ”œâ”‚n de la "Maja Internacional". La de la fotografâ”œÂ¡a era la representante austrâ”œÂ¡aca, seâ”œâ–’orita Inge Krottendorfer, que "ataviada con el traje tâ”œÂ¡pico de su paâ”œÂ¡s" posa para los reporteros grâ”œÃ­ficos con una pala mientras dos operarios de Parques y Jardines realizan la tarea.', 1970, 1970, 1970, 'Anos 70', 'UNIVERSIDAD', 41.63415200, -0.89400100, '0101000020E6100000E6EB32FCA79BECBFB4588AE42BD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51720247037.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51720247037.webp', 'https://www.flickr.com/photos/zaragozaantigua/51720247037/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23001, 'Parque Primo de Rivera aâ”œâ–’os 90', 'Escaleras de acceso al Cabezo de Buena Vista, con la estatua de Alfonso I el Batallador al fondo. Fuente: Foto para postal de Comercial Josan. Cesiâ”œâ”‚n de la familia de Josâ”œÂ® Marâ”œÂ¡a Sanz Gonzâ”œÃ­lez a Rafael Castillejo. Dataciâ”œâ”‚n y procesado:', 1990, 1990, 1999, 'Anos 90', 'UNIVERSIDAD', 41.63440400, -0.89428200, '0101000020E6100000DCD8EC48F59DECBFCE39782634D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27146138930.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27146138930.webp', 'https://www.flickr.com/photos/zaragozaantigua/27146138930/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23021, 'P.â”¬â•‘ de Ruiseâ”œâ–’ores 1990', 'Granulada y parcial imagen, pero muy interesante, de la que fuera antigua fâ”œÃ­brica de harinas "La Imperial de Aragâ”œâ”‚n", en funcionamiento desde mediados de los aâ”œâ–’os sesenta del siglo XIX hasta los aâ”œâ–’os ochenta del pasado siglo XX en su domicilio social del paseo de Ruiseâ”œâ–’ores nâ”¬â•‘ 40. La captura se habrâ”œÂ¡a realizado desde la vecina urbanizaciâ”œâ”‚n de inmuebles adosados que la rodea por sus lados norte y oeste, durante el proceso de derribo de esta fâ”œÃ­brica para dar paso a una moderna urbanizaciâ”œâ”‚n de 24 inmuebles de selecta alta gama. En primer plano, â”œÃ­rboles que jalonaban el original acceso a la harinera desde el paseo de Ruiseâ”œâ–’ores. A la izquierda, balaustrada que delimitaba su perâ”œÂ¡metro, en este caso recayente al referido paseo. A la derecha, patio que vertebraba las instalaciones fabriles con edificios de una, dos y tres alturas. En el centro de la imagen, decorativa fachada principal de la fâ”œÃ­brica recayente tambiâ”œÂ®n al paseo del Canal, resultado de la remodelaciâ”œâ”‚n diseâ”œâ–’ada por el arquitecto Miguel â”œÃ¼ngel Navarro hacia 1920. Al fondo, â”œÃ­rboles de la ribera del Canal Imperial y modernos edificios de las calles de Joaquâ”œÂ¡n Octavio de Toledo y del Cabezo de Buenavista Fuente visual: AMZ.', 1990, 1990, 1990, 'Anos 90', 'UNIVERSIDAD', 41.63413000, -0.89098500, '0101000020E6100000FB3F87F9F282ECBFCCB4FD2B2BD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/43590730681.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/43590730681.webp', 'https://www.flickr.com/photos/zaragozaantigua/43590730681/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23454, 'P.â”¬â•‘ de Ruiseâ”œâ–’ores 1990', 'Una de las caracterâ”œÂ¡sticas de las calles privadas de la ciudad, fueran de los ensanches obreros o burgueses, como en este caso, es que no perdura documentaciâ”œâ”‚n municipal respecto a su edificaciâ”œâ”‚n, ya que fue a partir de 1913 cuando se hizo obligatorio el trâ”œÃ­mite de solicitud de licencia para edificar en ellas, y durante unos cuantos aâ”œâ–’os este requisito fue bastante "flexible" en su aplicaciâ”œâ”‚n. Este edificio fue concebido como vivienda unifamiliar, con la denominaciâ”œâ”‚n "Villa Rosita", propiedad de Raimundo Balet, proyectada por Manuel Isasi Isasmendi y edificada en 1903 en el nâ”¬â•‘ 13 (actual nâ”¬â•‘ 39) del paseo de los Ruiseâ”œâ–’ores. Posteriormente ha sufrido numerosas reformas, algunas muy sustanciales, como la de 1919 a cargo de Miguel â”œÃ¼ngel Navarro Pâ”œÂ®rez, o la que le aâ”œâ–’adiâ”œâ”‚ el esquinado torreâ”œâ”‚n modernista de la imagen, rematado con câ”œâ•‘pula recubierta con vistosos trozos cerâ”œÃ­micos. En el momento de capturar la imagen, cuando ya apenas si quedaban rastros de su traza original, aâ”œâ•‘n contaba con el letrero de su mâ”œÃ­s reciente funciâ”œâ”‚n: sede desde 1960 del colegio Santo Tomâ”œÃ­s de Aquino de bachillerato masculino primero, luego Mixto de BUP y COU hasta su cierre en 1986. Fuente visual: "Zaragoza barrio a barrio"', 1990, 1990, 1990, 'Anos 90', 'UNIVERSIDAD', 41.63651000, -0.88907700, '0101000020E61000007D06D49B5173ECBFDAC9E02879D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15328438123.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15328438123.webp', 'https://www.flickr.com/photos/zaragozaantigua/15328438123/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21490, 'Director de la AGM 1928', 'AHPZ. Estudio Coyne. 1928. "Francisco Franco, en la Academia General Militar." La primera Academia General Militar (Toledo) fue disuelta en 1892. En 1927, durante la Dictadura de Primo de Rivera, el golpista general propuso al rey reabrirla. Asâ”œÂ¡ se hizo, y la A.G.M. (Segunda â”œÃ«poca) se enclavâ”œâ”‚ en Zaragoza, por su situaciâ”œâ”‚n estratâ”œÂ®gica y por la proximidad del campo de maniobras de S. Gregorio. Para ello, se invirtieron ingentes cantidades de dinero pâ”œâ•‘blico, y se levantâ”œâ”‚ un enorme complejo en estilo neomudâ”œÂ®jar. Como primer director del nuevo centro, Primo de Rivera eligiâ”œâ”‚ a un prometedor joven general, procedente del tercio â”¬Â½africanistaâ”¬â•— del ejâ”œÂ®rcito, Francisco Franco Bahamonde, que desempeâ”œâ–’â”œâ”‚ el cargo desde agosto de 1927 al 14 de julio de 1931, cuando la reforma militar llevada a cabo por el gobierno de la Segunda Repâ”œâ•‘blica democrâ”œÃ­tica espaâ”œâ–’ola, volviâ”œâ”‚ al sistema de las Academias Especiales de las Armas. Esta reforma intentâ”œâ”‚ una soluciâ”œâ”‚n al sinsentido de la realidad organizativa del ejâ”œÂ®rcito espaâ”œâ–’ol, con 21.000 jefes y oficiales (entre ellos, 800 generales) para 118.000 soldados de tropa. Pocos aâ”œâ–’os despuâ”œÂ®s se llevâ”œâ”‚ a cabo otra "reforma" (golpe de estado fracasado que desembocâ”œâ”‚ en guerra), radical, dolorosa y sangrienta, que definiâ”œâ”‚ no sâ”œâ”‚lo el futuro del ejâ”œÂ®rcito, sino el de todo el paâ”œÂ¡s. En ambos casos estuvo por el medio el fotografiado. En la imagen, el general Francisco Franco en su despacho posa en su despacho del cuartel del Carmen, donde provisionalmente estaban instaladas las oficinas de la academia.', 1928, 1928, 1928, 'Anos 20', NULL, 41.69932600, -0.87172000, '0101000020E6100000A29C685721E5EBBF0A9FAD8383D94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15202789213.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15202789213.webp', 'https://www.flickr.com/photos/zaragozaantigua/15202789213/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21497, 'Monasterio de Santa Fe de Huerva c.1920', 'Imagen exterior del antiguo Monasterio de Santa Fe de Huerva, en la parte mâ”œÃ­s al Sur de la ciudad. Cisterciense en fâ”œÃ­brica barroca del s. XVIII, estâ”œÃ­ abandonado desde la exclaustraciâ”œâ”‚n de 1835, y tuvo que ser objeto de una intervenciâ”œâ”‚n pâ”œâ•‘blica de urgencia en 1981 para evitar su total ruina, ante la inacciâ”œâ”‚n de sus privados propietarios. En la imagen, visual del antiguo monasterio en los comienzos del S. XX, en la zona de su acceso principal. A la izquierda, a apenas 140 metros, el cauce del râ”œÂ¡o Huerva. Por donde circula el ciclista seguido de chiquillerâ”œÂ¡a, hoy hay un aparcamiento y un establecimiento hostelero, en la confluencia de la calle Camino del Plano, y la Avenida de la Muralla de Santa Fe.', 1920, 1920, 1920, 'Anos 20', NULL, 41.57758700, -0.94988800, '0101000020E6100000739CDB847B65EEBF21CCED5EEEC94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15348604094.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15348604094.webp', 'https://www.flickr.com/photos/zaragozaantigua/15348604094/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21583, 'San Juan de Mozarrifar 1923', 'El martes 10 de julio de 1923, Zaragoza y sus inmediaciones fueron testigos de una rara acumulaciâ”œâ”‚n catastrâ”œâ”‚fica. De madrugada se produjo un terremoto, haciendo sonar las campanas de las iglesias. Al inicio de la tarde, las nubes oscurecieron la ciudad y un ciclâ”œâ”‚n la agitâ”œâ”‚ con fuerza, derribando chimeneas como la de la fâ”œÃ­brica de galletas Patria. Una granizada de considerables dimensiones asolâ”œâ”‚ las calles. Las tormentas continuaron hasta el crepâ”œâ•‘sculo. Se cortaron las vâ”œÂ¡as fâ”œÂ®rreas. En Villanueva de Gâ”œÃ­llego se sufrieron graves inundaciones. Y en San Juan de Mozarrifar se hundieron 33 casas, siendo los vecinos evacuados en barcas, momento que recoge la foto. Al fondo, la papelera de Las Navas, y sus chimeneas.', 1923, 1923, 1923, 'Anos 20', NULL, 41.71404800, -0.83737100, '0101000020E610000057CD7344BECBEABF19E3C3EC65DB4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24546633600.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24546633600.webp', 'https://www.flickr.com/photos/zaragozaantigua/24546633600/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21708, 'AGM 1938', '"Frente de Aragâ”œâ”‚n. Prisioneros republicanos y de las Brigadas Internacionales capturados en el avance nacional sobre Lâ”œÂ®rida". 8 de mayo de 1938. Desde julio de 1936, los sublevados contra la Repâ”œâ•‘blica habâ”œÂ¡an habilitado un campo de concentraciâ”œâ”‚n en el Cuartel de infanterâ”œÂ¡a de San Gregorio. Conforme avanzaban las operaciones militares victoriosas para los fascistas, especialmente tras la Batalla de Teruel y la del Segre (Lâ”œÂ®rida), el volumen de prisioneros "rojos" desbordâ”œâ”‚ la capacidad de este campo. Tras la Batalla del Ebro, la tendencia se agravarâ”œÂ¡a. Es por ello que la cercana fâ”œÃ­brica papelera de "Las Navas", en San Juan de Mozarrifar, serâ”œÂ¡a habilitada como Campo de Concentraciâ”œâ”‚n principal en la zona, hasta mâ”œÃ­s allâ”œÃ­ de la guerra (1943). En la imagen, Prisioneros de guerra republicanos "posando" en el Patio de Armas de la Academia General Militar, donde eran exhibidos para las câ”œÃ­maras de la propaganda, antes de enviarlos al campo de concentraciâ”œâ”‚n. Especialmente buscados por los objetivos eran los voluntarios internacionalistas capturados. Y si eran negros, bingo. Fuente visual: Archivo Josâ”œÂ® F. Demarâ”œÂ¡a Campâ”œâ•‘a. Foto: Josâ”œÂ® Demarâ”œÂ¡a Vâ”œÃ­zquez "Campâ”œâ•‘a".', 1938, 1938, 1938, 'Anos 30', NULL, 41.69932600, -0.87172000, '0101000020E6100000A29C685721E5EBBF0A9FAD8383D94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17070203990.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17070203990.webp', 'https://www.flickr.com/photos/zaragozaantigua/17070203990/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21743, 'AGM 1935', 'Con la llegada de la reformista Segunda Repâ”œâ•‘blica, hubo tambiâ”œÂ®n mudanzas para el gremio militar desde el Ministerio de la Guerra. Asâ”œÂ¡, en junio de 1931 se decreta el cierre de la Academia General Militar de Zaragoza, por motivos econâ”œâ”‚micos, ideolâ”œâ”‚gicos, y polâ”œÂ¡ticos. Desde ese momento, la reivindicaciâ”œâ”‚n de la AGM se convirtiâ”œâ”‚ en una de las seâ”œâ–’as de identidad de las derechas. La imagen se corresponde con uno de los reportajes publicados al objeto de denunciar el estado ruinoso de los edificios que, aunque fueron inaugurados en 1927, "antes de tres meses" estarâ”œÂ¡an hundidos si no se ponâ”œÂ¡a remedio. Tras el golpe de Estado del 18 de julio de 1936, como las instalaciones seguâ”œÂ¡an sorprendentemente en pie, fueron reconvertidas para servir de temporal campo de concentraciâ”œâ”‚n durante unos aâ”œâ–’os. En 1940, el enorme complejo fue reinaugurado oficialmente como AGM, y sometido a sucesivas ampliaciones. En la imagen, aâ”œÂ®rea vista del conjunto de edificios de la AGM, poco antes del supuesto hundimiento, no producido. Fuente: Foto Marâ”œÂ¡n Chivite, "Crâ”œâ”‚nica" (Madrid).', 1935, 1935, 1935, 'Anos 30', NULL, 41.69932600, -0.87172000, '0101000020E6100000A29C685721E5EBBF0A9FAD8383D94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21835033640.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21835033640.webp', 'https://www.flickr.com/photos/zaragozaantigua/21835033640/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21802, 'Aerâ”œâ”‚dromo Sanjurjo 1938', 'Imagen identificada en el aerâ”œâ”‚dromo Sanjurjo de Zaragoza, posiblemente relacionada con el escâ”œÂ®nico ceremonial de despedida a la tripulaciâ”œâ”‚n de un Dornier Do-17 E-1 de la Legiâ”œâ”‚n Câ”œâ”‚ndor caâ”œÂ¡do en combate contra las Fuerzas Aâ”œÂ®reas de la Repâ”œâ•‘blica Espaâ”œâ–’ola. Al fondo, un par de los modernâ”œÂ¡simos bombarderos ligeros Do-17 E-1 que los alemanes denominaban "Fliegender Bleistift" (lâ”œÃ­piz volador) por su alargado fuselaje, y que los espaâ”œâ–’oles redenominaron mâ”œÃ­s castizamente "Bacalao".', 1938, 1938, 1938, 'Anos 30', NULL, 41.66927300, -1.02867100, '0101000020E6100000737FF5B86F75F0BF438CD7BCAAD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26451566078.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26451566078.webp', 'https://www.flickr.com/photos/zaragozaantigua/26451566078/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21832, 'AGM 1937', 'Imagen con el posado de destacados oficiales del Corpo di Truppe Volontarie (CTV) formado por tropas regulares del ejâ”œÂ®rcito italiano, y camisas negras o milicianos del Partido Fascista italiano, enviado por Mussolini a Espaâ”œâ–’a en respaldo de los alzados en armas contra la Repâ”œâ•‘blica democrâ”œÃ­tica. Entre los oficiales, posiblemente se encuentra el general Mario Roatta "Mancini", cuarto de la segunda fila, nombrado por Mussolini jefe de las tropas italianas en Espaâ”œâ–’a en 1936, hasta su relevo tras la derrota en la batalla de Guadalajara (marzo de 1937) por el general Ettore Bastico (a su derecha), que tambiâ”œÂ®n serâ”œÃ­ relevado en octubre de ese aâ”œâ–’o (esta vez tras solicitud expresa de Franco), por el general Mario Berti, el sâ”œÂ®ptimo de la misma fila, hasta su relevo en octubre de 1938 por el general Gastone Gambara. El grupo de oficiales posa delante del pabellâ”œâ”‚n principal que flanquea el ingreso al gran patio central de la AGM (a la izquierda, fuera de plano). Fuente visual: Foto Elâ”œÂ®ctrica (Zaragoza), en www.todocoleccion.net/', 1937, 1937, 1937, 'Anos 30', NULL, 41.69976200, -0.87091200, '0101000020E6100000DB34B6D782DEEBBFE57D1CCD91D94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33365947334.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33365947334.webp', 'https://www.flickr.com/photos/zaragozaantigua/33365947334/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21850, 'Garrapinillos 1935', 'Imagen capturada durante la inauguraciâ”œâ”‚n oficial del reclamado puente de paso sobre el Canal Imperial que conectara directamente el barrio de Garrapinillos con su tâ”œÂ®rmino agrâ”œÂ¡cola, al otro lado del Canal. Este paso se ubicâ”œâ”‚ inmediato a la almenara de La Sagrada y el camino de Bâ”œÃ­rboles, a la izquierda. A la ceremonia acudiâ”œâ”‚ notable representaciâ”œâ”‚n institucional del Ayuntamiento, la DPZ, la Junta del Canal, alcaldes de barrios rurales y juntas de sindicatos de riegos. Fuente visual: www.mecd.gob.es/.', 1935, 1935, 1935, 'Anos 30', NULL, 41.67502600, -1.03376700, '0101000020E6100000CCF10A444F8AF0BF90F9804067D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35707605974.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35707605974.webp', 'https://www.flickr.com/photos/zaragozaantigua/35707605974/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21887, 'Aerâ”œâ”‚dromo Sanjurjo 1939', 'Singular y luminosa imagen correspondiente a la celebraciâ”œâ”‚n en el Aerâ”œâ”‚dromo Sanjurjo del "Dâ”œÂ¡a de la Luftwaffe" el 1 de marzo de ese aâ”œâ–’o, aniversario cuatro de la fundaciâ”œâ”‚n del "Arma Aâ”œÂ®rea" de la Alemania nazi. En primer tâ”œÂ®rmino, autoridades militares espaâ”œâ–’olas, italianas y alemanas saludan a la imponente parada militar compuesta, al fondo, por las tripulaciones y aeronaves de la Legiâ”œâ”‚n Câ”œâ”‚ndor estacionadas en este importante aerâ”œâ”‚dromo, entre las que se distinguen cazas Messerschmitt Bf 109-E y bombarderos Heinkel He 111-E/3. De telâ”œâ”‚n de fondo natural, la sierra de Alcubierre.', 1939, 1939, 1939, 'Anos 30', NULL, 41.66927300, -1.02867100, '0101000020E6100000737FF5B86F75F0BF438CD7BCAAD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49667569022.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49667569022.webp', 'https://www.flickr.com/photos/zaragozaantigua/49667569022/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21910, 'Aerâ”œâ”‚dromo Sanjurjo 1938', 'Entraâ”œâ–’able estampa guerracivilista compuesta a base de bombas de aviaciâ”œâ”‚n, con el inconfundible tono marcial de la Legiâ”œâ”‚n Câ”œâ”‚ndor, para desear a todo el mundo una "Feliz" fiesta del lunes de "Pentecostâ”œÂ®s" desde la base aâ”œÂ®rea de utilizaciâ”œâ”‚n conjunta italo-germano-espaâ”œâ–’ola de Zaragoza. Esta tradicional fiesta cristiana en Alemania celebra el "descenso del Espâ”œÂ¡ritu Santo", de forma que la presencia de las bombas en la foto bien podrâ”œÂ¡a considerarse una "broma" macabra, aunque es probable que los destinatarios de las mismas las recibieran con mâ”œÃ­s terror que broma.', 1938, 1938, 1938, 'Anos 30', NULL, 41.67695000, -1.06696100, '0101000020E610000024B891B24512F1BF7B832F4CA6D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51854911646.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51854911646.webp', 'https://www.flickr.com/photos/zaragozaantigua/51854911646/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21957, 'Esclusas de Valdegurriana 1949', 'Las antiguas "inclusas de Val de Gurriana" (por estar en la val, o barranco, de ese nombre) formaban parte de la inmensa obra civil del Canal Imperial acometida a finales del siglo XVIII con el propâ”œâ”‚sito de proveer de agua suficiente a Zaragoza, y de permitir la navegaciâ”œâ”‚n Cantâ”œÃ­brico-Mediterrâ”œÃ­neo. En este caso, cuatro kilâ”œâ”‚metros aguas abajo de la "Playa de Torrero", y para salvar los 13 metros de acentuado desnivel, sobre un terreno de muy mala calidad, se construyeron cuatro esclusas en piedra sillar maravillosamente tallada, y unas compuertas de paso. Junto a la primera esclusa se levantâ”œâ”‚ la "Casa de Compuertas", o Almenara de San Bernardo, para regular el Contra-Canal y un riego de inmediatos campos de cultivo. Pero esta descomunal obra fue estâ”œÂ®ril en su propâ”œâ”‚sito principal, pues la porosidad del terreno calcâ”œÃ­reo, y las simas, hicieron del todo imposible continuar la obra tal y como estaba diseâ”œâ–’ada. Las siguientes esclusas construidas, las de Torrecilla de Valmadrid, tres kilâ”œâ”‚metros aguas abajo, quedaron asâ”œÂ¡ varadas entre la estepa, sin ver pasar gota de agua. Luego fueron depredadas de sillares, y maltratadas por la desidia, el abandono. En la imagen, aspecto de la enormidad de la voluntad polâ”œÂ¡tica y dineros pâ”œâ•‘blicos que fueron necesarios para levantar las esclusas de Valdegurriana. Toda una joya de la demediada Ilustraciâ”œâ”‚n en Zaragoza, y jalâ”œâ”‚n inexcusable para paseantes del Canal Imperial. Fuente visual: fotografâ”œÂ¡a de Mariano Lacruz Berdejo, amablemente aportada por Mariano Lacruz Pâ”œÂ®rez (Archivo Familia Lacruz Pâ”œÂ®rez).', 1949, 1949, 1949, 'Anos 40', NULL, 41.61116500, -0.85628000, '0101000020E610000011018750A566EBBFDCBA9BA73ACE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20039981196.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20039981196.webp', 'https://www.flickr.com/photos/zaragozaantigua/20039981196/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21997, 'Peâ”œâ–’aflor c.1949', 'Imagen de la calle del Paso del barrio de Peâ”œâ–’aflor de Gâ”œÃ­llego, con buena vista de la mudâ”œÂ®jar torre e iglesia parroquial de Nâ”¬Â¬ Sâ”¬Â¬ del Coro de los â”œÃ¼ngeles, en cuyo lateral figura la correspondiente placa de la memoria histâ”œâ”‚rica en recuerdo de los muertos por Dios y la Espaâ”œâ–’a nacionalista entre 1936 y 1939. Las parcelas de la imagen, hasta la plaza del Rosario, perduran remozadas, y algunas algo recrecidas. Fuente visual: foto Juan Mora Insa, en AHPZ.', 1949, 1949, 1949, 'Anos 40', NULL, 41.76056400, -0.79822000, '0101000020E61000007B6B60AB048BE9BFEA4141295AE14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32600703694.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32600703694.webp', 'https://www.flickr.com/photos/zaragozaantigua/32600703694/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22147, 'Polâ”œÂ¡gono de La Cartuja 1956', 'Dibujo del proyecto ganador en el concurso nacional para la creaciâ”œâ”‚n de un polâ”œÂ¡gono industrial junto a La Cartuja Baja. El emplazamiento fue elegido por disponer de agua (râ”œÂ¡o Ebro y Canal Imperial), carretera y ferrocarril. "Los vientos dominantes alejarâ”œÃ­n de Zaragoza los humos de las factorâ”œÂ¡as y las aguas residuales irâ”œÃ­n al Ebro". Se preveâ”œÂ¡a que fuera la zona industrial mâ”œÃ­s grande de Espaâ”œâ–’a, con una poblaciâ”œâ”‚n total de 60 000 habitantes. En ese entorno se inaugurâ”œâ”‚ en 2006 el polâ”œÂ¡gono Empresarium, algo mâ”œÃ­s modesto. Fuente visual: revista Aragâ”œâ”‚n, SIPA (1956).', 1956, 1956, 1956, 'Anos 50', NULL, 41.60294700, -0.81740800, '0101000020E6100000FDA36FD23428EABF541C075E2DCD4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26595028749.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26595028749.webp', 'https://www.flickr.com/photos/zaragozaantigua/26595028749/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22186, 'Camino de San Antonio c.1955', 'Imagen de la "escuela de primera enseâ”œâ–’anza en Miraflores", sita en el camino de San Antonio, que desde la almenara de San Antonio del Canal Imperial descendâ”œÂ¡a en paralelo al escorredero de la Media Legua, cruzaba el camino de Enmedio, y llegaba hasta la carretera de Castellâ”œâ”‚n. Esta ubicaciâ”œâ”‚n estaba flanqueada por dos lâ”œÂ¡neas ferroviarias: a la izquierda, fuera de plano, la lâ”œÂ¡nea Madrid-Barcelona; a la derecha, la lâ”œÂ¡nea del ferrocarril a Utrillas, con la seâ”œâ–’al del paso a nivel de la caseta "Escorredero". El escorredero de la Media Legua fluye por detrâ”œÃ­s del edificio. Esta escuela tenâ”œÂ¡a su parte para niâ”œâ–’os, y su parte para niâ”œâ–’as, y entre ambas, la capilla. Tras unas pocas dâ”œÂ®cadas de servicio, el edifico perdiâ”œâ”‚ su funciâ”œâ”‚n, y la propiedad recayâ”œâ”‚ en la archidiâ”œâ”‚cesis de Zaragoza, que en 2002 se la vendiâ”œâ”‚ a la Hermandad del Refugio, que la ampliâ”œâ”‚ y convirtiâ”œâ”‚ en la Casa de San Josâ”œÂ®, para acogida de jâ”œâ”‚venes inmigrantes tutelados, entre 2006-2009. Fuente visual: foto Jarke, en www.todocoleccion.net/', 1955, 1955, 1955, 'Anos 50', NULL, 41.62288700, -0.85323000, '0101000020E610000021EA3E00A94DEBBF410DDFC2BACF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32030296225.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32030296225.webp', 'https://www.flickr.com/photos/zaragozaantigua/32030296225/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22196, 'Estaciâ”œâ”‚n Aula Dei c.1950', 'Obras de construcciâ”œâ”‚n de la Estaciâ”œâ”‚n Experimental de Aula Dei, segâ”œâ•‘n proyecto de Teodoro Râ”œÂ¡os Balaguer de 1946. Serâ”œÃ­ inaugurada en 1952, con una sola ala de las dos previstas. Fuente: Historia de la Estaciâ”œâ”‚n Experimental de Aula Dei, 2014.', 1950, 1950, 1950, 'Anos 50', NULL, 41.72462200, -0.81198400, '0101000020E61000002A029CDEC5FBE9BF26FBE769C0DC4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33283269562.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33283269562.webp', 'https://www.flickr.com/photos/zaragozaantigua/33283269562/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22232, 'Coso Medio 1955', 'Imagen capturada en el tramo medio del Coso durante las fiestas del Cincuentenario de la Coronaciâ”œâ”‚n canâ”œâ”‚nica de Nuestra Seâ”œâ–’ora del Pilar (1905), celebradas entre los dâ”œÂ¡as 15 y 22 de mayo de 1955. La escena se centra en el paso de la imagen de la Virgen de Nuestra Seâ”œâ–’ora de Arcos de la localidad bajoaragonesa de Albalate del Arzobispo, participante en la procesiâ”œâ”‚n celebrada el dâ”œÂ¡a 20 de mayo con treinta regionalistas Vâ”œÂ¡rgenes acompaâ”œâ–’adas de las correspondientes autoridades locales, grupos de devotos y devotas venidos desde esos municipios, asâ”œÂ¡ como grupos folklâ”œâ”‚ricos varios (en este caso, de dance), rondallas, bandas de mâ”œâ•‘sica, cornetas y tambores. Ese mismo dâ”œÂ¡a, pero en sesiâ”œâ”‚n matinal, el rector magnâ”œÂ¡fico Juan Cabrera y Felipe consagrâ”œâ”‚ la Universidad de Zaragoza al Inmaculado Corazâ”œâ”‚n de Marâ”œÂ¡a, aâ”œâ–’adiâ”œÂ®ndole de esta forma una excelencia acadâ”œÂ®mica extracurricular, sobrenatural y fantâ”œÃ­stica. A la izquierda, la calle de Eusebio Blasco y la chaflanera esquina del Teatro Principal, sede del selecto I Congreso Nacional de Teatro Catâ”œâ”‚lico, con ponencias y disertaciones acadâ”œÂ®micas, amâ”œÂ®n de varias representaciones escâ”œÂ®nicas del ramo. A la derecha, un "Topolino" en servicio en la tranviaria lâ”œÂ¡nea 13. San Josâ”œÂ®, aguarda pacientemente en el Coso el desarrollo de la procesiâ”œâ”‚n para poder llegar a su terminal en las traseras del Teatro Principal. La magnificencia de estas celebraciones, acompaâ”œâ–’adas de un apacible clima primaveral, fueron el germen del posterior establecimiento de unas anuales Fiestas de Primavera que, siempre vinculadas a la fecha gloriosa de la Coronaciâ”œâ”‚n de la Virgen el 20 de mayo, incluyeron algunos festejos profanos o laicos susceptibles de convertir a Zaragoza en un atractivo destino turâ”œÂ¡stico mundial.', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.65171900, -0.87937800, '0101000020E6100000E84CDA54DD23ECBF469737876BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50050073122.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50050073122.webp', 'https://www.flickr.com/photos/zaragozaantigua/50050073122/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22269, 'Base aâ”œÂ®rea c.1965', 'Base aâ”œÂ®rea de Zaragoza. Fue utilizada por la Fuerza Aâ”œÂ®rea de los Estados Unidos (USAF) desde 1954 hasta 1992, siendo una de las 3 bases aâ”œÂ®reas de la USAF en Espaâ”œâ–’a durante la Guerra Frâ”œÂ¡a, junto a la de Torrejâ”œâ”‚n y a la de Morâ”œâ”‚n. La presencia de militares yanquis en Zaragoza supuso una vâ”œÂ¡a de entrada del rock en el paâ”œÂ¡s. El uso estadounidense del recinto fue contestado por las organizaciones locales de izquierda, organizando marchas anuales hasta su supuesto abandono por parte de USAF.', 1965, 1965, 1965, 'Anos 60', NULL, 41.67288600, -1.06027500, '0101000020E61000002D431CEBE2F6F0BFD7F7E12021D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14864970256.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14864970256.webp', 'https://www.flickr.com/photos/zaragozaantigua/14864970256/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22339, 'Calle Mâ”œÃ­rtires 1968', 'Foto Josâ”œÂ® Antonio Duce, 1968. Calle de los Mâ”œÃ­rtires en el Tubo de Zaragoza, con la plaza de Espaâ”œâ–’a a espaldas del fotâ”œâ”‚grafo. Fuente: www.gozazaragoza.com', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.65250300, -0.88048400, '0101000020E610000028D714C8EC2CECBF5DC5E23785D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20068713651.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20068713651.webp', 'https://www.flickr.com/photos/zaragozaantigua/20068713651/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22453, 'Base Aâ”œÂ®rea 1962', 'Imagen de un aviâ”œâ”‚n de transporte Douglas C-54C "Skymaster" del Mando Estratâ”œÂ®gico de la USAF, estacionado en una pista de la Base Aâ”œÂ®rea de Zaragoza. Este modelo fue el primer aviâ”œâ”‚n de transporte presidencial de la repâ”œâ•‘blica norteamericana (previo al "Air Force One"). En la identificativa torre de control aeroportuaria, visual del oximorâ”œâ”‚nico lema de las instalaciones. Fuente visual: www.usarmygermany.com', 1962, 1962, 1962, 'Anos 60', NULL, 41.67786400, -1.06798100, '0101000020E610000072FDBB3E7316F1BF60915F3FC4D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31605982403.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31605982403.webp', 'https://www.flickr.com/photos/zaragozaantigua/31605982403/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22490, 'Paseo de la Independencia 1964', 'Vista aâ”œÂ®rea del paseo de la Independencia, con el Pilar al fondo. Fuente: Foto TAF. Revista Triunfo.', 1964, 1964, 1964, 'Anos 60', 'CENTRO', 41.65162000, -0.88165200, '0101000020E6100000E97E4E417E36ECBFB3B5BE4868D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46302992465.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46302992465.webp', 'https://www.flickr.com/photos/zaragozaantigua/46302992465/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22494, 'Cartuja de Aula Dei 1968', 'Imagen capturada un soleado dâ”œÂ¡a de invierno en la ajardinada plaza de ingreso a la cartuja de Aula Dei, flanqueada por el edificio de la procura (a la izquierda, fuera de plano), y por el de la hospederâ”œÂ¡a (a la derecha, fuera de plano). Al fondo, la monumental y barroca portada que da acceso a la iglesia. En primer tâ”œÂ®rmino, un hermano lego de la contemplativa Orden fundada por San Bruno, afanado en un trabajo manual entre la hora nona y las vâ”œÂ¡speras de la Santâ”œÂ¡sima Virgen.', 1968, 1968, 1968, 'Anos 60', NULL, 41.73256300, -0.81273000, '0101000020E61000006E4C4F58E201EABF3CA1D79FC4DD4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48213983731.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48213983731.webp', 'https://www.flickr.com/photos/zaragozaantigua/48213983731/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22667, 'Aeropuerto 1971', 'Jardines ante el edificio terminal de pasajeros del aeropuerto de Zaragoza, al fondo, junto a la torre de control y comunicaciones, a la izquierda de la imagen, conjunto diseâ”œâ–’ado por el arquitecto Josâ”œÂ® de Yarza y Garcâ”œÂ¡a. Este campo de aviaciâ”œâ”‚n, situado en el barrio rural de Garrapinillos, en la margen derecha del Canal Imperial de Aragâ”œâ”‚n, fue resultado de la puesta a disposiciâ”œâ”‚n para uso civil del aerâ”œâ”‚dromo Sanjurjo, decidida en 1946 e inaugurada en 1950. En primer tâ”œÂ®rmino, Monumento a la Aeronâ”œÃ­utica, realizado por los alumnos del Centro Politâ”œÂ®cnico Virgen del Pilar como trabajo prâ”œÃ­ctico, en hierro forjado y acero inoxidable. Tras la gran remodelaciâ”œâ”‚n del aeropuerto entre 2006 y 2008, la escultura se halla en paradero incierto, aunque las construcciones preexistentes han sido conservadas. En el lugar de los jardines se extiende un aparcamiento en superficie.', 1971, 1971, 1971, 'Anos 70', NULL, 41.66267300, -1.00702700, '0101000020E61000001C06F357C81CF0BF9A780778D2D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22867497374.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22867497374.webp', 'https://www.flickr.com/photos/zaragozaantigua/22867497374/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22763, 'Las Casetas 1978', 'Imagen del acceso desde Zaragoza al barrio de las Casetas por la carretera nacional 232, con el panorama edilicio y circulatorio de la â”œÂ®poca. El actual mojâ”œâ”‚n que indica esta entrada estâ”œÃ­ retranqueado unos 160 metros hacia el fondo, a la altura del inmediato camiâ”œâ”‚n, resultado de una reordenaciâ”œâ”‚n de fronteras con Utebo tal vez mâ”œÃ­s fiel a los medievales lindes entre estos lugares de la periferia zaragozana. La diferencia es notable, en tâ”œÂ®rminos de movilidad peatonal: desde el nuevo mojâ”œâ”‚n, junto a la calle Austria (Utebo), hoy hay acera. Fuente visual: Banco de Imâ”œÃ­genes/Asociaciâ”œâ”‚n de Vecinos Barrio de San Josâ”œÂ®, amablemente cedida para el', 1978, 1978, 1978, 'Anos 70', NULL, 41.71643000, -1.02342200, '0101000020E6100000501C40BFEF5FF0BFC8EF6DFAB3DB4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33016446562.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33016446562.webp', 'https://www.flickr.com/photos/zaragozaantigua/33016446562/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22836, 'Academia General Militar c.1981', 'Fundada en 1927 por el dictador Miguel Primo de Rivera, es el centro de formaciâ”œâ”‚n superior de todo el ejâ”œÂ®rcito de tierra de Espaâ”œâ–’a. Su primer director fue el luego tambiâ”œÂ®n dictador Francisco Franco. El ministro de Guerra Manuel Azaâ”œâ–’a la cerrâ”œâ”‚ en 1931, pero Franco la reabriâ”œâ”‚ en 1940. Allâ”œÂ¡ han estudiado tanto Juan Carlos de Borbâ”œâ”‚n como su hijo Felipe. La estatua ecuestre que se aprecia en el centro representa a Francisco Franco. Fue donada por el Ayuntamiento de Zaragoza en 1948 y retirada en 2006. El nuevo plan de estudios de 1973 establecâ”œÂ¡a que la AGM pasaba a ser el primer centro de enseâ”œâ–’anza del Ejâ”œÂ®rcito de Tierra. La necesidad de alojar a mâ”œÃ­s tropa hizo insuficiente las capacidades del complejo original. Un nuevo proyecto dispuso, por ello, la construcciâ”œâ”‚n de nuevos inmuebles, en varias fases, que aparecen al fondo de la imagen. En diciembre de 1980 quedâ”œâ”‚ inaugurado el nuevo Servicio de Alimentaciâ”œâ”‚n para tropa, cadetes y mandos, en un gran edificio con la cocina en el centro, rodeada por los comedores, caracterâ”œÂ¡stico por sus porches, a la derecha de la imagen.', 1981, 1981, 1981, 'Anos 80', NULL, 41.69952500, -0.87188200, '0101000020E610000006137F1475E6EBBF01DE02098AD94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14813267099.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14813267099.webp', 'https://www.flickr.com/photos/zaragozaantigua/14813267099/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22886, 'Santa Isabel c.1980', 'El barrio rural de Santa Isabel en una vista aâ”œÂ®rea capturada desde el este y sobrevolando en primer tâ”œÂ®rmino la antigua carretera a Villamayor de Gâ”œÃ­llego, actual avenida del Real Zaragoza. Se mantiene la estructura del barrio vertebrado fundamentalmente en torno a la carretera de Madrid a Francia, actual avenida de Santa Isabel, y con un caserâ”œÂ¡o caracterizado de forma mayoritaria por tradicionales viviendas unifamiliares. Modernos bloques, algunos en proceso de construcciâ”œâ”‚n, como el inmediato a la iglesia parroquial de Santa Isabel de Portugal, empiezan a surgir de forma aislada, de forma mâ”œÃ­s acusada en la zona cercana al puente sobre el râ”œÂ¡o Gâ”œÃ­llego, donde tambiâ”œÂ®n destaca la vertical estampa de la Harinera del barrio. Al fondo, tras el cauce fluvial, la discontinua urbanizaciâ”œâ”‚n de la Margen Izquierda de Zaragoza, desde Vadorrey hasta el Actur. El templo del Pilar emerge a la izquierda mâ”œÃ­s extrema. Fuente: Zaragoza en imâ”œÃ­genes, CAZAR, 1980.', 1980, 1980, 1980, 'Anos 80', NULL, 41.66654500, -0.82485600, '0101000020E61000009C19FD683865EABFFA27B85851D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20074129790.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20074129790.webp', 'https://www.flickr.com/photos/zaragozaantigua/20074129790/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22916, 'Calle Mâ”œÃ­rtires aâ”œâ–’os 80', 'Entrada al Tubo por la calle de los Mâ”œÃ­rtires desde la plaza de Epaâ”œâ–’a. Fuente: dp-foto.blogspot.com', 1980, 1980, 1989, 'Anos 80', 'CENTRO', 41.65224700, -0.88059100, '0101000020E6100000A9DC442DCD2DECBF02F566D47CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25156220105.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25156220105.webp', 'https://www.flickr.com/photos/zaragozaantigua/25156220105/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22942, 'Carretera de Madrid 1983', 'Captura visual realizada durante la ceremonia oficial de colocaciâ”œâ”‚n de la primera piedra del nuevo recinto de la Feria de Muestras de Zaragoza, en la carretera de Madrid, frente a la Venta de los Caballos, el primaveral domingo 10 de abril de ese aâ”œâ–’o. Siguiendo la tradiciâ”œâ”‚n, sobre esa piedra se colocâ”œâ”‚ el hormigonado pilar de la imagen con una inscripciâ”œâ”‚n que reza (sin una coma, ni media): "Aquâ”œÂ¡ se colocâ”œâ”‚ la primera piedra para la nueva Feria Oficial y Nacional de Muestras siendo alcalde de Zaragoza el ilustrâ”œÂ¡simo seâ”œâ–’or don Ramâ”œâ”‚n Sâ”œÃ­inz de Varanda y presidente de la Instituciâ”œâ”‚n y de la Câ”œÃ­mara de Comercio e Industria el ilustrâ”œÂ¡simo seâ”œâ–’or don Josâ”œÂ® Luis Martâ”œÂ¡nez Candial. Abril de 1983." Fuente visual: foto Gerardo Sancho Ramo, en AMZ.', 1983, 1983, 1983, 'Anos 80', NULL, 41.62951200, -0.97865000, '0101000020E6100000705F07CE1951EFBF433866D993D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33251392676.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33251392676.webp', 'https://www.flickr.com/photos/zaragozaantigua/33251392676/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23092, 'Rolling Stones 2003', 'Foto: Josâ”œÂ® Miguel Marco. Lunes 29 de septiembre de 2003, explanada de la Feria de Muestras de Zaragoza. Concierto de The Rolling Stones. En la foto, Mick Jagger. Fuente: www.josemiguelmarco.com/', 2003, 2003, 2003, 'Siglo XXI', NULL, 41.62957000, -0.97837300, '0101000020E6100000D542C9E4D44EEFBF7845F0BF95D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20902392306.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20902392306.webp', 'https://www.flickr.com/photos/zaragozaantigua/20902392306/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23139, 'Cuarto Cinturâ”œâ”‚n 2006', 'Foto: Juan Carlos Arcos. El Cuarto Cinturâ”œâ”‚n de ronda de Zaragoza (Z-40) avanza en sus obras en esta vista aâ”œÂ®rea de 2006. En primer plano, campos del barrio rural de Movera. Al fondo, el râ”œÂ¡o Ebro, a su paso por la huerta de Las Fuentes (arriba a la derecha). Fuente: Heraldo de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', NULL, 41.65728500, -0.84106300, '0101000020E61000004F05DCF3FCE9EABF609335EA21D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31821519421.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31821519421.webp', 'https://www.flickr.com/photos/zaragozaantigua/31821519421/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23145, 'Parque PLAZA 2006', 'Foto: Esther Casas. Estructura de la atalaya del parque lineal de PLAZA (Plataforma Logâ”œÂ¡stica de Zaragoza), durante su construcciâ”œâ”‚n en 2006, junto al Canal Imperial de Aragâ”œâ”‚n. Este gigantesco parque, de cuatro kilâ”œâ”‚metros de largo y 62 hectâ”œÃ­reas, se inaugurâ”œâ”‚ en mayo de 2007. Era la â”œÂ®poca de hacer cosas enormes, sin previsiâ”œâ”‚n de uso alguno y con presupuestos endiablados. Fuente: Heraldo de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', NULL, 41.65404700, -0.98337000, '0101000020E6100000B9C2BB5CC477EFBF0186E5CFB7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31953342436.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31953342436.webp', 'https://www.flickr.com/photos/zaragozaantigua/31953342436/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23147, 'Shakira 2006', 'Foto: Marina Ovejero. La cantante colombiana Shakira fue elegida por la organizaciâ”œâ”‚n de la Expo 2008 para promocionarla dos aâ”œâ–’os antes. Estuvo varios dâ”œÂ¡as en Zaragoza, terminando con un concierto el 14 de junio de 2006 en la Feria de Muestras, que iniciâ”œâ”‚ su gira "Fijaciâ”œâ”‚n oral". Fuente: Heraldo de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', NULL, 41.62951200, -0.97865000, '0101000020E6100000705F07CE1951EFBF433866D993D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31979673695.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31979673695.webp', 'https://www.flickr.com/photos/zaragozaantigua/31979673695/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23182, 'Aeropuerto c.2001', 'Imagen de un aviâ”œâ”‚n de transporte norteamericano modelo Douglas C-47 Skytrain abandonado en el aeropuerto de Zaragoza durante un cuarto de siglo hasta que en 2003 fue desmontado y trasladado al Aeromuseo de Mâ”œÃ­laga, donde fue restaurado con la apariencia de una aeronave de transporte de pasajeros de la compaâ”œâ–’â”œÂ¡a Iberia entre 1955 y 1977. La vida â”œâ•‘til de este aviâ”œâ”‚n comenzâ”œâ”‚ en 1945 en las fuerzas aâ”œÂ®reas norteamericanas, siendo luego cedido al Ejâ”œÂ®rcito del Aire espaâ”œâ–’ol hasta finales de los aâ”œâ–’os 70.', 2001, 2001, 2001, 'Siglo XXI', NULL, 41.66201100, -1.00490500, '0101000020E6100000DC63E9431714F0BFCF4BC5C6BCD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50938298611.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50938298611.webp', 'https://www.flickr.com/photos/zaragozaantigua/50938298611/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23215, 'Riada 2015', 'Foto: Yeresi Arnal. Vista aâ”œÂ®rea de la riada o crecida del Ebro en marzo de 2015. Al fondo, el noroeste de Zaragoza, siguiendo el curso ascendente de la inundaciâ”œâ”‚n, bordeando los montes de El Castellar. Abajo se aprecia el encauzamiento del râ”œÂ¡o a su paso por la ciudad. Fuente: www.soydezaragoza.es', 2015, 2015, 2015, 'Siglo XXI', NULL, 41.69350100, -0.91856000, '0101000020E6100000863DEDF0D764EDBF245F09A4C4D84440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40492042624.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40492042624.webp', 'https://www.flickr.com/photos/zaragozaantigua/40492042624/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23406, 'Ermita de Santa Bâ”œÃ­rbara 1750', 'Tras unas tremendas tormentas con enorme aparato elâ”œÂ®ctrico, fue fundada en 1690 la cofradâ”œÂ¡a de la Gloriosa Santa Bâ”œÃ­rbara, por agricultores de la parroquia de San Pablo temerosos por sus cultivos, y erigieron una ermita en honor a esa Santa en lo alto de uno de los esteparios vales de Valdespartera, sobre terreno poco estable, y con precarios materiales de la zona, de forma que cada poco tiempo eran necesarias reparaciones. El templo es descrito como modesto, de una sola nave y dos altares, uno dedicado a la santa titular, y otro al Santo Cristo. En el tejado, una espadaâ”œâ–’a con "cimbalico" o pequeâ”œâ–’a campana. Ante la puerta de entrada, un "pilâ”œâ”‚n" o "peirâ”œâ”‚n" culminado con una cruz de hierro. Adosada detrâ”œÃ­s estaba la vivienda del ermitaâ”œâ–’o, de dos alturas. Por la notable distancia con la ciudad, su momento culminante era la anual romerâ”œÂ¡a, cada primero de mayo. Asâ”œÂ¡ fue hasta que el reordenamiento parroquial de 1905 dejâ”œâ”‚ a la ermita sin ermitaâ”œâ–’o, ni romerâ”œÂ¡a, y sin las periâ”œâ”‚dicas reparaciones, con lo que el edificio fue entrando en progresiva ruina, y hacia 1946 fue desmantelado lo poco que quedaba. En la imagen, dibujo que recrea esta ermita de Santa Bâ”œÃ­rbara, rodeada de contrafuertes para reforzar su precaria estructura. A la izquierda, la vivienda del ermitaâ”œâ–’o, en el centro, la ermita propiamente dicha, y a la derecha, el "peirâ”œâ”‚n". Al fondo, y abajo, quedarâ”œÂ¡an Valdespartera y Zaragoza. Fuente visual: plenaszaragoza.blogspot.com.es/', 1750, 1750, 1750, 'Siglo XIX', NULL, 41.61564200, -0.94103600, '0101000020E61000001C7A8B87F71CEEBFA305685BCDCE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19499821869.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19499821869.webp', 'https://www.flickr.com/photos/zaragozaantigua/19499821869/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23407, 'Monasterio de Santa Fe 1998', 'Monasterio de Santa Fe de Zaragoza, acuarela de Teodoro Pâ”œÂ®rez Bordetas, 1998. Fuente: www.aragonesasi.com', 1998, 1998, 1998, 'Anos 90', NULL, 41.57758700, -0.94988800, '0101000020E6100000739CDB847B65EEBF21CCED5EEEC94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19575966445.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19575966445.webp', 'https://www.flickr.com/photos/zaragozaantigua/19575966445/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23408, 'Arcosur 2009', 'Vista del terreno explanado para la construcciâ”œâ”‚n de la urbanizaciâ”œâ”‚n Arcosur de Zaragoza, en junio de 2009. Abajo, Valdespartera y Montecanal. Al fondo, la Feria de Muestras y la Plataforma Logâ”œÂ¡stica PLAZA. Este barrio gigante del suroeste de Zaragoza fue defendido en el Ayuntamiento por el alcalde Josâ”œÂ® Atarâ”œÂ®s en 2003, y criticado por Juan Alberto Belloch, en la oposiciâ”œâ”‚n. En 2004, cuando se decidiâ”œâ”‚ que la Expo Zaragoza 2008 se ubicarâ”œÂ¡a en el Meandro de Ranillas, el Ayuntamiento no tenâ”œÂ¡a dinero suficiente para comprar todos esos terrenos. Asâ”œÂ¡ que Ibercaja desembolsâ”œâ”‚ los 70 millones de euros necesarios para la adquisiciâ”œâ”‚n. A cambio, el Ayuntamiento le daba a la entidad financiera el suelo para promover 2.000 viviendas en Arcosur. Fuente: www.arcosur-zaragoza.com/', 2009, 2009, 2009, 'Siglo XXI', NULL, 41.62853100, -0.96130300, '0101000020E6100000787E5182FEC2EEBFD7C22CB473D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19894706096.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19894706096.webp', 'https://www.flickr.com/photos/zaragozaantigua/19894706096/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23411, 'Venta de los Caballos 1999', 'Vista aâ”œÂ®rea del circuito de karts "Kartâ”œâ”‚dromo Aragâ”œâ”‚n", anexo al restaurante Venta de los Caballos, clausurado en 2009. Al fondo, la Feria de Muestras (1986) y su aparcamiento. Estos terrenos, en el km. 311 de la carretera de Madrid (ahora autovâ”œÂ¡a), fueron comprados en 2004 por Plaza (Plataforma Logâ”œÂ¡stica de Zaragoza) por 6,3 millones de euros, para que se hiciera por allâ”œÂ¡ el acceso al centro comercial Plaza Imperial. Cinco aâ”œâ–’os antes fueron tasados en 154.000 euros. Presuntamente, el dueâ”œâ–’o del terreno pagâ”œâ”‚ una comisiâ”œâ”‚n ilegal a los gestores pâ”œâ•‘blicos de 661.000 euros. Fuente: Colecciâ”œâ”‚n particular.', 1999, 1999, 1999, 'Anos 90', NULL, 41.63210600, -0.98665600, '0101000020E6100000A0DE8C9AAF92EFBF7DCD72D9E8D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24112575679.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24112575679.webp', 'https://www.flickr.com/photos/zaragozaantigua/24112575679/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23419, 'R.E.M. 2005', 'Foto: Josâ”œÂ® Miguel Marco. Sâ”œÃ­bado, 28 de mayo de 2005. R.E.M., el grupo estadounidense de rock alternativo (1980-2011), actâ”œâ•‘a en la Feria de Muestras de Zaragoza. En la foto, su cantante, Michael Stipe. Fuente: Heraldo de Aragâ”œâ”‚n.', 2005, 2005, 2005, 'Siglo XXI', NULL, 41.62957000, -0.97837300, '0101000020E6100000D542C9E4D44EEFBF7845F0BF95D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31829092241.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31829092241.webp', 'https://www.flickr.com/photos/zaragozaantigua/31829092241/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23421, 'Recintos feriales 2006', 'Foto: Esther Casas. Aunque en Zaragoza los enclaves que no tienen dos o mâ”œÃ­s denominaciones son poco comunes, la alusiâ”œâ”‚n al "recinto ferial" puede referirse a dos lugares bien distintos: por un lado, los solares donde se asientan los feriantes nâ”œâ”‚madas con sus atracciones y circos; y por otro, los recintos permanentes en los que se celebran las ferias de muestras. En la foto panorâ”œÃ­mica de agosto de 2006, explanaciâ”œâ”‚n de los terrenos del nuevo recinto ferial (de atracciones) de Valdespartera, comenzado a usar en 2007, y al fondo, gracias a la ausencia de construcciones en el barrio de Arcosur, vista hacia el oeste del recinto ferial de la Feria de Muestras, en la confluencia del Cuarto Cinturâ”œâ”‚n con la autovâ”œÂ¡a a Madrid. En todo caso, ferias. Fuente: Heraldo de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', NULL, 41.61920000, -0.93911800, '0101000020E6100000BBB72231410DEEBF73D712F241CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31997418666.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31997418666.webp', 'https://www.flickr.com/photos/zaragozaantigua/31997418666/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23427, 'Monasterio de Santa Fe c.1893', 'Interesante imagen del monasterio cisterciense de Santa Fe de Huerva en un contraste con el despejado entorno y el fondo de los montes de Cuarte. Se trata de una construcciâ”œâ”‚n barroca que data del siglo XVIII y que transformâ”œâ”‚ radicalmente el original convento establecido a mediados del siglo XIV. Destaca su monumental iglesia, construida en formas y escala barroca en el â”œâ•‘ltimo tercio del siglo XVIII, con gran câ”œâ•‘pula sobre el crucero y torre alzada a la diestra de su ingreso principal, y el muro perimetral que delimitaba el conjunto. Abandonado desde la exclaustraciâ”œâ”‚n de 1835, en el momento de realizar esta captura las cubiertas de la iglesia ya aparecen hundidas.', 1893, 1893, 1893, 'Siglo XIX', NULL, 41.57696100, -0.95160400, '0101000020E6100000E3C4573B8A73EEBFA208A9DBD9C94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49060726156.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49060726156.webp', 'https://www.flickr.com/photos/zaragozaantigua/49060726156/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23761, 'Puente Z-40 2007', 'Vista aâ”œÂ®rea de las obras de construcciâ”œâ”‚n del puente del Cuarto Cinturâ”œâ”‚n o autovâ”œÂ¡a de circunvalaciâ”œâ”‚n Z-40 sobre el râ”œÂ¡o Ebro, entre el barrio de Movera (izquierda) y los terrenos entre Las Fuentes y La Cartuja (derecha). Comenzâ”œâ”‚ a construirse en 2005 y se inaugurâ”œâ”‚ en junio de 2008. Fuente visual: Archivo El Periâ”œâ”‚dico de Aragâ”œâ”‚n.', 2007, 2007, 2007, 'Siglo XXI', NULL, 41.63183200, -0.83964000, '0101000020E6100000E73A8DB454DEEABF7C48F8DEDFD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21842420741.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21842420741.webp', 'https://www.flickr.com/photos/zaragozaantigua/21842420741/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23661, 'Jura AGM 1942', 'Imagen capturada por los reporteros grâ”œÃ­ficos alemanes destacados en la decembrina y solemne Jura de Bandera de Caballeros Cadetes en la Academia General Militar, con motivo del retorno de la histâ”œâ”‚rica bandera que en 1886 bordâ”œâ”‚ con sus humanas manos la regente doâ”œâ–’a Marâ”œÂ¡a Cristina, y que tras el cierre de la Academia durante la Segunda Repâ”œâ•‘blica, habâ”œÂ¡a permanecido guardada en una vitrina. El director y fundador de la Academia en su nueva ubicaciâ”œâ”‚n zaragozana, ahora casualmente Caudillo por la gracia de dios, la entregâ”œâ”‚ de nuevo a su entonces director, el general Hidalgo de Cisneros, en una ceremonia con inaudita pasarela de las autoridades polâ”œÂ¡ticas del momento (militares, religiosas, civiles, y jerarquâ”œÂ¡as del Movimiento). Mientras, en un lejano recodo de la estepa euroasiâ”œÃ­tica junto al râ”œÂ¡o Volga, ruge la descomunal batalla que pondrâ”œÃ­ patas arriba la guerra en la que Espaâ”œâ–’a era formalmente "no beligerante", aunque con simpatâ”œÂ¡as algo mâ”œÃ­s que fuertes hacia el amigo Eje Roma-Berlâ”œÂ¡n-Tokio. Mientras, en el cercano San Juan de Mozarrifar, junto al Gâ”œÃ­llego, seguâ”œÂ¡a funcionando, como desde 1938, el campo de concentraciâ”œâ”‚n para prisioneros de guerra allâ”œÂ¡ habilitado, donde la antigua fâ”œÃ­brica papelera de "Las Navas". Fuente visual: Berliner Verlag Archiv (Agencia EFE)', 1942, 1942, 1942, 'Anos 40', NULL, 41.69932600, -0.87172000, '0101000020E6100000A29C685721E5EBBF0A9FAD8383D94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24667332695.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24667332695.webp', 'https://www.flickr.com/photos/zaragozaantigua/24667332695/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23663, 'Aerâ”œâ”‚dromo Sanjurjo 1939', 'Imagen del Sturzkampfflugzeug (bombardero en picado) Junkers Ju-87 de la serie B-1 ("Bertha") durante una parada militar realizada en el aerâ”œâ”‚dromo Sanjurjo de Zaragoza. Matriculado con la referencia "29-11" este fue uno de los cinco aparatos de la novâ”œÂ¡sima serie "Bertha" que de este moderno aeroplano de guerra fueron incorporados por los alemanes a la Legiâ”œâ”‚n Câ”œâ”‚ndor para combatir contra la Repâ”œâ•‘blica Espaâ”œâ–’ola desde finales del aâ”œâ–’o 1938 en escenarios bâ”œÂ®licos de Lâ”œÂ®rida, Barcelona, Tarragona y Valencia. Dibujado en el carenado tren de aterrizaje izquierdo destaca el dibujo de la rosada cerdita "Jolanthe", mamâ”œÂ¡fero artiodâ”œÃ­ctilo cuyo personaje daba tâ”œÂ¡tulo a la popular pelâ”œÂ¡cula alemana del gâ”œÂ®nero comedia româ”œÃ­ntica titulada "Krach um Jolanthe" (Problemas con Jolanthe), que ademâ”œÃ­s prestâ”œâ”‚ su nombre a una de las primeras "Kette" (formaciâ”œâ”‚n de combate compuesta por tres aviones) de Stukas operativas en combate real sobre cielos espaâ”œâ–’oles: la Kette Jolanthe. Al fondo, en formaciâ”œâ”‚n de revista, algunos de los "Pedros" o bombarderos Heinkel He-111 B-1 que operaban desde esta plurinacionalista base aâ”œÂ®rea. Fuente visual: elhangardetj.blogspot.com.es/', 1939, 1939, 1939, 'Anos 30', NULL, 41.66927300, -1.02867100, '0101000020E6100000737FF5B86F75F0BF438CD7BCAAD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26442014858.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26442014858.webp', 'https://www.flickr.com/photos/zaragozaantigua/26442014858/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23667, 'Carretera de Huesca 1938', 'Imagen capturada por un soldado alemâ”œÃ­n de la Legiâ”œâ”‚n Câ”œâ”‚ndor destinado a la base aâ”œÂ®rea de Sanjurjo, en el militarizado puesto de control instalado en la carretera de Huesca, unos 200 metros despuâ”œÂ®s del acceso principal a la Academia General Militar, junto a la estaciâ”œâ”‚n transformadora de Elâ”œÂ®ctricas Reunidas de Zaragoza S.A. allâ”œÂ¡ ubicada. Entre la dotaciâ”œâ”‚n que custodia este puesto, una pareja de la Guardia Civil, y miembros de Acciâ”œâ”‚n Ciudadana de Zaragoza. Mientras la barrera permanece bajada, un convoy en direcciâ”œâ”‚n a Zaragoza pasando inspecciâ”œâ”‚n. Fuente: www.todocoleccion.net/', 1938, 1938, 1938, 'Anos 30', NULL, 41.70165300, -0.86758600, '0101000020E610000066F50EB743C3EBBFF511F8C3CFD94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30946046941.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30946046941.webp', 'https://www.flickr.com/photos/zaragozaantigua/30946046941/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23671, 'Aerâ”œâ”‚dromo Sanjurjo 1937', 'Imagen capturada desde la altura de un bombardero alemâ”œÃ­n Heinkel-111 B-1 durante la maniobra de aterrizaje en el aerâ”œâ”‚dromo zaragozano de Sanjurjo. Sobre las pistas posan al menos otros quince "Pedros", denominaciâ”œâ”‚n indâ”œÂ¡gena de este moderno modelo aeronaâ”œâ•‘tico que, en nâ”œâ•‘mero de 100, formâ”œâ”‚ parte del contingente de la Legiâ”œâ”‚n Câ”œâ”‚ndor llegado como solidaridad militar desde el III Reich con los nacionalistas sublevados contra la Repâ”œâ•‘blica. En uno de los aparatos se visualiza el sâ”œÂ¡mbolo de identificaciâ”œâ”‚n pintado en lugar de la reglamentaria esvâ”œÃ­stica. Fuente visual: "Condor: The Luftwaffe in Spain, 1936-39".', 1937, 1937, 1937, 'Anos 30', NULL, 41.66303700, -1.02413100, '0101000020E6100000CD1DFD2FD762F0BFDC847B65DED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32091312901.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32091312901.webp', 'https://www.flickr.com/photos/zaragozaantigua/32091312901/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23675, 'Aerâ”œâ”‚dromo Sanjurjo 1938', 'Posado del contingente radicado en el zaragozano aerâ”œâ”‚dromo de Sanjurjo de la "Aviazione Legionaria", o unidades de la Regia Aeronautica italiana enviadas por Mussolini en agosto de 1936 en apoyo de los nacionalistas sublevados en armas contra la Repâ”œâ•‘blica democrâ”œÃ­tica. Al fondo, aviones de caza italianos CR-20 y CR-32 "Freccia/Chirri". Unas semanas despuâ”œÂ®s, sus camaradas destinados en la base aâ”œÂ®rea de Logroâ”œâ–’o volaron por la ruta de la carretera de Zaragoza, en aparatos Savoia-Marchetti S-79 hasta la localidad bajoaragonesa de Alcaâ”œâ–’iz, y la arrasaron, tal que diez meses y una semana antes habâ”œÂ¡a sucedido con Gernika. Mâ”œÃ­s adelante, este tipo de acciones serâ”œÃ­n consideradas "bombardeos terroristas". Fuente visual: revista "Vida Aragonesa".', 1938, 1938, 1938, 'Anos 30', NULL, 41.66927300, -1.02867100, '0101000020E6100000737FF5B86F75F0BF438CD7BCAAD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34415745475.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34415745475.webp', 'https://www.flickr.com/photos/zaragozaantigua/34415745475/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23677, 'Ctra. de Huesca 1928', 'Imagen capturada durante la construcciâ”œâ”‚n de uno de los pabellones principales de la Academia General Militar junto a la carretera de Huesca, proyectada por los ingenieros militares Mariano Lafiguera, Vicente Rodrâ”œÂ¡guez y Antonio Parelladas en formas historicistas y neomudâ”œÂ®jares. Fuente visual: Academia General Militar. 90 aâ”œâ–’os de presencia en Zaragoza, Luis Alfonso Arcarazo Garcâ”œÂ¡a, IFC, 2017.', 1928, 1928, 1928, 'Anos 20', NULL, 41.69949300, -0.87190200, '0101000020E6100000CC24EA059FE6EBBFF56393FC88D94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37697787465.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37697787465.webp', 'https://www.flickr.com/photos/zaragozaantigua/37697787465/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23682, 'Ctra. de Huesca 1930', 'Imagen capturada desde la carretera de Zaragoza a Huesca y centrada en la gran fachada principal de la Academia General Militar, inaugurada hacâ”œÂ¡a poco con diseâ”œâ–’o de los ingenieros militares Mariano Lafiguera, Vicente Rodrâ”œÂ¡guez y Antonio Parelladas. Esta fachada presenta una llamativa alternancia de edificios de tres alturas con torreones de cuatro y cinco pisos, estos â”œâ•‘ltimos flanqueando el ingreso al Patio de Armas. A la derecha, bloque de alojamientos con capacidad para 400 efectivos de tropa y 250 caballerâ”œÂ¡as. Justo antes del ingreso, incipientes jardines de la Reina Marâ”œÂ¡a Cristina.', 1930, 1930, 1930, 'Anos 30', NULL, 41.69915200, -0.87137400, '0101000020E6100000E5B512BA4BE2EBBF6C770FD07DD94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48195809011.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48195809011.webp', 'https://www.flickr.com/photos/zaragozaantigua/48195809011/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24096, 'Maginot y Franco 1930', 'Imagen capturada en el patio central de la Academia General Militar y centrada en la presencia de altura del ministro de la guerra de Francia, general Andrâ”œÂ® Maginot. Junto a â”œÂ®l, el director de la instituciâ”œâ”‚n, general Francisco Franco Bahamonde. Ademâ”œÃ­s, y entre otros, el capitâ”œÃ­n general de la regiâ”œâ”‚n militar, Jorge Fernâ”œÃ­ndez de Heredia; el gobernador civil, Juan Dâ”œÂ¡az Caneja; el gobernador militar, general de divisiâ”œâ”‚n Agustâ”œÂ¡n Gâ”œâ”‚mez Morato. El batallâ”œâ”‚n de cadetes de la academia, con su bandera, mâ”œâ•‘sica y banda de cornetas, rindiâ”œâ”‚ honores a Maginot interpretando la Marsellesa. Tras el preceptivo desfile de tropas, visitâ”œâ”‚ las instalaciones de la academia, terminando en un almuerzo trufado de discursos oficiales, culminado con la imposiciâ”œâ”‚n al director de las insignias de comendador de la Legiâ”œâ”‚n de Honor por sus mâ”œÂ®ritos en el desembarco de Alhucemas (1925). Finalmente, saludâ”œâ”‚ a los representantes de la colonia francesa en la ciudad y visitâ”œâ”‚ a continuaciâ”œâ”‚n el templo del Pilar antes de regresar a Francia por la carretera de Navarra. Este ministro, fallecido en 1932, ha pasado a la historia por impulsar el proyecto de construcciâ”œâ”‚n de una lâ”œÂ¡nea estâ”œÃ­tica de fortificaciones en la frontera con Alemania que, denominada "Lâ”œÂ¡nea Maginot", fue rebasada sin demasiados problemas por el ejâ”œÂ®rcito de la Alemania nazi en 1940.', 1930, 1930, 1930, 'Anos 30', NULL, 41.69915200, -0.87137400, '0101000020E6100000E5B512BA4BE2EBBF6C770FD07DD94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49881848736.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49881848736.webp', 'https://www.flickr.com/photos/zaragozaantigua/49881848736/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24099, 'Ctra. de Pastriz 1959', 'Imagen de la procesiâ”œâ”‚n que desde el barrio rural de Movera se encamina por la carretera del Puente de Santa Isabel a Pastriz para llegar hasta la Torre de Santa Engracia. La fotografâ”œÂ¡a se centra en la cabecera de la procesiâ”œâ”‚n, con el Santo Cristo al frente, tallado por el escultor villalenguino Genaro Lâ”œÃ­zaro Gumiel, y la prâ”œÃ­ctica totalidad de los lugareâ”œâ–’os detrâ”œÃ­s. Hacia el fondo, volquete habilitado como carroza donde la imagen de Nuestra Seâ”œâ–’ora de Movera es transportada junto con niâ”œâ–’as y niâ”œâ–’os en trâ”œÃ­nsito hacia su Primera Comuniâ”œâ”‚n. Esta imagen se ha capturado a la altura, a la derecha, del actual inmueble del nâ”¬â•‘ 473 de la avenida de Movera que, junto con las inmediatas parcelas gemelas de los nâ”œâ•‘meros 469 y 471 perduran, si bien algo remodeladas.', 1959, 1959, 1959, 'Anos 50', NULL, 41.64796700, -0.81996200, '0101000020E6100000DDCEBEF2203DEABF91F12895F0D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50769637908.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50769637908.webp', 'https://www.flickr.com/photos/zaragozaantigua/50769637908/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
