INSERT INTO public.photos VALUES (24380, 'Hermanas de Santa Ana 1978', 'Casa de Espiritualidad del Sagrado Corazâ”œâ”‚n de las Hermanas de la Caridad de Santa Ana, en el barrio rural de Garrapinillos de Zaragoza, en 1978. La comunidad religiosa se instala en este lugar en 1896, aunque es en 1973 cuando se construye el edificio actual, destinado a ejercicios espirituales. Pese a que los ejercicios espirituales provocan agujetas mentales, esta actividad perdura hasta nuestros dâ”œÂ¡as. Fuente: www.facebook.com/groups/fotosantiguasdezaragoza/permalink...', 1978, 1978, 1978, 'Anos 70', NULL, 41.67226000, -0.96560300, '0101000020E6100000726C3D4338E6EEBF59349D9D0CD64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21287227072.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21287227072.webp', 'https://www.flickr.com/photos/zaragozaantigua/21287227072/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24359, 'Cariâ”œâ–’ena en Santa Fe 1934', '1934. Automotor diesel tipo "Zaragoza", construido bajo licencia de la alemana "Waggonfabrik Wismar" por Material Mâ”œâ”‚vil y Construcciones (Zaragoza), en un viaje de prueba por la lâ”œÂ¡nea de ferrocarril de Cariâ”œâ–’ena. La imagen estâ”œÃ­ tomada en el apeadero de Santa Fe, lo que permite una vista, al fondo, del impresionante real monasterio cisterciense de Santa Marâ”œÂ¡a de Santa Fe (siglo XIV), tal y como lo dejâ”œâ”‚ la profunda reforma barroca del siglo XVIII, las circunstancias histâ”œâ”‚ricas, y estar en manos privadas desde hacâ”œÂ¡a casi un siglo. Actualmente, la iglesia y la porterâ”œÂ¡a han sido declaradas Monumento Histâ”œâ”‚rico Artâ”œÂ¡stico (1979), y tienen categorâ”œÂ¡a de BIC, pero sâ”œâ”‚lo el horno y las celdas se han recuperado como viviendas. El resto de edificios permanecen en ruinas.', 1934, 1934, 1934, 'Anos 30', NULL, 41.57936900, -0.95905000, '0101000020E6100000545227A089B0EEBF7AA86DC328CA4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14996842871.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14996842871.webp', 'https://www.flickr.com/photos/zaragozaantigua/14996842871/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24410, 'Peâ”œâ–’aflor c.1976', 'Festejos populares en el barrio rural de Peâ”œâ–’aflor de Gâ”œÃ­llego, con suelta de vacas. A la izquierda, iglesia y torre mudâ”œÂ®jar de Nuestra Seâ”œâ–’ora del Coro de Los â”œÃ¼ngeles. Fuente: Heraldo de Aragâ”œâ”‚n.', 1976, 1976, 1976, 'Anos 70', NULL, 41.76056400, -0.79822000, '0101000020E61000007B6B60AB048BE9BFEA4141295AE14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32302492744.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32302492744.webp', 'https://www.flickr.com/photos/zaragozaantigua/32302492744/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24427, 'Peâ”œâ–’aflor 1999', 'Iglesia parroquial de Nuestra Seâ”œâ–’ora de los â”œÃ¼ngeles, ubicada en la plaza del Rosario del barrio rural de Peâ”œâ–’aflor de Gâ”œÃ­llego. Fue levantada en el siglo XVI en estilo mudâ”œÂ®jar. En el momento de tomar la imagen, el edificio se hallaba en obras de restauraciâ”œâ”‚n, que se prolongaron hasta 2002, dejando a la vista el piso inferior de la torre, oculto hasta entonces por construcciones anexas. En el lateral derecho, placa franquista rememorando a los Ã”Ã‡Â£Caâ”œÂ¡dos por Dios y por Espaâ”œâ–’aÃ”Ã‡Ã˜, finalmente retirada dos dâ”œÂ®cadas despuâ”œÂ®s.', 1999, 1999, 1999, 'Anos 90', NULL, 41.76061100, -0.79842900, '0101000020E61000000CB265F9BA8CE9BF2AFD84B35BE14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50199374651.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50199374651.webp', 'https://www.flickr.com/photos/zaragozaantigua/50199374651/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24437, 'Harinas Polo 1963', 'AHPZ-Archivo Coyne, Manuel Coyne, 1959-1965. La referencia a esta imagen es "Casa", que se corresponde con la nueva fâ”œÃ­brica de Harinas Polo, sita en las inmediaciones de Villanueva de Gâ”œÃ­llego, tras abandonar sus instalaciones en el Camino de las Torres.', 1963, 1963, 1963, 'Anos 60', NULL, 41.76316500, -0.81836300, '0101000020E6100000D234289A0730EABFD6390664AFE14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14863214716.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14863214716.webp', 'https://www.flickr.com/photos/zaragozaantigua/14863214716/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24899, 'Universidad Laboral 1968', 'Vista aâ”œÂ®rea de la Universidad Laboral Femenina en el barrio de Santa Isabel, inaugurada en 1967. Al fondo, el Polâ”œÂ¡gono de Malpica. A la derecha, la carretera de Barcelona. A la izquierda, la autopista a Barcelona. Era como una pequeâ”œâ–’a ciudad, con sus propio nomenclâ”œÃ­tor (calles del Rector, Larga, Corta, de los Deportes, Mayor), sala de cine, cafeterâ”œÂ¡a, aulas y polideportivo. Las edificaciones eran pabellones conectados por pasillos cubiertos. Sus 65.000 m2 edificados comprendâ”œÂ¡an: piscina cubierta climatizada (la primera que se construyâ”œâ”‚ en Zaragoza) con grada de 400 espectadores; biblioteca para 200 lectores; tres salones de actos, el principal, con capacidad para 1400 espectadores sentados, un escenario dos veces superior en superficie al del Teatro Principal de Zaragoza; medios audiovisuales capaces de efectuar grabaciones televisivas; cancha polideportiva con suelo de parquet, con grada de 400 espectadores; laboratorios de fâ”œÂ¡sica, quâ”œÂ¡mica, ciencias naturales y de idiomas; nave-taller con maquinaria de confecciâ”œâ”‚n industrial (â”œâ•‘nica en Aragâ”œâ”‚n); tres residencias de alumnos/as, apartamentos para profesorado y viviendas para personal de servicios, con mâ”œÃ­s de 400 habitaciones equipadas (edificios de 12 plantas); servicios mâ”œÂ®dicos y enfermerâ”œÂ¡a con mâ”œÃ­s de 30 camas; aulas para mâ”œÃ­s de 2.000 alumnos; comedores y cocina; cafeterâ”œÂ¡a, capilla catâ”œâ”‚lica, oficinas... En el exterior: estadio de atletismo en todas sus modalidades, campo de fâ”œâ•‘tbol en câ”œÂ®sped; pistas de tenis, baloncesto, balonmano, voleibol, etc.', 1968, 1968, 1968, 'Anos 60', NULL, 41.65257700, -0.79263500, '0101000020E61000005A475513445DE9BF978FA4A487D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15268429446.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15268429446.webp', 'https://