INSERT INTO public.photos VALUES (25082, 'AGM 1955', 'Jura de bandera del prâ”œÂ¡ncipe Juan Carlos de Borbâ”œâ”‚n en la Academia General Militar (el primero de la fila, junto al cura), en diciembre de 1955. 25 aâ”œâ–’os despuâ”œÂ®s, ya rey, renovarâ”œÃ­ su juramento, a los cinco dâ”œÂ¡as del golpe de Estado fallido de 1981. Fuente: "Historia de la Academia General Militar".', 1955, 1955, 1955, 'Anos 50', NULL, 41.69949300, -0.87190200, '0101000020E6100000CC24EA059FE6EBBFF56393FC88D94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30110442278.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30110442278.webp', 'https://www.flickr.com/photos/zaragozaantigua/30110442278/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25084, 'Feria de Muestras 1989', 'Imagen capturada durante la oficial inauguraciâ”œâ”‚n de la 49â”¬Â¬ ediciâ”œâ”‚n de la Feria de Muestras de Zaragoza, en octubre de ese aâ”œâ–’o, en las recientes instalaciones de la carretera nacional II, Madrid-Zaragoza-Barcelona. En ella se nos muestran, de izquierda a derecha, el brazo izquierdo de Pascual Marco Sebastiâ”œÃ­n (PSOE), vicepresidente de la DPZ; junto a â”œÂ®l, Josâ”œÂ® Luis Martâ”œÂ¡nez Candial, presidente de Ibercaja (hasta 1988, Caja de Ahorros y Monte de Piedad de Zaragoza, Aragâ”œâ”‚n y Rioja), y de la Câ”œÃ­mara de Comercio e Industria de Zaragoza; Hipâ”œâ”‚lito Gâ”œâ”‚mez de las Roces (PAR), presidente de la DGA; tras â”œÂ®l, Santiago Lanzuela; a su lado, Carlos Pâ”œÂ®rez Anadâ”œâ”‚n (PSOE), delegado del Gobierno en Aragâ”œâ”‚n y gobernador Civil; Juan Bautista Monserrat Mesanza (CDS), presidente de las Cortes de Aragâ”œâ”‚n; Antonio Gonzâ”œÃ­lez Triviâ”œâ–’o (PSOE), alcalde de Zaragoza; Luis Acâ”œÂ¡n Boned (PAR), consejero de Industria, Comercio y Turismo de la DGA; y Luis Garcâ”œÂ¡a Nieto (PSOE), primer teniente de Alcalde y concejal de Urbanismo del ayuntamiento de Zaragoza. Fuente visual: Antonio Calvo Pedrâ”œâ”‚s, AMZ.', 1989, 1989, 1989, 'Anos 80', NULL, 41.62957000, -0.97837300, '0101000020E6100000D542C9E4D44EEFBF7845F0BF95D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30751700766.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30751700766.webp', 'https://www.flickr.com/photos/zaragozaantigua/30751700766/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25086, 'Base Aâ”œÂ®rea 1963', 'Simpâ”œÃ­tica imagen del alcalde Luis Gâ”œâ”‚mez Laguna encasquetâ”œÃ­ndose un casco de piloto en la Base Aâ”œÂ®rea donde desde 1958 estaba radicada la Fuerza Aâ”œÂ®rea de los Estados Unidos (de Norteamâ”œÂ®rica). Le ayuda en las labores un sargento tâ”œÂ®cnico forano antes de subirse, posiblemente, a uno de los reactores "F-102A Delta Dagger" del "431st Test and Evaluation Squadron" (los "Red Devils", o "Demonios Rojos"), cazas interceptores de la primera lâ”œÂ¡nea de defensa ante las flotas de bombarderos nucleares soviâ”œÂ®ticos que amenazaban la civilizaciâ”œâ”‚n occidental y el modo de vida norteamericano. Poco despuâ”œÂ®s, Stanley Kubrick dirigirâ”œÂ¡a el sensato delirio "Dr. Strangelove, or How I Learned to Stop Worrying and Love the Bomb". Tal vez Luis Gâ”œâ”‚mez Laguna compartiera durante su visita de la imagen alguna anâ”œÂ®cdota de cuando, a finales de los aâ”œâ–’os 30, hizo de traductor para la germana Legiâ”œâ”‚n Câ”œâ”‚ndor establecida en esos mismos pagos. O no. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1963, 1963, 1963, 'Anos 60', NULL, 41.67786400, -1.06798100, '0101000020E610000072FDBB3E7316F1BF60915F3FC4D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31596163733.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31596163733.webp', 'https://www.flickr.com/photos/zaragozaantigua/31596163733/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25170, 'Estaciâ”œâ”‚n Aula Dei 1946', '"Estaciâ”œâ”‚n de biologâ”œÂ¡a experimental de Cogullada. Aspecto general". Teodoro Râ”œÂ¡os Balaguer, 1946. Dibujo del proyecto de edificios para la Estaciâ”œâ”‚n Experimental creada en 1944 en Cogullada, que se trasladarâ”œÃ­ junto a la Cartuja de Aula Dei en 1952. Pese a conservar en el proyecto su denominaciâ”œâ”‚n hasta 1948, el grâ”œÃ­fico representa los terrenos de la avenida de Montaâ”œâ–’ana, en Peâ”œâ–’aflor. Fuente: Historia de la Estaciâ”œâ”‚n Experimental de Aula Dei, 2014.', 1946, 1946, 1946, 'Anos 40', NULL, 41.72462200, -0.81198400, '0101000020E61000002A029CDEC5FBE9BF26FBE769C0DC4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33055338430.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33055338430.webp', 'https://www.flickr.com/photos/zaragozaantigua/33055338430/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25196, 'Cartuja de N.â”¬Â¬ S.â”¬Â¬ de Aula Dei 1852', 'Dibujo de la planta, cortes y alzados de la Cartuja de Nuestra Seâ”œâ–’ora de Aula Dei trazados por Miguel Blasco. Segâ”œâ•‘n la disposiciâ”œâ”‚n de la planta, el norte quedarâ”œÂ¡a a la derecha. En 1564 se habâ”œÂ¡a puesto la primera piedra del conjunto, inmediato al camino de Peâ”œâ–’aflor de Gâ”œÃ­llego, en el tâ”œÂ®rmino de El Regado. En 1835 el inmueble habâ”œÂ¡a sido desamortizado, y dos aâ”œâ–’os despuâ”œÂ®s pertenecâ”œÂ¡a a Juan Francisco Clarac, que destinâ”œâ”‚ el recinto a fâ”œÃ­brica de sedas. Durante el resto del siglo XIX cambiâ”œâ”‚ de propietario varias veces. Fuente visual: Cartuja de N.â”¬Â¬ S.â”¬Â¬ de Aula Dei, AHPZ.', 1852, 1852, 1852, 'Siglo XIX', NULL, 41.73175800, -0.81231000, '0101000020E61000001FD7868A71FEE9BF0E4B033FAADD4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27386739158.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27386739158.webp', 'https://www.flickr.com/photos/zaragozaantigua/27386739158/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25539, 'Galacho de Juslibol 2012', 'Foto: Josâ”œÂ® Marâ”œÂ¡a Ballestâ”œÂ¡n, 2012. Vista del galacho de Juslibol, meandro abandonado por el râ”œÂ¡o Ebro en la crecida del 2 de enero de 1961. Fuente: peripaseos.wordpress.com/2012/04/13/montes-de-juslibol/', 2012, 2012, 2012, 'Siglo XXI', NULL, 41.70572300, -0.92852000, '0101000020E61000004AD235936FB6EDBF7B849A2155DA4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19295487273.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19295487273.webp', 'https://www.flickr.com/photos/zaragozaantigua/19295487273/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25600, 'Romareda 1956', 'Construcciâ”œâ”‚n del campo de fâ”œâ•‘tbol de La Romareda. Al fondo, la Feria de Muestras. Fuente. www.facebook.com/photo.php?fbid=785150371544327&set=o...', 1956, 1956, 1956, 'Anos 50', 'UNIVERSIDAD', 41.63645000, -0.90176200, '0101000020E610000052D158FB3BDBECBF05C58F3177D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15020542974.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15020542974.webp', 'https://www.flickr.com/photos/zaragozaantigua/15020542974/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21484, 'Cardenal Soldevila 1926', '1926. Gerardo Alcaâ”œâ–’iz. "Mausoleo del Cardenal Soldevila". El cuatro de junio de 1923, el coche del Cardenal Soldevila, matrâ”œÂ¡cula Z-135, se detuvo frente a la reja de la escuela-asilo de las hermanas de San Vicente de Paâ”œâ•‘l en la calle Terminillo. El cardenal habâ”œÂ¡a fundado la instituciâ”œâ”‚n, y era su principal valedor. Todas las tardes repetâ”œÂ¡a la misma rutina, segâ”œâ•‘n voces porque mantenâ”œÂ¡a una relaciâ”œâ”‚n con una de las monjas, a la que legâ”œâ”‚ parte de su fortuna, lo que ella aprovechâ”œâ”‚ para volver al estado civil. Mientras esperaba para entrar, Ã”Ã‡Â£Los SolidariosÃ”Ã‡Ã˜ Francisco Ascaso y Rafael Liberato se plantaron junto al coche y vaciaron sus armas. El châ”œâ”‚fer y el mayordomo resultaron heridos, el cardenal muriâ”œâ”‚ en el acto. Si para la gente de orden el cardenal Soldevila era merecedor de todos los honores (Senador Vitalicio, Gran Cruz de Isabel la Catâ”œâ”‚lica, Hijo Adoptivo de Zaragoza...), para los medios obreros de la ciudad su figura se identificaba directamente con la corrupciâ”œâ”‚n y el terrorismo patronal y de Estado, en los convulsos aâ”œâ–’os 20. Tras su asesinato, el cardenal Soldevila fue enterrado en el Pilar, enfrente de la capilla de la Virgen. La escuela-asilo de las hermanas paulas sigue en la calle "La Milagrosa", a pocos metros del Hospital Clâ”œÂ¡nico Universitario. Desde entonces, en el patio del recreo el monolito de la foto seâ”œâ–’alaba el lugar del atentado hasta 2024, cuando fue trasladado al patio del Cedro del palacio Arzobispal. Zaragoza perdiâ”œâ”‚ a su cardenal y nunca lo ha vuelto a recuperar. En la imagen, el monumento al cardenal Soldevila en el lugar de autos. Los que sonrâ”œÂ¡en son sospechosos.', 1926, 1926, 1926, 'Anos 20', 'UNIVERSIDAD', 41.64452000, -0.90479400, '0101000020E6100000A9BEF38B12F4ECBF18CFA0A17FD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14974761721.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14974761721.webp', 'https://www.flickr.com/photos/zaragozaantigua/14974761721/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21535, 'Dictador y alcalde 1929', 'El dictador Miguel Primo de Rivera y el alcalde de Zaragoza, Miguel Alluâ”œÂ® Salvador (1927-1929), en la inauguraciâ”œâ”‚n del parque Primo de Rivera, el 17 de mayo de 1929. Fuente: Eloy Fernâ”œÃ­ndez Clemente, "Gente de orden", Ibercaja, 1995.', 1929, 1929, 1929, 'Anos 20', 'UNIVERSIDAD', 41.63714200, -0.89751100, '0101000020E6100000B29B19FD68B8ECBF3A747ADE8DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19527938614.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19527938614.webp', 'https://www.flickr.com/photos/zaragozaantigua/19527938614/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21805, 'Cementerio Terminillo 1935', 'El cementerio de Terminillo, Miralbueno, o de la Casa Blanca, fue un temporal camposanto de efâ”œÂ¡mera vida prâ”œÃ­ctica (1864-1866), producto de la reacciâ”œâ”‚n del crecido clericalismo polâ”œÂ¡tico tras el Concordato de 1851. Fue concebido como cementerio 100% parroquial, para arrebatar al ayuntamiento la gestiâ”œâ”‚n del negocio de la muerte, y privatizarla en beneficio propio. En esta aventura se embarcaron 13 de las 15 parroquias de la ciudad. Este cementerio fue ubicado en una irracional localizaciâ”œâ”‚n al suroeste de la ciudad, en el Tâ”œÂ®rmino de Miralbueno, partida del Viâ”œâ–’edo Viejo, entre el camino de la Mosquetera, un brazal de riego del Canal Imperial denominado "de la Cabra", y el camino hacia el puente de Medio. En los poco mâ”œÃ­s de dos aâ”œâ–’os de funcionamiento, casi 3.500 restos humanos fueron allâ”œÂ¡ depositados, entre nichos y enterramientos. Tras su clausura, los restos fueron exhumados y llevados al municipal cementerio de Torrero, y el terreno quedâ”œâ”‚ sin uso. En 1914 fue vendido en pâ”œâ•‘blica subasta, por un montante de 19.211,50 pesetas, al arzobispo Juan Soldevila, que allâ”œÂ¡ fundâ”œâ”‚ poco despuâ”œÂ®s la Escuela-Asilo de las Hijas de la Caridad de San Vicente de Paâ”œâ•‘l, o "monjas del cardenal". Allâ”œÂ¡ encontrarâ”œÂ¡a la muerte en 1923. En la imagen, plano parcelario del Instituto Geogrâ”œÃ­fico y Catastral de 1935 en el que hemos coloreado la rectangular â”œÃ­rea donde se ubicâ”œâ”‚ este cementerio. A su izquierda, la lâ”œÂ¡nea del ferrocarril de Caminreal. Al sur, el camino a los nuevos depâ”œâ”‚sitos de agua. Al norte, fuera de plano, el riego y camino de la Mosquetera. En la actualidad, este lugar se ubica al nordeste del cruce de la avenida de San Juan Bosco, y la Vâ”œÂ¡a Universitas. Fuente: Ramâ”œâ”‚n Betrâ”œÃ­n Abadâ”œÂ¡a, "La Ciudad y los muertos. La formaciâ”œâ”‚n del Cementerio de Torrero" (2015)', 1935, 1935, 1935, 'Anos 30', 'UNIVERSIDAD', 41.64418300, -0.90571700, '0101000020E6100000A7CCCD37A2FBECBFD0D1AA9674D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28213420285.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28213420285.webp', 'https://www.flickr.com/photos/zaragozaantigua/28213420285/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21880, 'Monumento escolares caâ”œÂ¡dos 1936', 'Imagen de la maqueta proyectada por Regino Borobio y Fâ”œÂ®lix Burriel para el "Monumento a los Escolares muertos por la Patria 1936", que en su versiâ”œâ”‚n definitiva serâ”œÂ¡a denominado "Monumento a los Escolares muertos por Dios y por Espaâ”œâ–’a 1936-39". Se construyâ”œâ”‚ en 1941 en "La gran plaza de las Facultades" del Campos de la nueva plaza de San Francisco, proyectada como de Espaâ”œâ–’a, y asâ”œÂ¡ redenominada tras 1936, frente a la Facultad de Derecho, quedando la de Filosofâ”œÂ¡a y Letras a la izquierda, y la de Ciencias, a la derecha. Sobre un soporte hormigonado y revestido con piedra blanca de las canteras de La Puebla de Albortâ”œâ”‚n, se levantâ”œâ”‚ una horizontal pantalla de sillares con el escudo de la Universidad en el centro, sobre el que se imprimiâ”œâ”‚ la leyenda que da nombre al monumento, y que aparece flanqueado ademâ”œÃ­s por dos parejas de escolares militarizados y tres guirnaldas en piedra a cada lado, como perenne muestra de homenaje. Cada 9 de febrero en este monumento se celebraba el Dâ”œÂ¡a del Estudiante Caâ”œÂ¡do, ceremonia establecida en 1938 por el gobierno faccioso para conmemorar la muerte violenta de un estudiante falangista inmediatamente convertido en protomâ”œÃ­rtir, que el franquismo institucionalizâ”œâ”‚. En 1981, tras unos aâ”œâ–’os en el limbo, fue finalmente desmontado y recompuesto en el patio principal del acuartelamiento de San Fernando en una versiâ”œâ”‚n reducida que sâ”œâ”‚lo incluâ”œÂ¡a a las figuras de los escolares-soldados. Los sillares sobrantes fueron trasladados a la Comandancia de obras del Cuartel de Valdespartera. En la actualidad no es fâ”œÃ­cil saber dâ”œâ”‚nde, ni en quâ”œÂ® estado, se encuentran los restos de este monumento, ni quiâ”œÂ®n vela por ellos. Fuente visual: Mâ”œâ”‚nica Vâ”œÃ­zquez Astorga, Anales de Historia del Arte, 2006.', 1936, 1936, 1936, 'Anos 30', 'UNIVERSIDAD', 41.64262800, -0.89672600, '0101000020E6100000F7216FB9FAB1ECBF38BF61A241D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46525098992.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46525098992.webp', 'https://www.flickr.com/photos/zaragozaantigua/46525098992/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21969, 'Feria de Muestras 1944', 'Una imagen promocional de la Feria de Muestras al atardecer, ya inaugurada la torre, con su iluminaria, terminada para el certamen de ese aâ”œâ–’o. Este punto de vista escogido por el fotâ”œâ”‚grafo, hacia el suroeste, contrasta sobremanera en un entorno sin mâ”œÃ­s edificaciones, y despoblado, en el lâ”œÂ¡mite de la Zaragoza del momento. A la izquierda, el paseo de Isabel la Catâ”œâ”‚lica Fuente: www.todocoleccion.net/', 1944, 1944, 1944, 'Anos 40', 'UNIVERSIDAD', 41.63732000, -0.89852900, '0101000020E6100000213EB0E3BFC0ECBF1A8BA6B393D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22809690438.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22809690438.webp', 'https://www.flickr.com/photos/zaragozaantigua/22809690438/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21984, 'Feria de Muestras 1944', 'Inâ”œÂ®dita imagen centrada en la torre en obras de la Feria de Muestras construida en terrenos propiedad de la Câ”œÃ­mara Oficial del Comercio y de la Industria de Zaragoza ubicados frente al puente del 13 de Septiembre y el parque de Primo de Rivera, en el arranque de la prolongaciâ”œâ”‚n del paseo de Fernando el Catâ”œâ”‚lico (luego paseo de Isabel la Catâ”œâ”‚lica). Fue diseâ”œâ–’ada en 1940 por los arquitectos Regino y Josâ”œÂ® Borobio Ojeda y Josâ”œÂ® Beltrâ”œÃ­n Navarro al hilo de las celebraciones oficiales asociadas al XIX Centenario de la Virgen del Pilar, en formas eclâ”œÂ®cticas entre las locales evocaciones neomudâ”œÂ®jares y la arquitectura fascista italiana referente del Râ”œÂ®gimen franquista. En la IIIâ”¬Â¬ ediciâ”œâ”‚n de 1943 la torre estaba todavâ”œÂ¡a a un tercio de su altura, y serâ”œÂ¡a inaugurada durante la IVâ”¬Â¬ ediciâ”œâ”‚n de la Feria, en 1944. En primer tâ”œÂ®rmino, tendido aâ”œÂ®reo y postes de la reciente y tranviaria lâ”œÂ¡nea 11 "Parque", cuya terminal estaba ubicada justo al lado. Fuente visual: aportaciâ”œâ”‚n personal y exclusiva de la familia De Sola al Gran Archivo Zaragoza Antigua (GAZA).', 1944, 1944, 1944, 'Anos 40', 'UNIVERSIDAD', 41.63732400, -0.89877800, '0101000020E61000003FA88B14CAC2ECBF5B7A34D593D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29044624127.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29044624127.webp', 'https://www.flickr.com/photos/zaragozaantigua/29044624127/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21986, 'Gran Vâ”œÂ¡a 1949', 'Vista de la prolongaciâ”œâ”‚n de la Gran Vâ”œÂ¡a capturada desde la torre de la Feria Nacional de Muestras. A la izquierda, construcciâ”œâ”‚n de la Residencia Sanitaria Josâ”œÂ® Antonio, comenzada en 1948 y terminada en 1955. A la derecha, acequia de la Romareda. Sobre el firme de la calle, obras para la lâ”œÂ¡nea 15 "Casablanca" del tranvâ”œÂ¡a, que unirâ”œÃ­ ese barrio con la plaza de Espaâ”œâ–’a en 1950. Fuente: www.facebook.com/photo.php?fbid=10209509669832229&set...', 1949, 1949, 1949, 'Anos 40', 'UNIVERSIDAD', 41.63631300, -0.90024300, '0101000020E6100000637E6E68CACEECBF848252B472D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30082891026.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30082891026.webp', 'https://www.flickr.com/photos/zaragozaantigua/30082891026/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21993, 'Pedro Cerbuna 1949', 'Imagen capturada por F. Mesas (Bilbao) y convertida en postal, de las instalaciones ocupadas en el Cuartel de Palafox por el Regimiento de Montaâ”œâ–’a nâ”¬â•‘ 20, correspondientes a las residencias de oficiales y suboficiales. Varias dâ”œÂ®cadas despuâ”œÂ®s, y tras la "Operaciâ”œâ”‚n Cuarteles", el edificio de primer plano, angular entre las calle de Domingo Miral (izquierda) y Pedro Cerbuna (al fondo), serâ”œÂ¡a reconvertido en cuartel de la policâ”œÂ¡a local. El edificio del fondo, esquinero con la calle de Manuel Serrano Sanz, serâ”œÃ­ remodelado y elevado una planta, para convertirlo en la Residencia Logâ”œÂ¡stica Militar "Palafox". Fuente visual: www.todocoleccion.net/', 1949, 1949, 1949, 'Anos 40', 'UNIVERSIDAD', 41.63961500, -0.89882800, '0101000020E6100000B05417F032C3ECBFF98381E7DED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31196548754.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31196548754.webp', 'https://www.flickr.com/photos/zaragozaantigua/31196548754/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22028, 'P.â”¬â•‘ de Isabel la Catâ”œâ”‚lica c.1946', 'Imagen capturada en el adoquinado paseo reciâ”œÂ®n denominado de Isabel la Catâ”œâ”‚lica, con el aspecto de esta perifâ”œÂ®rica zona flanqueada a la izquierda por el moderno convento de Jerusalâ”œÂ®n (desde 1943), y a la derecha por el Colegio-Residencia de Nuestra Seâ”œâ–’ora del Pilar para Huâ”œÂ®rfanos e Hijos del Magisterio que, proyectado en 1943 por Rafael F. Huidobro, Josâ”œÂ® Beltrâ”œÃ­n, Regino Borobio y Josâ”œÂ® Borobio, tuvo un dilatado proceso constructivo, para ser finalmente inaugurado en 1957. Al fondo, la rutilante atalaya de la Feria de Muestras, los nuevos bloques de viviendas del paseo de Fernando el Catâ”œâ”‚lico, e incluso la torre del colegio La Salle Gran Vâ”œÂ¡a, heredada del original y fallido convento e Iglesia de los Carmelitas Descalzos.', 1946, 1946, 1946, 'Anos 40', 'UNIVERSIDAD', 41.63400000, -0.90303500, '0101000020E6100000689604A8A9E5ECBFFED478E926D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50642257527.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50642257527.webp', 'https://www.flickr.com/photos/zaragozaantigua/50642257527/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22410, 'Monumento a la Madre 1967', 'En 1965, la emisora "Radio Popular", reciente invento propagandâ”œÂ¡stico de la Conferencia Episcopal Espaâ”œâ–’ola, propuso erigir un monumento que homenajease a "la Madre". Se realizâ”œâ”‚ una recogida de donativos, y con la colaboraciâ”œâ”‚n municipal se localizâ”œâ”‚ su emplazamiento en el parque Primo de Rivera, junto a una zona de juegos infantiles. Los promotores de la idea pretendâ”œÂ¡an que el homenaje fuera tanto a la "madre terrena", como "a la del cielo", y casi se meten en un lâ”œÂ¡o, pues eso hubiera supuesto erigir un nuevo santuario de la singular "Madre del Cielo", o "Virgen del Pilar", fuera del espacio de su habitual columna. La cosa se reencauzâ”œâ”‚, dejando que este monumento fuera "sâ”œâ”‚lo" a la terrenal madre. Un joven â”œÃ¼ngel Orensanz fue seâ”œâ–’alado para realizar los bultos redondos del grupo escultâ”œâ”‚rico, tallado en piedra de Ulldecona (Tarragona), que representa a una joven figura maternal en actitud protectora de un niâ”œâ–’o. Junto a ellos, un bloque de piedra reza "A la Madre. Levantâ”œâ”‚ el pueblo de Aragâ”œâ”‚n este monumento por iniciativa de Radio Popular". En la imagen, inauguraciâ”œâ”‚n del monumento, con presencia de numerosas autoridades religiosas, militares e institucionales, amâ”œÂ®n de bastante gente de a pie. Fuente visual: Gerardo Sancho Ramo, Archivo Pâ”œâ•‘blico Municipal.', 1967, 1967, 1967, 'Anos 60', 'UNIVERSIDAD', 41.63202700, -0.89784200, '0101000020E61000001A355F251FBBECBF3198BF42E6D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24706498900.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24706498900.webp', 'https://www.flickr.com/photos/zaragozaantigua/24706498900/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22413, 'Cuartel Palafox 1965', 'El franquismo resultâ”œâ”‚ ser una continuidad de la guerra civil por otras vâ”œÂ¡as. Su perenne vinculaciâ”œâ”‚n con la guerra, que fue su epifanâ”œÂ¡a, se reforzaba con la exaltaciâ”œâ”‚n de los sâ”œÂ¡mbolos que recordaban esa â”œÂ¡ntima uniâ”œâ”‚n. La memoria de los caâ”œÂ¡dos (propios) en combate, y el homenaje a las organizaciones de excombatientes franquistas, formaban parte de esa cultura de guerra, aunque aparentemente se conmemorara la "paz". Lejos de "olvidar" el pasado, de "pasar pâ”œÃ­gina", se trataba de recordar, actualizar y mantener viva la memoria de la guerra en forma de ceremonias, actos pâ”œâ•‘blicos, homenajes, desfiles, participaciâ”œâ”‚n en organizaciones y hermandades de excombatientes, mutilados o no... La imagen ha sido capturada durante la VIII Asamblea de la Hermandad Provincial de Alfâ”œÂ®reces Provisionales, en uno de los patios internos del cuartel de Palafox, de artillerâ”œÂ¡a de montaâ”œâ–’a. Una misa al aire libre como parte del programa de actos, con una cobertera para proteger del canicular sol zaragozano, fuera de temporada. Al fondo, edificios del paseo de Fernando el Catâ”œâ”‚lico, y de la calle de Luis Vives. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1965, 1965, 1965, 'Anos 60', 'UNIVERSIDAD', 41.63974300, -0.90029700, '0101000020E61000002FFB75A73BCFECBF276C3F19E3D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25071591582.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25071591582.webp', 'https://www.flickr.com/photos/zaragozaantigua/25071591582/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22418, 'Feria de Muestras 1964', 'Imagen en altura, desde la torre de la Feria de Muestras, del interior del recinto ferial, posiblemente durante el primero de los certâ”œÃ­menes dedicado monogrâ”œÃ­ficamente a la maquinaria agrâ”œÂ¡cola. A la izquierda, el cubierto y referencial "Pabellâ”œâ”‚n Francâ”œÂ®s", inaugurado en 1958, como doble homenaje al asedio francâ”œÂ®s de 1808, y a la exposiciâ”œâ”‚n hispano-francesa de 1908. A la derecha, vista parcial del Cuartel de Palafox. El acople de otra fotografâ”œÂ¡a, en la parte superior, origina una extraâ”œâ–’a sensaciâ”œâ”‚n en una zona que, por esos aâ”œâ–’os, asomaba a campos de cultivo, aâ”œâ•‘n sin edificar. Fuente visual: Estudio Coyne (DARA-AHPZ).', 1964, 1964, 1964, 'Anos 60', 'UNIVERSIDAD', 41.63751500, -0.89931400, '0101000020E6100000DCB75A272EC7ECBFCFDA6D179AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26248236173.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26248236173.webp', 'https://www.flickr.com/photos/zaragozaantigua/26248236173/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22547, 'Campus Universidad 1975', 'Archivo Histâ”œâ”‚rico Municipal. Gerardo Sancho Ramo. 21/09/1975. Campus Universidad Plaza San Francisco. Edificio Interfacultades. Expresivo grafitti (aerosol sobre plantilla) que representa câ”œâ”‚mo sobre un cerdo comunista estâ”œÃ­ a punto de abatirse, sin que San Antâ”œâ”‚n intervenga, la soluciâ”œâ”‚n final en forma de tremendo cuchillo nazi. Se nota que quien ha dibujado el cuchillo ha participado en pocas matacâ”œÂ¡as de verdad.', 1975, 1975, 1975, 'Anos 70', 'UNIVERSIDAD', 41.64233100, -0.89799200, '0101000020E61000006D3A02B859BCECBF7E1AF7E637D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15016515750.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15016515750.webp', 'https://www.flickr.com/photos/zaragozaantigua/15016515750/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22605, 'Palacio Municipal de los Deportes 1976', 'Imagen de la construcciâ”œâ”‚n del Palacio de los Deportes de Zaragoza, capturada en altura desde la confluencia de las calles Asâ”œÂ¡n y Palacios, y Luis Bermejo. Al fondo, los grandes megabloques habitacionales que estaban surgiendo en la confluencia de San Juan Bosco y lo que luego serâ”œÂ¡a denominado "Vâ”œÂ¡a Universitas". La local costumbre de ponerle varios nombres a los sitios bautizâ”œâ”‚ pronto a esta pâ”œâ•‘blica instalaciâ”œâ”‚n como "El Huevo", por la ovalada culminaciâ”œâ”‚n de su cubierta. Esta es una de las razones por las que los foranos y turistas se lo pasan pipa cuando intentan localizar esta, u otra instalaciâ”œâ”‚n. Este Palacio de los Deportes de Zaragoza fue inaugurado en setiembre de 1977, con el I Trofeo de Baloncesto "Ciudad de Zaragoza" entre las selecciones absolutas de Espaâ”œâ–’a, Francia, Uniâ”œâ”‚n Soviâ”œÂ®tica, y la universitaria de Cuba. Antonio Dâ”œÂ¡az-Miguel seleccionâ”œâ”‚ por Espaâ”œâ–’a a Brabender, Cabrera, Prada, Corbalâ”œÃ­n, Rullâ”œÃ­n, Josâ”œÂ® Marâ”œÂ¡a Margall, Santillana, Filbâ”œÃ­, Fernâ”œÃ­ndez, Flores, De la Cruz, Gonzalo Sagi-Vela y Vicente Gil. La Uniâ”œâ”‚n Soviâ”œÂ®tica de Aleksandr Gomelsky fue la vencedora del torneo, con Serguâ”œÂ®i Belov, Ivâ”œÃ­n Edeshko, Jurij Pavlov, Valeri Miloserdov, Aleksandr Boloshev, Alzhan Zharmujamedov, Aleksandr Belov, Aleksandr Salnikov, Mijaâ”œÂ¡l Korkia, Vladâ”œÂ¡mir Zhigili. Fuente visual: Archivo Pâ”œâ•‘blico Municipal. Gerardo Sancho Ramo.', 1976, 1976, 1976, 'Anos 70', 'UNIVERSIDAD', 41.63975400, -0.90414900, '0101000020E61000005DC136E2C9EEECBF1BBE8575E3D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18795439299.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18795439299.webp', 'https://www.flickr.com/photos/zaragozaantigua/18795439299/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22606, 'Fernando el Catâ”œâ”‚lico 1976', 'Torre de la Editorial Luis Vives, ubicada entre 1941 y 1975 en el paseo de Fernando el Catâ”œâ”‚lico nâ”¬â•‘ 63, en una imagen cuando las instalaciones y talleres ya se habâ”œÂ¡an trasladado al extrarradio urbano, y apenas quedaban los muros perimetrales y sus jardines y zonas verdes. La torre, demediada de su cuerpo superior, serâ”œÂ¡a poco despuâ”œÂ®s derribada, y sobre este cotizado espacio se construirâ”œÂ¡a despuâ”œÂ®s una compacta manzana de bloques de viviendas.', 1976, 1976, 1976, 'Anos 70', 'UNIVERSIDAD', 41.63825300, -0.89686100, '0101000020E6100000F5D901D715B3ECBF75C93846B2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18881848032.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18881848032.webp', 'https://www.flickr.com/photos/zaragozaantigua/18881848032/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22616, 'Pabellâ”œâ”‚n de Deportes 1973', 'Con este dibujo se anunciaba a comienzos de 1973 la futura construcciâ”œâ”‚n del Pabellâ”œâ”‚n Municipal de Deportes de Zaragoza, en el barrio de la Romareda. Su aspecto definitivo distâ”œâ”‚ mucho del mostrado, siendo bautizado por la ciudadanâ”œÂ¡a como "el huevo", tras su inauguraciâ”œâ”‚n en 1977. En primer plano, la entrada principal, en la calle de los Condes de Aragâ”œâ”‚n. Fuente: Diario Amanecer, 13 de enero de 1973.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.63975400, -0.90414900, '0101000020E61000005DC136E2C9EEECBF1BBE8575E3D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19218313098.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19218313098.webp', 'https://www.flickr.com/photos/zaragozaantigua/19218313098/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22770, 'Hugh Thomas 1976', 'Imagen del historiador e hispanista britâ”œÃ­nico Hugh Thomas, capturada durante su conferencia organizada en el mes de febrero por una poderosa e influyente entidad de ahorro local en el polideportivo de su propiedad en el polâ”œÂ¡gono Romareda. Reciâ”œÂ®n pasado del Partido Laborista al Partido Conservador, su presencia en la Espaâ”œâ–’a en esa â”œÂ®poca fue considerada una muestra mâ”œÃ­s de la apertura del Râ”œÂ®gimen Franquista que, en este caso, sirviâ”œâ”‚ para dar a conocer al gran pâ”œâ•‘blico la obra de Thomas del aâ”œâ–’o 1961 titulada "La guerra civil espaâ”œâ–’ola", publicada en la editorial Ruedo Ibâ”œÂ®rico. Como los tiempos eran los que eran, en la rueda de prensa previa al acto, realizada en la Casa del Deâ”œÃ­n, a Thomas le preguntaron por el "Generalâ”œÂ¡simo" Franco, fallecido no hacâ”œÂ¡a mucho, a lo que el britâ”œÃ­nico respondiâ”œâ”‚ que fue un "hombre bueno", un "militar arriesgado en su juventud", un "generalâ”œÂ¡simo muy cauteloso", y un "estadista prudente". Preguntado por Fraga Iribarne, respondiâ”œâ”‚ que era "un hombre culto que podrâ”œÂ¡a ser primer ministro (presidente del Gobierno) de una Espaâ”œâ–’a democrâ”œÃ­tica". Con estos antecedentes, el â”œÂ®xito de crâ”œÂ¡tica y pâ”œâ•‘blico mayoritario estaba mâ”œÃ­s que garantizado. Desde 1981, Thomas fue asesor para asuntos hispâ”œÃ­nicos de la primera ministra Margaret Thatcher. Fue nombrado lord de Inglaterra, y Espaâ”œâ–’a le concediâ”œâ”‚ en 1986 la orden de Isabel la Catâ”œâ”‚lica. Tiene, ademâ”œÃ­s, el tâ”œÂ¡tulo de barâ”œâ”‚n de Swynnerton y se sienta en la Câ”œÃ­mara de los Lores. Tras dejar a los Conservadores, estuvo con los Demâ”œâ”‚cratas, y hoy es Independiente, cualidad caracterâ”œÂ¡stica de todos los historiadores, por supuesto. Fuente visual: foto Gerardo Sancho Ramo, en AMZ.', 1976, 1976, 1976, 'Anos 70', 'UNIVERSIDAD', 41.63825200, -0.90310900, '0101000020E6100000FB2477D844E6ECBFA54DD53DB2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33513889902.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33513889902.webp', 'https://www.flickr.com/photos/zaragozaantigua/33513889902/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22797, 'La Romareda 1976', 'Imagen capturada durante la ampliaciâ”œâ”‚n del estadio municipal de La Romareda acometida durante el verano de 1976, cuando el campo del entonces exitoso club de fâ”œâ•‘tbol de la ciudad ampliâ”œâ”‚ su aforo hasta las 43.524 localidades. La vista parcial se centra en el fondo de gol sur, recayente a la calle de Jerusalâ”œÂ®n, asâ”œÂ¡ denominada en homenaje al inmediato convento de Santa Marâ”œÂ¡a de Jerusalâ”œÂ®n, aquâ”œÂ¡ ubicado desde 1943. De fondo, algunas de las torres de viviendas del Polâ”œÂ¡gono Romareda, entre las calles de Jerusalâ”œÂ®n, y de Asâ”œÂ¡n y Palacios, con una vista parcial de la moderna parroquia de Santa Mâ”œâ”‚nica. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1976, 1976, 1976, 'Anos 70', 'UNIVERSIDAD', 41.63599900, -0.90249700, '0101000020E61000009D9E776341E1ECBFF4A44C6A68D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45777800125.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45777800125.webp', 'https://www.flickr.com/photos/zaragozaantigua/45777800125/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22807, 'Universidad 1976', 'Imagen capturada en el campus universitario de San Francisco el 21 de octubre de 1976 con motivo de la primera "Apertura Paralela", asâ”œÂ¡ denominada por los convocantes de las organizaciones polâ”œÂ¡ticas de la plural izquierda local, como râ”œÂ®plica alternativa a la oficial y protocolaria que se realizaba con el tradicional boato y parafernalia en el edificio de la plaza de Basilio Paraâ”œÂ¡so. Las reivindicaciones de esta jornada, muy polâ”œÂ¡ticas menos de un aâ”œâ–’o despuâ”œÂ®s de la muerte del Jefe del Estado que personificâ”œâ”‚ los â”œâ•‘ltimos cuarenta aâ”œâ–’os de la historia de Espaâ”œâ–’a, se centraron en tâ”œÂ®rminos generales en la recuperaciâ”œâ”‚n de las libertades y la democracias arrebata en 1936, la amnistâ”œÂ¡a, y la escenificaciâ”œâ”‚n de los primeros sâ”œÂ¡mbolos autonomistas desde un punto de vista no tradicionalista. Las actividades previstas, polâ”œÂ¡tico-reivindicativas y festivas, se desarrollaron en el Aula Magna de la Facultad de Ciencias y en el inmediato campus, e incluyeron las actuaciones de Joaquâ”œÂ¡n Carbonell, Eduardo Paz de La Bullonera, y el grupo de teatro El Silbo Vulnerado. La jornada festiva (no oficial, de forma que las clases continuaron, al menos en teorâ”œÂ¡a) y reivindicativa terminâ”œâ”‚ entre cargas de la Policâ”œÂ¡a Armada llamada por la Autoridad para disolverlos. En la imagen, acceso principal a la Facultad de Ciencias engalanado con carteles informativos y reivindicativos, entre los que destaca por su tamaâ”œâ–’o el de "Universidad para Aragâ”œâ”‚n" firmado por el CERZ (Comitâ”œÂ® de Estudiantes Revolucionarios de Zaragoza), ademâ”œÃ­s de ventanas de las que penden banderas varias y pancartas.', 1976, 1976, 1976, 'Anos 70', 'UNIVERSIDAD', 41.64186600, -0.89943000, '0101000020E61000002A52616C21C8ECBF093543AA28D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50241298023.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50241298023.webp', 'https://www.flickr.com/photos/zaragozaantigua/50241298023/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22921, 'Maradona 1983', 'Diego Armando Maradona (1960-2020) fue un estelar delantero de fâ”œâ•‘tbol argentino que el F.C. Barcelona fichâ”œâ”‚ en 1982 tras pagar unos inconcebibles 1.000 millones de pesetas. La imagen fue capturada en la final de la Copa del Rey (asâ”œÂ¡ denominada desde 1976 a la que desde 1939 fuera del Generalâ”œÂ¡simo) disputada en el estadio municipal de La Romareda el dâ”œÂ¡a 4 de junio de 1983, y con resultado final de F.C. Barcelona 2, Real Madrid C.F. 1. A la derecha, el Lobo Carrasco. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1983, 1983, 1983, 'Anos 80', 'UNIVERSIDAD', 41.63653100, -0.90184600, '0101000020E6100000C9E88024ECDBECBFF1F109D979D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29637855374.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29637855374.webp', 'https://www.flickr.com/photos/zaragozaantigua/29637855374/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22958, 'Salesianos 1980', 'Imagen del colegio de los Salesianos centrada en la esquina de la avenida de San Juan Bosco y la calle de Pedro Lâ”œâ”‚pez de Luna, donde destaca la piscina abierta en el gran patio. En este espacio aâ”œâ–’os despuâ”œÂ®s se construirâ”œÂ¡a el actual pabellâ”œâ”‚n polideportivo del colegio.', 1980, 1980, 1980, 'Anos 80', 'UNIVERSIDAD', 41.64452000, -0.90235900, '0101000020E61000005B0A48FB1FE0ECBF18CFA0A17FD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49915490646.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49915490646.webp', 'https://www.flickr.com/photos/zaragozaantigua/49915490646/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22987, 'Auditorio Palacio de Congresos 1994', 'Obra de Josâ”œÂ® Manuel Pâ”œÂ®rez Latorre, fue inaugurado en octubre de 1994 en la calle Eduardo Ibarra 3, hoy plaza (izquierda). En la foto, edificio en construcciâ”œâ”‚n. Fuente: www.elperiodicodearagon.com/', 1994, 1994, 1994, 'Anos 90', 'UNIVERSIDAD', 41.63826300, -0.90138400, '0101000020E6100000BE67244223D8ECBF999F1B9AB2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19858861911.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19858861911.webp', 'https://www.flickr.com/photos/zaragozaantigua/19858861911/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23099, 'Lou Reed 2000', 'El cantante estadounidense Lou Reed (1942-2013), durante su actuaciâ”œâ”‚n en el Pabellâ”œâ”‚n Municipal de Deportes, el 14 de abril de 2000. Fuente: Agencia EFE.', 2000, 2000, 2000, 'Siglo XXI', 'UNIVERSIDAD', 41.63975400, -0.90414900, '0101000020E61000005DC136E2C9EEECBF1BBE8575E3D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24016430694.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24016430694.webp', 'https://www.flickr.com/photos/zaragozaantigua/24016430694/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26021, 'Feria de Muestras 1983', 'â”œÃœltimos tiempos de la Feria de Muestras ubicada desde 1941 en el entonces lejano final del paseo de Fernando el Catâ”œâ”‚lico. En la imagen aâ”œÂ®rea conforma una gran manzana flanqueada por la calle de Luis Bermejo, la plaza del Emperador Carlos y la calle de Violante de Hungrâ”œÂ¡a. Al fondo, la calle de Eduardo Ibarra, el Polâ”œÂ¡gono Romareda y el Pabellâ”œâ”‚n Municipal de Deportes. En primer tâ”œÂ®rmino, denso arbolado ribereâ”œâ–’o del râ”œÂ¡o Huerva en paralelo al paseo de Isabel la Catâ”œâ”‚lica. Fuente visual: AMZ.', 1983, 1983, 1983, 'Anos 80', 'UNIVERSIDAD', 41.63732400, -0.89877800, '0101000020E61000003FA88B14CAC2ECBF5B7A34D593D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27151823487.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27151823487.webp', 'https://www.flickr.com/photos/zaragozaantigua/27151823487/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24026, 'Pilar Lorengar 1967', 'Imagen de la institucional ceremonia de descubrimiento de lâ”œÃ­pida de la nueva calle denominada "de la cantante Pilar Lorengar". La protagâ”œâ”‚nica soprano de fama internacional (Lorenza Pilar Garcâ”œÂ¡a Seta, "Pilar Lorengar" de nombre artâ”œÂ¡stico, "Loren Garcy", en su etapa de local artista de variedades), de espaldas, junto al sonriente y nunca bien ponderado alcalde Cesâ”œÃ­reo Alierta, en la esquina del final de la calle, donde desemboca en la de Corona de Aragâ”œâ”‚n. A la derecha, solares y obras de nuevos bloques en la esquina de la calle San Antonio Marâ”œÂ¡a Claret. Una vecina del inmueble disfruta de una vista privilegiada, desde un palco no oficial, entre sorprendida e intimidada. Aplausos generalizados por el respetable asistente. Debajo de la lâ”œÃ­pida descubierta, huella de la anterior placa arrancada, que identificaba hasta ese momento este vial como "calle de la Virtud". Pocos aâ”œâ–’os mâ”œÃ­s tarde, el antiguo edificio que la soportaba, el de la imagen, reliquia de las construcciones de los aâ”œâ–’os 30 de esta perifâ”œÂ®rica barriada, serâ”œÃ­ derribado, y en su lugar se levantarâ”œÃ­ uno mâ”œÃ­s moderno, vertical, y en chaflâ”œÃ­n. El actual. La ceremonial placa, desaparecida. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1967, 1967, 1967, 'Anos 60', 'UNIVERSIDAD', 41.64347100, -0.89677900, '0101000020E6100000ACAA97DF69B2ECBF5376FA415DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24770295910.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24770295910.webp', 'https://www.flickr.com/photos/zaragozaantigua/24770295910/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24094, 'Campus universitario 1943', 'Imagen capturada durante la provechosa visita a la ciudad del ministro de Educaciâ”œâ”‚n Nacional, el turolense Josâ”œÂ® Ibâ”œÃ­â”œâ–’ez Martâ”œÂ¡n, a finales de junio de ese aâ”œâ–’o. En este caso se trata de la excursiâ”œâ”‚n realizada a los terrenos de la Ciudad Universitaria, donde tras el preceptivo homenaje religioso-castrense en la Cruz de los Estudiantes Caâ”œÂ¡dos, procediâ”œâ”‚ a participar en la colocaciâ”œâ”‚n de la primera piedra de la Casa de Gobierno de la Universidad, y asegurâ”œâ”‚ que "antes de dos aâ”œâ–’os" la Universidad de Zaragoza serâ”œÂ¡a una realidad tangible. Esta Casa de Gobierno luego no serâ”œÂ¡a realizada. Despuâ”œÂ®s visitâ”œâ”‚ las obras de la Facultad de Derecho, inaugurada en 1945, y recorriâ”œâ”‚ las instalaciones de la Facultad de Letras, donde se impartieron hasta entonces las enseâ”œâ–’anzas de ambas disciplinas.', 1943, 1943, 1943, 'Anos 40', 'UNIVERSIDAD', 41.64201800, -0.89654400, '0101000020E6100000CC99ED0A7DB0ECBFBFB854A52DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49367380911.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49367380911.webp', 'https://www.flickr.com/photos/zaragozaantigua/49367380911/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24241, 'Ferial de atracciones c.1959', 'Nocturna imagen capturada desde la altura de la torre de la Editorial Luis Vives y centrada en el luminoso recinto de la Feria de Muestras y el anexo ferial de atracciones instalado durante las fiestas del Pilar, del que destaca el tobogâ”œÃ­n y la noria. Detrâ”œÃ­s y en penumbra, el reciente estadio municipal de La Romareda. A la izquierda, la avenida de Isabel la Catâ”œâ”‚lica. En primer tâ”œÂ®rmino, la plaza del Emperador Carlos V.', 1959, 1959, 1959, 'Anos 50', 'UNIVERSIDAD', 41.63777700, -0.89901200, '0101000020E610000009C556D0B4C4ECBF0C923EADA2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51656772309.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51656772309.webp', 'https://www.flickr.com/photos/zaragozaantigua/51656772309/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24347, 'Santa Mâ”œâ”‚nica in the fields 1973', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. 16/06/1973. Al fondo, las torres de viviendas del novâ”œÂ¡simo Polâ”œÂ¡gono Romareda, con su no menos moderna versiâ”œâ”‚n de lugar de culto catâ”œâ”‚lico en forma de la Parroquia de Santa Mâ”œâ”‚nica. En primer plano, los campos que producâ”œÂ¡an cereales y herbâ”œÃ­ceas, delimitados por la calle Condes de Aragâ”œâ”‚n, el Seminario y la Vâ”œÂ¡a Hispanidad, y la prolongaciâ”œâ”‚n de Juan Pablo Bonet. Era otra modalidad de barbecho urbanâ”œÂ¡stico expectante: producir hasta el â”œâ•‘ltimo momento. En la actualidad, toda esta zona estâ”œÃ­ urbanizada, construida, ingerida por la ciudad.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.63812900, -0.90663400, '0101000020E61000001D226E4E2503EDBF89D00836AED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14720114960.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14720114960.webp', 'https://www.flickr.com/photos/zaragozaantigua/14720114960/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24423, 'Pedro III el Grande 1973', 'Imagen capturada en la novâ”œÂ¡sima calle de Pedro III el Grande del polâ”œÂ¡gono Romareda y centrada en el cruce con la calle de Asâ”œÂ¡n y Palacios, donde destaca la postconcilar iglesia parroquial de Santa Mâ”œâ”‚nica de la Orden de Agustinos Recoletos de San Nicolâ”œÃ­s de Tolentino, bendecida a mediados de ese aâ”œâ–’o. Confrontando con ella, algunos de los cooperativos bloques poligoneros: el nâ”œâ•‘mero 15, 17 y 21 de Asâ”œÂ¡n y Palacios, traseras del nâ”œâ•‘mero 8 de la calle de Don â”œÃ¼lvaro de Bazâ”œÃ­n y los nâ”œâ•‘meros 3 y 6 de la calle de Juan II de Aragâ”œâ”‚n. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.63687300, -0.90544800, '0101000020E6100000C25087156EF9ECBF4B5AF10D85D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38072978844.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38072978844.webp', 'https://www.flickr.com/photos/zaragozaantigua/38072978844/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
